var surah003 = {
  number: 3,
  nameArabic: "Ali Imran",
  nameEnglish: "Aal-e-Imran",
  meaning: "Family of Imran",
  totalAyahs: 200,
  ayahs: [
    { number: 1, arabic: "الٓمٓ", transliteration: "Aliflammeem", transliterationB: "Alif-Laam-Meeem", english: "L. M", romanUrdu: "Alif laam meem" },
    { number: 2, arabic: "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْحَىُّ ٱلْقَيُّومُ", transliteration: "Allahu la ilaha illa huwa alhayyu alqayyoomu", transliterationB: "Allaahu laaa ilaaha illaa Huwal Haiyul Qaiyoom", english: "Allah! There is no god but He,-the Living, the Self-Subsisting, Eternal", romanUrdu: "Allah , woh zinda e javed hasti (Self-Subsisting), jo nizam e qayinaat ko sambhale huey hai, haqeeqat mein uske siwa koi khuda nahin hai" },
    { number: 3, arabic: "نَزَّلَ عَلَيْكَ ٱلْكِتَٰبَ بِٱلْحَقِّ مُصَدِّقًۭا لِّمَا بَيْنَ يَدَيْهِ وَأَنزَلَ ٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ", transliteration: "Nazzala AAalayka alkitaba bialhaqqi musaddiqan lima bayna yadayhi waanzala alttawrata waalinjeela", transliterationB: "Nazzala 'alaikal Kitaaba bilhaqqi musaddiqal limaa baina yadaihi wa anzalat Tawraata wal Injeel", english: "It is He Who sent down to thee (step by step), in truth, the Book, confirming what went before it; and He sent down the Law (of Moses) and the Gospel (of Jesus) before this, as a guide to mankind, and He sent down the criterion (of judgment between right and wrong)", romanUrdu: "Usne tumpar yeh kitab nazil ki hai, jo haqq lekar aayi hai aur un kitabon ki tasdeeq kar rahi hai jo pehle se aayi hui thi, issey pehle woh insaano ki hidayat ke liye taurat aur injil nazil kar chukka hai" },
    { number: 4, arabic: "مِن قَبْلُ هُدًۭى لِّلنَّاسِ وَأَنزَلَ ٱلْفُرْقَانَ ۗ إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ ٱللَّهِ لَهُمْ عَذَابٌۭ شَدِيدٌۭ ۗ وَٱللَّهُ عَزِيزٌۭ ذُو ٱنتِقَامٍ", transliteration: "Min qablu hudan lilnnasi waanzala alfurqana inna allatheena kafaroo biayati Allahi lahum AAathabun shadeedun waAllahu AAazeezun thoo intiqamin", transliterationB: "Min qablu hudal linnaasi wa anzalal Furqaan; innallazeena kafaroo bi Aayaatil laahi lahum 'azaabun shadeed; wallaahu 'azeezun zun tiqaam", english: "Then those who reject Faith in the Signs of Allah will suffer the severest penalty, and Allah is Exalted in Might, Lord of Retribution", romanUrdu: "Aur usne woh kasauti (criteria) utari hai (jo haqq aur baatil ka farq dikhane wali hai). Ab jo log Allah ke farameen ko qabool karne se inkar karein, unko yaqeenan sakht saza milegi. Allah be-panaah taaqat ka maalik hai aur burayi ka badla dene wala hai" },
    { number: 5, arabic: "إِنَّ ٱللَّهَ لَا يَخْفَىٰ عَلَيْهِ شَىْءٌۭ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ", transliteration: "Inna Allaha la yakhfa AAalayhi shayon fee alardi wala fee alssamai", transliterationB: "Innal laaha laa yakhfaa 'alaihi shai'un fil ardi wa laa fis samaaa", english: "From Allah, verily nothing is hidden on earth or in the heavens", romanUrdu: "Zameen aur asmaan ki koi cheez Allah se posheeda nahin" },
    { number: 6, arabic: "هُوَ ٱلَّذِى يُصَوِّرُكُمْ فِى ٱلْأَرْحَامِ كَيْفَ يَشَآءُ ۚ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Huwa allathee yusawwirukum fee alarhami kayfa yashao la ilaha illa huwa alAAazeezu alhakeemu", transliterationB: "Huwal lazee yusawwirukum fil arhaami kaifa yashaaa'; laa ilaaha illaa Huwal 'Azeezul Hakeem", english: "He it is Who shapes you in the wombs as He pleases. There is no god but He, the Exalted in Might, the Wise", romanUrdu: "Wahi to hai jo tumhari Maaon (mothers) ke pait mein tumhari suratein , jaisi chahta hai, banata hai. Us zabardast hikmat waley ke siwa koi aur khuda nahin hai" },
    { number: 7, arabic: "هُوَ ٱلَّذِىٓ أَنزَلَ عَلَيْكَ ٱلْكِتَٰبَ مِنْهُ ءَايَٰتٌۭ مُّحْكَمَٰتٌ هُنَّ أُمُّ ٱلْكِتَٰبِ وَأُخَرُ مُتَشَٰبِهَٰتٌۭ ۖ فَأَمَّا ٱلَّذِينَ فِى قُلُوبِهِمْ زَيْغٌۭ فَيَتَّبِعُونَ مَا تَشَٰبَهَ مِنْهُ ٱبْتِغَآءَ ٱلْفِتْنَةِ وَٱبْتِغَآءَ تَأْوِيلِهِۦ ۗ وَمَا يَعْلَمُ تَأْوِيلَهُۥٓ إِلَّا ٱللَّهُ ۗ وَٱلرَّٰسِخُونَ فِى ٱلْعِلْمِ يَقُولُونَ ءَامَنَّا بِهِۦ كُلٌّۭ مِّنْ عِندِ رَبِّنَا ۗ وَمَا يَذَّكَّرُ إِلَّآ أُو۟لُوا۟ ٱلْأَلْبَٰبِ", transliteration: "Huwa allathee anzala AAalayka alkitaba minhu ayatun muhkamatun hunna ommu alkitabi waokharu mutashabihatun faamma allatheena fee quloobihim zayghun fayattabiAAoona ma tashabaha minhu ibtighaa alfitnati waibtighaa taweelihi wama yaAAlamu taweelahu illa Allahu waalrrasikhoona fee alAAilmi yaqooloona amanna bihi kullun min AAindi rabbina wama yaththakkaru illa oloo alalbabi", transliterationB: "Huwal lazeee anzala 'alaikal Kitaaba minhu Aayaatum Muh kamaatun hunna Ummul Kitaabi wa ukharu Mutashaabihaatun faammal lazeena fee quloobihim ziyghun fa yattabi'oona ma tashaabaha minhubtighaaa 'alfitnati wabtighaaa'a taaweelih; wa maa ya'lamu taaweelahooo illal laah; warraasikhoona fil 'ilmi yaqooloona aamannaa bihee kullum min 'indi Rabbinaa; wa maa yazzakkaru illaaa ulul albaab", english: "He it is Who has sent down to thee the Book: In it are verses basic or fundamental (of established meaning); they are the foundation of the Book: others are allegorical. But those in whose hearts is perversity follow the part thereof that is allegorical, seeking discord, and searching for its hidden meanings, but no one knows its hidden meanings except Allah. And those who are firmly grounded in knowledge say: \"We believe in the Book; the whole of it is from our Lord:\" and none will grasp the Message except men of understanding", romanUrdu: "Wahi khuda hai, jisne yeh kitab tumpar nazil ki hai. Is kitab mein do tarah ki ayaat hain : ek mohkamaat, jo kitab ki asal buniyaad hain aur dusri mutashaabihaat (ambiguous). Jin logon ke dilon mein tedh hai, woh fitne ki talash mein hamesha mutashabihaat hi ke pichey padey rehte hain aur unko maani pehnane ki koshish kiya karte hain, halaanke unka haqiqi mafhoom Allah ke siwa koi nahin jaanta. Bakhilaf iske jo log ilm mein pukhta-kaar hain, woh kehte hain ke “ hamara unpar iman hai, yeh sab hamare Rubb hi ki taraf se hain” aur sach yeh hai ke kisi cheez se saheeh sabaq sirf daanishmand log hi hasil karte hain" },
    { number: 8, arabic: "رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَّدُنكَ رَحْمَةً ۚ إِنَّكَ أَنتَ ٱلْوَهَّابُ", transliteration: "Rabbana la tuzigh quloobana baAAda ith hadaytana wahab lana min ladunka rahmatan innaka anta alwahhabu", transliterationB: "Rabbanaa laa tuzigh quloobanaa ba'da iz hadaitanaa wa hab lanaa mil ladunka rahmah; innaka antal Wahhaab", english: "Our Lord!\" (they say), \"Let not our hearts deviate now after Thou hast guided us, but grant us mercy from Thine own Presence; for Thou art the Grantor of bounties without measure", romanUrdu: "Woh Allah se dua karte rehte hain ke “ parwardigaar! Jab tu humein seedhe raste par laga chukka hai, to phir kahin hamare dilon ko kaji (crookedness) mein mubtila na kardijiyo. Humein apne khazane faiz se rehmat ata kar ke tu hi fayyaz e haqiqi (ata farmane wala) hai" },
    { number: 9, arabic: "رَبَّنَآ إِنَّكَ جَامِعُ ٱلنَّاسِ لِيَوْمٍۢ لَّا رَيْبَ فِيهِ ۚ إِنَّ ٱللَّهَ لَا يُخْلِفُ ٱلْمِيعَادَ", transliteration: "Rabbana innaka jamiAAu alnnasi liyawmin la rayba feehi inna Allaha la yukhlifu almeeAAada", transliterationB: "Rabbanaaa innaka jaami 'un-naasi li Yawmil laa raibafeeh; innal laaha laa yukhliful mee'aad", english: "Our Lord! Thou art He that will gather mankind Together against a day about which there is no doubt; for Allah never fails in His promise", romanUrdu: "Parwardigaar! Tu yaqeenan sab logon ko ek roz jamaa karne wala hai, jiske aane mein koi shubha (shakk) nahin, tu hargiz apne wadey se talne wala nahin hai”" },
    { number: 10, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَٰدُهُم مِّنَ ٱللَّهِ شَيْـًۭٔا ۖ وَأُو۟لَٰٓئِكَ هُمْ وَقُودُ ٱلنَّارِ", transliteration: "Inna allatheena kafaroo lan tughniya AAanhum amwaluhum wala awladuhum mina Allahi shayan waolaika hum waqoodu alnnari", transliterationB: "Innal lazeena kafaroo lan tughniya 'anhum amwaaluhum wa laaa awlaaduhum minal laahi shai'anw wa ulaaa'ika hum waqoodun Naar", english: "Those who reject Faith,- neither their possessions nor their (numerous) progeny will avail them aught against Allah: They are themselves but fuel for the Fire", romanUrdu: "Jin logon ne kufr ka rawayya ikhtiyar kiya hai, unhein Allah ke muqable mein na unka maal kuch kaam dega, na aulad , woh dozakh ka indhan (fuel) bankar rahenge" },
    { number: 11, arabic: "كَدَأْبِ ءَالِ فِرْعَوْنَ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَّبُوا۟ بِـَٔايَٰتِنَا فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ ۗ وَٱللَّهُ شَدِيدُ ٱلْعِقَابِ", transliteration: "Kadabi ali firAAawna waallatheena min qablihim kaththaboo biayatina faakhathahumu Allahu bithunoobihim waAllahu shadeedu alAAiqabi", transliterationB: "Kadaabi Aali Fir'awna wallazeena min qablihim; kazzaboo bi Aayaatinaa fa akhazahumul laahu bizunoo bihim; wallaahu shadeedul 'iqaab", english: "(Their plight will be) no better than that of the people of Pharaoh, and their predecessors: They denied our Signs, and Allah called them to account for their sins. For Allah is strict in punishment", romanUrdu: "Unka anjaam waisa hi hoga, jaisa Firoun ke saathiyon aur unse pehle ke nafarmaano ka ho chukka hai ke unhon ne ayaat e ilahi ko jhutlaya, nateeja yeh hua ke Allah ne unke gunaahon par unhein pakad liya aur haqq yeh hai ke Allah sakht saza dene wala hai" },
    { number: 12, arabic: "قُل لِّلَّذِينَ كَفَرُوا۟ سَتُغْلَبُونَ وَتُحْشَرُونَ إِلَىٰ جَهَنَّمَ ۚ وَبِئْسَ ٱلْمِهَادُ", transliteration: "Qul lillatheena kafaroo satughlaboona watuhsharoona ila jahannama wabisa almihadu", transliterationB: "Qul lillazeena kafaroosatughlaboona wa tuhsharoona ilaa jahannam; wa bi'sal mihaad", english: "Say to those who reject Faith: \"Soon will ye be vanquished and gathered together to Hell,-an evil bed indeed (to lie on)", romanUrdu: "Pas (aey Muhammad) ! jin logon ne tumhari dawat ko qabool karne se inkar kardiya hai, unse kehdo ke qareeb hai woh waqt , jab tum magloob ho jaogey aur jahannum ki taraf haanke jaogey aur jahannum bada hi bura thikana hai" },
    { number: 13, arabic: "قَدْ كَانَ لَكُمْ ءَايَةٌۭ فِى فِئَتَيْنِ ٱلْتَقَتَا ۖ فِئَةٌۭ تُقَٰتِلُ فِى سَبِيلِ ٱللَّهِ وَأُخْرَىٰ كَافِرَةٌۭ يَرَوْنَهُم مِّثْلَيْهِمْ رَأْىَ ٱلْعَيْنِ ۚ وَٱللَّهُ يُؤَيِّدُ بِنَصْرِهِۦ مَن يَشَآءُ ۗ إِنَّ فِى ذَٰلِكَ لَعِبْرَةًۭ لِّأُو۟لِى ٱلْأَبْصَٰرِ", transliteration: "Qad kana lakum ayatun fee fiatayni iltaqata fiatun tuqatilu fee sabeeli Allahi waokhra kafiratun yarawnahum mithlayhim raya alAAayni waAllahu yuayyidu binasrihi man yashao inna fee thalika laAAibratan liolee alabsari", transliterationB: "Qad kaana lakum Aayatun fee fi'atainil taqataa fi'atun tuqaatilu fee sabeelil laahi wa ukhraa kaafiratuny yarawnahum mislaihim raayal 'ayn; wallaahu yu'ayyidu bi nasrihee mai yashaaa'; innaa fee zaalika la 'ibratal li ulil absaar", english: "There has already been for you a Sign in the two armies that met (in combat): One was fighting in the cause of Allah, the other resisting Allah; these saw with their own eyes Twice their number. But Allah doth support with His aid whom He pleaseth. In this is a warning for such as have eyes to see", romanUrdu: "Tumhare liye un do giroohon mein ek nishan e ibrat tha, jo (badr mein) ek dusre se nabard aazma (encountered) huey, ek giroh Allah ki raah mein ladd raha tha aur dusra giroh kafir tha, dekhne waley ba-chashm e sar dekh rahey thay ke kafir giroh momin giroh se do chandh (twice the number) hai magar (nateeje ne saabit kardiya ke) Allah apni fatah o nusrat se jisko chahta hai madad deta hai. Deedha e beena(eyes to see) rakhne walon ke liye ismein bada sabaq posheeda hai" },
    { number: 14, arabic: "زُيِّنَ لِلنَّاسِ حُبُّ ٱلشَّهَوَٰتِ مِنَ ٱلنِّسَآءِ وَٱلْبَنِينَ وَٱلْقَنَٰطِيرِ ٱلْمُقَنطَرَةِ مِنَ ٱلذَّهَبِ وَٱلْفِضَّةِ وَٱلْخَيْلِ ٱلْمُسَوَّمَةِ وَٱلْأَنْعَٰمِ وَٱلْحَرْثِ ۗ ذَٰلِكَ مَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَٱللَّهُ عِندَهُۥ حُسْنُ ٱلْمَـَٔابِ", transliteration: "Zuyyina lilnnasi hubbu alshshahawati mina alnnisai waalbaneena waalqanateeri almuqantarati mina alththahabi waalfiddati waalkhayli almusawwamati waalanAAami waalharthi thalika mataAAu alhayati alddunya waAllahu AAindahu husnu almaabi", transliterationB: "Zuyyina linnaasi hubbush shahawaati minannisaaa'i wal baneena walqanaateeril muqantarati minaz zahabi walfiddati walkhailil musawwamati wal an'aami walhars; zaalika mataa'ul hayaatid dunyaa wallaahu 'indahoo husnul ma-aab", english: "Fair in the eyes of men is the love of things they covet: Women and sons; Heaped-up hoards of gold and silver; horses branded (for blood and excellence); and (wealth of) cattle and well-tilled land. Such are the possessions of this world's life; but in nearness to Allah is the best of the goals (To return to)", romanUrdu: "Logon ke liye margoobaat e nafs (naturally tempted by the lure of) auratein, aulad, soney chandi ke dhair, cheeda ghodey(branded horses) maweshi aur zarayi zameenein badi khush-aand bana di gayi hain. Magar yeh sab duniya ki chandh roza zindagi ke samaan hain , haqeeqat mein jo behtar thikana hai woh to Allah ke paas hai" },
    { number: 15, arabic: "۞ قُلْ أَؤُنَبِّئُكُم بِخَيْرٍۢ مِّن ذَٰلِكُمْ ۚ لِلَّذِينَ ٱتَّقَوْا۟ عِندَ رَبِّهِمْ جَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا وَأَزْوَٰجٌۭ مُّطَهَّرَةٌۭ وَرِضْوَٰنٌۭ مِّنَ ٱللَّهِ ۗ وَٱللَّهُ بَصِيرٌۢ بِٱلْعِبَادِ", transliteration: "Qul aonabbiokum bikhayrin min thalikum lillatheena ittaqaw AAinda rabbihim jannatun tajree min tahtiha alanharu khalideena feeha waazwajun mutahharatun waridwanun mina Allahi waAllahu baseerun bialAAibadi", transliterationB: "Qul a'unabbi 'ukum bikhairim min zaalikum; lillazeenat taqaw 'inda Rabbihim jannaatun tajree min tahtihal anhaaru khaalideena feehaa wa azwaajum mutahharatunw wa ridwaanum minal laah; wallaahu baseerum bil'ibaad", english: "Say: Shall I give you glad tidings of things Far better than those? For the righteous are Gardens in nearness to their Lord, with rivers flowing beneath; therein is their eternal home; with companions pure (and holy); and the good pleasure of Allah. For in Allah's sight are (all) His servants", romanUrdu: "Kaho: main tumhein bataoon ke inse zyada acchi cheez kya hai? Jo log taqwa ki rawish ikhtiyar karein, unke liye unke Rubb ke paas baagh hain, jinke nichey nehrein behti hongi, wahan unhein hameshgi ki zindagi haasil hogi, pakeeza biwiyan unki rafeeq (companions) hongi aur Allah ki raza se woh sarfaraz honge. Allah apne bandon ke rawayye par gehri nazar rakhta hai" },
    { number: 16, arabic: "ٱلَّذِينَ يَقُولُونَ رَبَّنَآ إِنَّنَآ ءَامَنَّا فَٱغْفِرْ لَنَا ذُنُوبَنَا وَقِنَا عَذَابَ ٱلنَّارِ", transliteration: "Allatheena yaqooloona rabbana innana amanna faighfir lana thunoobana waqina AAathaba alnnari", transliterationB: "Allazeena yaqooloona Rabbanaaa innanaaa aamannaa faghfir lanaa zunoobanaa wa qinaa 'azaaban Naar", english: "(Namely), those who say: \"Our Lord! we have indeed believed: forgive us, then, our sins, and save us from the agony of the Fire", romanUrdu: "Yeh woh log hain, jo kehte hain ke “ maalik ! hum iman laye, hamari khataon se darguzar farma aur humein aatish e dozakh se bacha ley”" },
    { number: 17, arabic: "ٱلصَّٰبِرِينَ وَٱلصَّٰدِقِينَ وَٱلْقَٰنِتِينَ وَٱلْمُنفِقِينَ وَٱلْمُسْتَغْفِرِينَ بِٱلْأَسْحَارِ", transliteration: "Alssabireena waalssadiqeena waalqaniteena waalmunfiqeena waalmustaghfireena bialashari", transliterationB: "Assaabireena wassaa diqeena walqaaniteena walmunfiqeena walmus taghfireena bil ashaar", english: "Those who show patience, Firmness and self-control; who are true (in word and deed); who worship devoutly; who spend (in the way of Allah); and who pray for forgiveness in the early hours of the morning", romanUrdu: "Yeh log sabr karne waley hain, raastbaaz hain, farmabardaar aur fayyaz hain aur raat ki aaakhri ghadiyon mein Allah se magfirat ki duaein maanga karte hain" },
    { number: 18, arabic: "شَهِدَ ٱللَّهُ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا هُوَ وَٱلْمَلَٰٓئِكَةُ وَأُو۟لُوا۟ ٱلْعِلْمِ قَآئِمًۢا بِٱلْقِسْطِ ۚ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Shahida Allahu annahu la ilaha illa huwa waalmalaikatu waoloo alAAilmi qaiman bialqisti la ilaha illa huwa alAAazeezu alhakeemu", transliterationB: "Shahidal laahu annahoo laa ilaaha illaa Huwa walmalaaa'ikatu wa ulul 'ilmi qaaa'imam bilqist; laaa ilaaha illaa Huwal 'Azeezul Hakeem", english: "There is no god but He: That is the witness of Allah, His angels, and those endued with knowledge, standing firm on justice. There is no god but He, the Exalted in Power, the Wise", romanUrdu: "Allah ne khud shahadat di hai ke uske siwa koi khuda nahin hai, aur ( yahi shahadat) Farishton aur sab ehle ilm ne bhi di hai, woh insaaf par qayam hai, us zabardast hakeem ke siwa fil waqeh koi khuda nahin hai" },
    { number: 19, arabic: "إِنَّ ٱلدِّينَ عِندَ ٱللَّهِ ٱلْإِسْلَٰمُ ۗ وَمَا ٱخْتَلَفَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۗ وَمَن يَكْفُرْ بِـَٔايَٰتِ ٱللَّهِ فَإِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ", transliteration: "Inna alddeena AAinda Allahi alislamu wama ikhtalafa allatheena ootoo alkitaba illa min baAAdi ma jaahumu alAAilmu baghyan baynahum waman yakfur biayati Allahi fainna Allaha sareeAAu alhisabi", transliterationB: "Innad deena 'indal laahil Islaam; wa makhtalafal lazeena ootul Kitaaba illaa mim ba'di maa jaaa'ahumul 'ilmu baghyam bainahum; wa mai yakfur bi Aayaatil laahi fa innal laaha saree'ul hisaab", english: "The Religion before Allah is Islam (submission to His Will): Nor did the People of the Book dissent therefrom except through envy of each other, after knowledge had come to them. But if any deny the Signs of Allah, Allah is swift in calling to account", romanUrdu: "Allah ke nazdeek deen sirf Islam hai, is deen se hatt kar jo mukhtalif tareeqe un logon ne ikhtiyar kiye jinhein kitab di gayi thi, unke is tarz e amal ki koi wajah iske siwa na thi ke unhon ne ilm aa janey ke baad aapas mein ek dusre par zyadati karne ke liye aisa kiya. Aur jo koi Allah ke ehkaam o hidayaat ki itaat se inkar karde, Allah ko ussey hisaab lete kuch dair nahin lagti hai" },
    { number: 20, arabic: "فَإِنْ حَآجُّوكَ فَقُلْ أَسْلَمْتُ وَجْهِىَ لِلَّهِ وَمَنِ ٱتَّبَعَنِ ۗ وَقُل لِّلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ وَٱلْأُمِّيِّۦنَ ءَأَسْلَمْتُمْ ۚ فَإِنْ أَسْلَمُوا۟ فَقَدِ ٱهْتَدَوا۟ ۖ وَّإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْكَ ٱلْبَلَٰغُ ۗ وَٱللَّهُ بَصِيرٌۢ بِٱلْعِبَادِ", transliteration: "Fain hajjooka faqul aslamtu wajhiya lillahi wamani ittabaAAani waqul lillatheena ootoo alkitaba waalommiyyeena aaslamtum fain aslamoo faqadi ihtadaw wain tawallaw fainnama AAalayka albalaghu waAllahu baseerun bialAAibadi", transliterationB: "Fa in haaajjooka faqul aslamtu wajhiya lillaahi wa manit taba'an; wa qul lillazeena ootul Kitaaba wal ummiyyeena 'a-aslamtum; fa in aslamoo faqadih tadaw wa in tawallaw fa innamaa 'alaikal balaagh; wallaahu baseerum bil 'ibaad", english: "So if they dispute with thee, say: \"I have submitted My whole self to Allah and so have those who follow me.\" And say to the People of the Book and to those who are unlearned: \"Do ye (also) submit yourselves?\" If they do, they are in right guidance, but if they turn back, Thy duty is to convey the Message; and in Allah's sight are (all) His servants", romanUrdu: "Ab agar yeh log tumse jhaghda karein, to inse kaho : “ maine aur mere pairawon (followers) ne to Allah ke aagey sar tasleem kham kardiya hai”. Phir ehle kitab aur gair ehle kitab dono se pucho: “ kya tumne bhi uski itaat o bandagi qabool ki?” Agar ki to woh raah e raast paa gaye, aur agar issey mooh moda to tumpar sirf paigaam pahuncha dene ki zimmedari thi, aagey Allah khud apne bandon ke maamlaat dekhne wala hai" },
    { number: 21, arabic: "إِنَّ ٱلَّذِينَ يَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلنَّبِيِّۦنَ بِغَيْرِ حَقٍّۢ وَيَقْتُلُونَ ٱلَّذِينَ يَأْمُرُونَ بِٱلْقِسْطِ مِنَ ٱلنَّاسِ فَبَشِّرْهُم بِعَذَابٍ أَلِيمٍ", transliteration: "Inna allatheena yakfuroona biayati Allahi wayaqtuloona alnnabiyyeena bighayri haqqin wayaqtuloona allatheena yamuroona bialqisti mina alnnasi fabashshirhum biAAathabin aleemin", transliterationB: "Innal lazeena yakfuroona bi Aayaatil laahi wa yaqtuloonan Nabiyyeena bighairi haqqinw wa yaqtuloonal lazeena yaamuroona bilqisti minannaasi fabashirhum bi'azaabin aleem", english: "As to those who deny the Signs of Allah and in defiance of right, slay the prophets, and slay those who teach just dealing with mankind, announce to them a grievous penalty", romanUrdu: "Jo log Allah ke ehkaam o hidayaat ko maanne se inkar karte hain aur uske paigambaron ko na-haqq qatal karte hain aur aisey logon ki jaan ke darpe ho jatey hain jo khalq e khuda mein adal o raasti ka hukum dene ke liye uthein, unko dardnaak saza ki khushkhabri suna do" },
    { number: 22, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ حَبِطَتْ أَعْمَٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَمَا لَهُم مِّن نَّٰصِرِينَ", transliteration: "Olaika allatheena habitat aAAmaluhum fee alddunya waalakhirati wama lahum min nasireena", transliterationB: "Ulaaa'ikal lazeena habitat a'maaluhum fid dunyaa wal Aaakhirati wa maa lahum min naasireen", english: "They are those whose works will bear no fruit in this world and in the Hereafter nor will they have anyone to help", romanUrdu: "Yeh woh log hain jinke aamaal duniya aur aakhirat dono mein zaya ho gaye, aur inka madadgaar koi nahin hai" },
    { number: 23, arabic: "أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًۭا مِّنَ ٱلْكِتَٰبِ يُدْعَوْنَ إِلَىٰ كِتَٰبِ ٱللَّهِ لِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلَّىٰ فَرِيقٌۭ مِّنْهُمْ وَهُم مُّعْرِضُونَ", transliteration: "Alam tara ila allatheena ootoo naseeban mina alkitabi yudAAawna ila kitabi Allahi liyahkuma baynahum thumma yatawalla fareequn minhum wahum muAAridoona", transliterationB: "Alam tara ilal lazeena ootoo naseebam minal Kitaabi yud'awna ilaa Kitaabil laahi liyahkuma bainahum summa yatawallaa fareequm minhum wa hum mu'ridoon", english: "Hast thou not turned Thy vision to those who have been given a portion of the Book? They are invited to the Book of Allah, to settle their dispute, but a party of them Turn back and decline (The arbitration)", romanUrdu: "Tumne dekha nahin ke jin logon ko kitab ke ilm mein se kuch hissa mila hai, unka haal kya hai? Unhein jab kitab e ilahi ki taraf bulaya jata hai taa-ke woh unke darmiyan faisla karey, to unmein se ek fareeq issey pehlu-tahi (turns away) karta hai aur is faisle ki taraf aane se mooh pher jata hai" },
    { number: 24, arabic: "ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامًۭا مَّعْدُودَٰتٍۢ ۖ وَغَرَّهُمْ فِى دِينِهِم مَّا كَانُوا۟ يَفْتَرُونَ", transliteration: "Thalika biannahum qaloo lan tamassana alnnaru illa ayyaman maAAdoodatin wagharrahum fee deenihim ma kanoo yaftaroona", transliterationB: "Zaalika bi annahum qaaloo lan tamassanan naaru illaaa ayyaamam ma'doodaatinw wa gharrahum fee deenihim maa kaanoo yaftaroon", english: "This because they say: \"The Fire shall not touch us but for a few numbered days\": For their forgeries deceive them as to their own religion", romanUrdu: "Unka yeh tarz-e-amal is wajah se hai ke woh kehte hain “ aatish e dozakh to humein mass (choo) tak na karegi aur agar dozakh ki saza humko milegi bhi to bas chandh roz”. Unke khud saakhta aqeedon ne unko apne deen ke maamle mein badi galat fehmiyon mein daal rakkha hai" },
    { number: 25, arabic: "فَكَيْفَ إِذَا جَمَعْنَٰهُمْ لِيَوْمٍۢ لَّا رَيْبَ فِيهِ وَوُفِّيَتْ كُلُّ نَفْسٍۢ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Fakayfa itha jamaAAnahum liyawmin la rayba feehi wawuffiyat kullu nafsin ma kasabat wahum la yuthlamoona", transliterationB: "Fakaifa izaa jama'naahum li Yawmil laa raiba fee wa wuffiyat kullu nafsim maa kasabat wa hum laa yuzlamoon", english: "But how (will they fare) when we gather them together against a day about which there is no doubt, and each soul will be paid out just what it has earned, without (favour or) injustice", romanUrdu: "Magar kya banegi unpar jab hum unhein us roz jamaa karenge jiska aana yaqeeni hai? Us roz har shaks ko uski kamayi ka badla poora poora de diya jayega aur kisi par zulm na hoga" },
    { number: 26, arabic: "قُلِ ٱللَّهُمَّ مَٰلِكَ ٱلْمُلْكِ تُؤْتِى ٱلْمُلْكَ مَن تَشَآءُ وَتَنزِعُ ٱلْمُلْكَ مِمَّن تَشَآءُ وَتُعِزُّ مَن تَشَآءُ وَتُذِلُّ مَن تَشَآءُ ۖ بِيَدِكَ ٱلْخَيْرُ ۖ إِنَّكَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Quli allahumma malika almulki tutee almulka man tashao watanziAAu almulka mimman tashao watuAAizzu man tashao watuthillu man tashao biyadika alkhayru innaka AAala kulli shayin qadeerun", transliterationB: "Qulil laahumma Maalikal Mulki tu'til mulka man tashaaa'u wa tanzi'ulmulka mimman tashhaaa'u wa tu'izzu man tashaaa'u wa tuzillu man tashaaa'u biyadikal khairu innaka 'alaa kulli shai'in Qadeer", english: "Say: \"O Allah! Lord of Power (And Rule), Thou givest power to whom Thou pleasest, and Thou strippest off power from whom Thou pleasest: Thou enduest with honour whom Thou pleasest, and Thou bringest low whom Thou pleasest: In Thy hand is all good. Verily, over all things Thou hast power", romanUrdu: "Kaho! Khudaya! Mulk ke maalik! Tu jisey chahey, hukumat de aur jissey chahey cheen le, jisey chahey izzat bakshey aur jisko chahey zillat de. Bhalayi tere ikhtiyar mein hai. Beshak tu har cheez par qaadir hai" },
    { number: 27, arabic: "تُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَتُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ ۖ وَتُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَتُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ ۖ وَتَرْزُقُ مَن تَشَآءُ بِغَيْرِ حِسَابٍۢ", transliteration: "Tooliju allayla fee alnnahari watooliju alnnahara fee allayli watukhriju alhayya mina almayyiti watukhriju almayyita mina alhayyi watarzuqu man tashao bighayri hisabin", transliterationB: "Toolijul laila fin nahaari wa toolijun nahaara fil laili wa tukhrijul haiya minalmaiyiti wa tukhrijulo maiyita minal haiyi wa tarzuqu man tashaaa'u bighari hisab", english: "Thou causest the night to gain on the day, and thou causest the day to gain on the night; Thou bringest the Living out of the dead, and Thou bringest the dead out of the Living; and Thou givest sustenance to whom Thou pleasest, without measure", romanUrdu: "Raat ko din mein pirota hua le aata hai aur din ko raat mein, jaandaar mein se be-jaan ko nikalta hai aur be-jaan mein se jaandaar ko, aur jisey chahta hai be-hisaab rizq deta hai" },
    { number: 28, arabic: "لَّا يَتَّخِذِ ٱلْمُؤْمِنُونَ ٱلْكَٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۖ وَمَن يَفْعَلْ ذَٰلِكَ فَلَيْسَ مِنَ ٱللَّهِ فِى شَىْءٍ إِلَّآ أَن تَتَّقُوا۟ مِنْهُمْ تُقَىٰةًۭ ۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفْسَهُۥ ۗ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ", transliteration: "La yattakhithi almuminoona alkafireena awliyaa min dooni almumineena waman yafAAal thalika falaysa mina Allahi fee shayin illa an tattaqoo minhum tuqatan wayuhaththirukumu Allahu nafsahu waila Allahi almaseeru", transliterationB: "Laa yattakhizil mu'minoonal kaafireena awliyaaa'a min doonil mu'mineena wa mai yaf'al zaalika falaisa minal laahi fee shai'in illaaa an tattaqoo minhum tuqaah; wa yuhazzirukumul laahu nafsah; wa ilal laahil maseer", english: "Let not the believers Take for friends or helpers Unbelievers rather than believers: if any do that, in nothing will there be help from Allah: except by way of precaution, that ye may Guard yourselves from them. But Allah cautions you (To remember) Himself; for the final goal is to Allah", romanUrdu: "Momineen ehle iman ko chodh kar kafiron ko apna rafeeq aur dost hargiz na banayein, jo aisa karega uska Allah se koi talluq nahin, haan yeh maaf hai ke tum unke zulm se bachne ke liye bazahir aisa tarz e amal ikhtiyar kar jao, magar Allah tumhein apne aap se darata hai aur tumhein usi ki taraf palat kar jana hai" },
    { number: 29, arabic: "قُلْ إِن تُخْفُوا۟ مَا فِى صُدُورِكُمْ أَوْ تُبْدُوهُ يَعْلَمْهُ ٱللَّهُ ۗ وَيَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Qul in tukhfoo ma fee sudoorikum aw tubdoohu yaAAlamhu Allahu wayaAAlamu ma fee alssamawati wama fee alardi waAllahu AAala kulli shayin qadeerun", transliterationB: "Qul in tukhfoo maa fee sudoorikum aw tubdoohu ya'lamhul laah; wa ya'lamu maa fis samaawaati wa maa fil ard; wallaahu 'alaa kulli shai'in Qadeer", english: "Say: \"Whether ye hide what is in your hearts or reveal it, Allah knows it all: He knows what is in the heavens, and what is on earth. And Allah has power over all things", romanUrdu: "(Aey Nabi)! Logon ko khabardaar kardo ke tumhare dilon mein jo kuch hai, usey khwa tum chupao ya zaahir karo, Allah bahar haal usey jaanta hai. Zameen o asmaan ki koi cheez uske ilm se bahar nahin hai aur uska iqtedar har cheez par haawi hai" },
    { number: 30, arabic: "يَوْمَ تَجِدُ كُلُّ نَفْسٍۢ مَّا عَمِلَتْ مِنْ خَيْرٍۢ مُّحْضَرًۭا وَمَا عَمِلَتْ مِن سُوٓءٍۢ تَوَدُّ لَوْ أَنَّ بَيْنَهَا وَبَيْنَهُۥٓ أَمَدًۢا بَعِيدًۭا ۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفْسَهُۥ ۗ وَٱللَّهُ رَءُوفٌۢ بِٱلْعِبَادِ", transliteration: "Yawma tajidu kullu nafsin ma AAamilat min khayrin muhdaran wama AAamilat min sooin tawaddu law anna baynaha wabaynahu amadan baAAeedan wayuhaththirukumu Allahu nafsahu waAllahu raoofun bialAAibadi", transliterationB: "Yawma tajidu kullu nafsim maa'amilat min khairim muhdaranw wa maa 'amilat min sooo'in tawaddu law anna bainahaa wa bainahooo amadam ba'eedaa; wa yuhazzirukumul laahu nafsah; wallaahu ra'oofum bil'ibaad", english: "On the Day when every soul will be confronted with all the good it has done, and all the evil it has done, it will wish there were a great distance between it and its evil. But Allah cautions you (To remember) Himself. And Allah is full of kindness to those that serve Him", romanUrdu: "Woh din aane wala hai, jab har nafs apne kiye ka phal hazir payega khwa usne bhalayi ki ho ya burayi. Us roz aadmi yeh tamanna karega ke kaash abhi yeh din ussey bahut door hota! Allah tumhein apne aap se darata hai aur woh apne bandon ka nihayat khair khwa hai" },
    { number: 31, arabic: "قُلْ إِن كُنتُمْ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِى يُحْبِبْكُمُ ٱللَّهُ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ ۗ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Qul in kuntum tuhibboona Allaha faittabiAAoonee yuhbibkumu Allahu wayaghfir lakum thunoobakum waAllahu ghafoorun raheemun", transliterationB: "Qul in kuntum tuhibboonal laaha fattabi' oonee yuhbibkumul laahu wa yaghfir lakum zunoobakum; wallaahu Ghafoorur Raheem", english: "Say: \"If ye do love Allah, Follow me: Allah will love you and forgive you your sins: For Allah is Oft-Forgiving, Most Merciful", romanUrdu: "(Aey Nabi)! Logon se kehdo ke “agar tum haqeeqat mein Allah se muhabbat rakhte ho , to meri pairwi ikhtiyar karo, Allah tumse muhabbat karega aur tumhari khataon se darguzar farmayega, woh bada maaf karne wala aur Raheem hai”" },
    { number: 32, arabic: "قُلْ أَطِيعُوا۟ ٱللَّهَ وَٱلرَّسُولَ ۖ فَإِن تَوَلَّوْا۟ فَإِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْكَٰفِرِينَ", transliteration: "Qul ateeAAoo Allaha waalrrasoola fain tawallaw fainna Allaha la yuhibbu alkafireena", transliterationB: "Qul atee'ul laaha war Rasoola fa in tawallaw fa innal laaha laa yuhibbul kaafireen", english: "Say: \"Obey Allah and His Messenger\": But if they turn back, Allah loveth not those who reject Faith", romanUrdu: "Unse kaho ke “Allah aur Rasool ki itaat qabool karlo” phir agar woh tumhari dawat qabool na karein, to yaqeenan yeh mumkin nahin hai ke Allah aise logon se muhabbat karey jo uski aur uske Rasool ki itaat se inkar karte hon" },
    { number: 33, arabic: "۞ إِنَّ ٱللَّهَ ٱصْطَفَىٰٓ ءَادَمَ وَنُوحًۭا وَءَالَ إِبْرَٰهِيمَ وَءَالَ عِمْرَٰنَ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Inna Allaha istafa adama wanoohan waala ibraheema waala AAimrana AAala alAAalameena", transliterationB: "Innal laahas tafaaa Aadama wa Noohanw wa Aala Ibraaheema wa Aala Imraana 'alal 'aalameen", english: "Allah did choose Adam and Noah, the family of Abraham, and the family of 'Imran above all people", romanUrdu: "Allah ne Adam aur Nooh aur aale- Ibrahim aur aal-e-Imran ko tamaam duniya walon par tarjeeh dekar ( apni risalat ke liye) muntakhab kiya tha" },
    { number: 34, arabic: "ذُرِّيَّةًۢ بَعْضُهَا مِنۢ بَعْضٍۢ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ", transliteration: "Thurriyyatan baAAduha min baAAdin waAllahu sameeAAun AAaleemun", transliterationB: "Zurriyyatam ba'duhaa mim ba'd; wallaahu Samee'un 'Aleem", english: "Offspring, one of the other: And Allah heareth and knoweth all things", romanUrdu: "Yeh ek silsile ke log thay, jo ek dusre ki nasal se paida huey thay, Allah sabkuch sunta aur jaanta hai" },
    { number: 35, arabic: "إِذْ قَالَتِ ٱمْرَأَتُ عِمْرَٰنَ رَبِّ إِنِّى نَذَرْتُ لَكَ مَا فِى بَطْنِى مُحَرَّرًۭا فَتَقَبَّلْ مِنِّىٓ ۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Ith qalati imraatu AAimrana rabbi innee nathartu laka ma fee batnee muharraran fataqabbal minnee innaka anta alssameeAAu alAAaleemu", transliterationB: "Iz qaalatim ra atu 'Imraana Rabbi innee nazartu laka maa fee batnee muharraran fataqabbal minnee innaka Antas Samee'ul 'Aleem", english: "Behold! a woman of 'Imran said: \"O my Lord! I do dedicate unto Thee what is in my womb for Thy special service: So accept this of me: For Thou hearest and knowest all things", romanUrdu: "(Woh us waqt sun raha tha) jab Imran ki aurat keh rahi thi ke, “ mere parwardigaar! Main is bacchey ko jo mere pait mein hai teri nazar karti hoon, woh tere hi kaam ke liye waqf hoga, meri is peshkash ko qabool farma, tu sunne aur jaanne wala hai.”" },
    { number: 36, arabic: "فَلَمَّا وَضَعَتْهَا قَالَتْ رَبِّ إِنِّى وَضَعْتُهَآ أُنثَىٰ وَٱللَّهُ أَعْلَمُ بِمَا وَضَعَتْ وَلَيْسَ ٱلذَّكَرُ كَٱلْأُنثَىٰ ۖ وَإِنِّى سَمَّيْتُهَا مَرْيَمَ وَإِنِّىٓ أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنَ ٱلشَّيْطَٰنِ ٱلرَّجِيمِ", transliteration: "Falamma wadaAAatha qalat rabbi innee wadaAAtuha ontha waAllahu aAAlamu bima wadaAAat walaysa alththakaru kaalontha wainnee sammaytuha maryama wainnee oAAeethuha bika wathurriyyataha mina alshshaytani alrrajeemi", transliterationB: "Falammaa waqa'athaa qaalat Rabbi innee wada'tuhaaa unsaa wallaahu a'lamu bimaa wada'at wa laisaz zakaru kalunsaa wa innee sammaituhaa Maryama wa innee u'eezuhaa bika wa zurriyyatahaa minash Shaitaanir Rajeem", english: "When she was delivered, she said: \"O my Lord! Behold! I am delivered of a female child!\"- and Allah knew best what she brought forth- \"And no wise is the male Like the female. I have named her Mary, and I commend her and her offspring to Thy protection from the Evil One, the Rejected", romanUrdu: "Phir jab woh bacchi uske haan paida hui to usne kaha “Maalik! Mere haan to ladki paida ho gayi hai, halaanke jo kuch usne janaa(delivered) tha, Allah ko iski khabar thi aur ladka ladki ki tarah nahin hota. Khair, maine uska naam Maryam rakh diya hai aur main usey aur uski aainda nasal ko shaytan mardood ke fitne se teri panaah mein deti hoon”" },
    { number: 37, arabic: "فَتَقَبَّلَهَا رَبُّهَا بِقَبُولٍ حَسَنٍۢ وَأَنۢبَتَهَا نَبَاتًا حَسَنًۭا وَكَفَّلَهَا زَكَرِيَّا ۖ كُلَّمَا دَخَلَ عَلَيْهَا زَكَرِيَّا ٱلْمِحْرَابَ وَجَدَ عِندَهَا رِزْقًۭا ۖ قَالَ يَٰمَرْيَمُ أَنَّىٰ لَكِ هَٰذَا ۖ قَالَتْ هُوَ مِنْ عِندِ ٱللَّهِ ۖ إِنَّ ٱللَّهَ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍ", transliteration: "Fataqabbalaha rabbuha biqaboolin hasanin waanbataha nabatan hasanan wakaffalaha zakariyya kullama dakhala AAalayha zakariyya almihraba wajada AAindaha rizqan qala ya maryamu anna laki hatha qalat huwa min AAindi Allahi inna Allaha yarzuqu man yashao bighayri hisabin", transliterationB: "Fataqabbalahaa Rabbuhaa biqaboolin hasaninw wa ambatahaa nabaatan hasananw wa kaffalahaa Zakariyyaa kullamaa dakhala 'alaihaa Zakariyyal Mihraaba wajada 'indahaa rizqan qaala yaa Maryamu annaa laki haazaa qaalat huwa min 'indil laahi innal laaha yarzuqu mai yashaaa'u bighairi hisaab", english: "Right graciously did her Lord accept her: He made her grow in purity and beauty: To the care of Zakariya was she assigned. Every time that he entered (Her) chamber to see her, He found her supplied with sustenance. He said: \"O Mary! Whence (comes) this to you?\" She said: \"From Allah: for Allah Provides sustenance to whom He pleases without measure", romanUrdu: "Aakhir e kaar uske Rubb ne us ladki ko ba-khushi qabool farma liya , usey badi acchi ladki banakar uthaya aur Zakariya ko uska sarparast bana diya. Zakariya jab kabhi uske paas mehraab (sanctuary) mein jaata to uske paas kuch na kuch khane peene ka samaan paata. Puchta Maryam! Yeh tere paas kahan se aaya? Woh jawab deti Allah ke paas se aaya hai, Allah jisey chahta hai be-hisaab deta hai" },
    { number: 38, arabic: "هُنَالِكَ دَعَا زَكَرِيَّا رَبَّهُۥ ۖ قَالَ رَبِّ هَبْ لِى مِن لَّدُنكَ ذُرِّيَّةًۭ طَيِّبَةً ۖ إِنَّكَ سَمِيعُ ٱلدُّعَآءِ", transliteration: "Hunalika daAAa zakariyya rabbahu qala rabbi hab lee min ladunka thurriyyatan tayyibatan innaka sameeAAu aldduAAai", transliterationB: "Hunaaalika da'aa Zakariyyaa Rabbahoo qaala Rabbi hab lee mil ladunka zurriyyatan taiyibatan innaka samee'ud du'aaa", english: "There did Zakariya pray to his Lord, saying: \"O my Lord! Grant unto me from Thee a progeny that is pure: for Thou art He that heareth prayer", romanUrdu: "Yeh haal dekh kar Zakariya ne apne Rubb ko pukara “parwardigaar! Apni qudrat se mujhey neik aulad ata kar, tu hi dua sunne wala hai”" },
    { number: 39, arabic: "فَنَادَتْهُ ٱلْمَلَٰٓئِكَةُ وَهُوَ قَآئِمٌۭ يُصَلِّى فِى ٱلْمِحْرَابِ أَنَّ ٱللَّهَ يُبَشِّرُكَ بِيَحْيَىٰ مُصَدِّقًۢا بِكَلِمَةٍۢ مِّنَ ٱللَّهِ وَسَيِّدًۭا وَحَصُورًۭا وَنَبِيًّۭا مِّنَ ٱلصَّٰلِحِينَ", transliteration: "Fanadathu almalaikatu wahuwa qaimun yusallee fee almihrabi anna Allaha yubashshiruka biyahya musaddiqan bikalimatin mina Allahi wasayyidan wahasooran wanabiyyan mina alssaliheena", transliterationB: "Fanaadat hul malaaa'ikatu wa huwa qaaa'imuny yusallee fil Mihraabi annal laaha yubashshiruka bi Yahyaa musaddiqam bi Kalimatim minal laahi wa saiyidanw wa hasooranw wa Nabiyyam minas saaliheen", english: "While he was standing in prayer in the chamber, the angels called unto him: \"Allah doth give thee glad tidings of Yahya, witnessing the truth of a Word from Allah, and (be besides) noble, chaste, and a prophet,- of the (goodly) company of the righteous", romanUrdu: "Jawab mein Farishton ne awaaz di, jab ke woh mehraab mein khada namaz padh raha tha ke “Allah tujhey Yahya ki khushkhabri deta hai , woh Allah ki taraf se ek farmaan ki tasdeeq karne wala bankar aayega, usmein sardari o buzurgi ki shaan hogi kamal darje ka zaabit (utterly chaste) hoga, nabuwat se sarfaraz hoga aur saliheen mein shumaar kiya jayega”" },
    { number: 40, arabic: "قَالَ رَبِّ أَنَّىٰ يَكُونُ لِى غُلَٰمٌۭ وَقَدْ بَلَغَنِىَ ٱلْكِبَرُ وَٱمْرَأَتِى عَاقِرٌۭ ۖ قَالَ كَذَٰلِكَ ٱللَّهُ يَفْعَلُ مَا يَشَآءُ", transliteration: "Qala rabbi anna yakoonu lee ghulamun waqad balaghaniya alkibaru waimraatee AAaqirun qala kathalika Allahu yafAAalu ma yashao", transliterationB: "Qaala Rabbi annaa yakoonu lee ghulaamunw wa qad balaghaniyal kibaru wamraatee 'aaqirun qaala kazaalikal laahu yaf'alu maa yashaaa", english: "He said: \"O my Lord! How shall I have son, seeing I am very old, and my wife is barren?\" \"Thus,\" was the answer, \"Doth Allah accomplish what He willeth", romanUrdu: "Zakariya ne kaha,“Parwardigaar! Bhala mere haan ladka kahan se hoga, main to boodha ho chuka hoon aur meri biwi baanjh hai, “ jawab mila, aisa hi hoga, Allah jo chahta hai karta hai”" },
    { number: 41, arabic: "قَالَ رَبِّ ٱجْعَل لِّىٓ ءَايَةًۭ ۖ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَٰثَةَ أَيَّامٍ إِلَّا رَمْزًۭا ۗ وَٱذْكُر رَّبَّكَ كَثِيرًۭا وَسَبِّحْ بِٱلْعَشِىِّ وَٱلْإِبْكَٰرِ", transliteration: "Qala rabbi ijAAal lee ayatan qala ayatuka alla tukallima alnnasa thalathata ayyamin illa ramzan waothkur rabbaka katheeran wasabbih bialAAashiyyi waalibkari", transliterationB: "Qaala Rabbij 'al leee Aayatan qaala Aaayatuka allaa tukalliman naasa salaasata ayyaamin illa ramzaa; wzkur Rabbaka kaseeranw wa sabbih bil'ashiyyi wal ibkaar", english: "He said: \"O my Lord! Give me a Sign!\" \"Thy Sign,\" was the answer, \"Shall be that thou shalt speak to no man for three days but with signals. Then celebrate the praises of thy Lord again and again, and glorify Him in the evening and in the morning", romanUrdu: "Arz kiya “Maalik! Phir koi nishani mere liye muqarrar farma de”. Kaha, Nishani yeh hai ke tum teen din tak logon se isharey ke siwa koi baat-chit na karoge (ya na kar sakoge), is dauraan mein apne Rubb ko bahut yaad karna aur subah o sham uski tasbeeh karte rehna.”" },
    { number: 42, arabic: "وَإِذْ قَالَتِ ٱلْمَلَٰٓئِكَةُ يَٰمَرْيَمُ إِنَّ ٱللَّهَ ٱصْطَفَىٰكِ وَطَهَّرَكِ وَٱصْطَفَىٰكِ عَلَىٰ نِسَآءِ ٱلْعَٰلَمِينَ", transliteration: "Waith qalati almalaikatu ya maryamu inna Allaha istafaki watahharaki waistafaki AAala nisai alAAalameena", transliterationB: "Wa iz qaalatil malaaa'ikatu yaa Ya Maryamu innal laahas tafaaki wa tahharaki wastafaaki 'alaa nisaaa'il 'aalameen", english: "Behold! the angels said: \"O Mary! Allah hath chosen thee and purified thee- chosen thee above the women of all nations", romanUrdu: "Phir woh waqt aaya jab Maryan se Farishton ne aakar kaha, “ Aey Maryam! Allah ne tujhey barguzeeda kiya aur pakeezgi ata ki aur tamaam duniya ki auraton par tujhko tarjeeh dekar apni khidmat ke liye chun liya" },
    { number: 43, arabic: "يَٰمَرْيَمُ ٱقْنُتِى لِرَبِّكِ وَٱسْجُدِى وَٱرْكَعِى مَعَ ٱلرَّٰكِعِينَ", transliteration: "Ya maryamu oqnutee lirabbiki waosjudee wairkaAAee maAAa alrrakiAAeena", transliterationB: "Yaa Maryamuq nutee li Rabbiki wasjudee warka'ee ma'ar raaki'een", english: "O Mary! worship Thy Lord devoutly: Prostrate thyself, and bow down (in prayer) with those who bow down", romanUrdu: "Aey Maryam! Apne Rubb ki tabeh farmaan bankar reh, uske aagey sar ba-sajood ho, aur jo banday uske huzoor jhukne waley hain unke saath tu bhi jhuk ja”" },
    { number: 44, arabic: "ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهِ إِلَيْكَ ۚ وَمَا كُنتَ لَدَيْهِمْ إِذْ يُلْقُونَ أَقْلَٰمَهُمْ أَيُّهُمْ يَكْفُلُ مَرْيَمَ وَمَا كُنتَ لَدَيْهِمْ إِذْ يَخْتَصِمُونَ", transliteration: "Thalika min anbai alghaybi nooheehi ilayka wama kunta ladayhim ith yulqoona aqlamahum ayyuhum yakfulu maryama wama kunta ladayhim ith yakhtasimoona", transliterationB: "Zaalika min ambaaa'il ghaibi nooheehi ilaik; wa maa kunta ladaihim iz yulqoona aqlaamahum ayyuhum yakfulu Maryama wa maa kunta ladaihim iz yakhtasimoon", english: "This is part of the tidings of the things unseen, which We reveal unto thee (O Messenger!) by inspiration: Thou wast not with them when they cast lots with arrows, as to which of them should be charged with the care of Mary: Nor wast thou with them when they disputed (the point)", romanUrdu: "(Aey Muhammad)! Yeh gaib ki khabrein hain jo hum tumko wahee ke zariye se bata rahey hain, warna tum us waqt wahan maujood na thay jab haykal ke khadim yeh faisla karne ke liye ke Mayram ka sarparast kaun ho apne apne qalam phenk rahey thay, aur na tum us waqt hazir thay jab unke darmiyaan jhagda barpa tha" },
    { number: 45, arabic: "إِذْ قَالَتِ ٱلْمَلَٰٓئِكَةُ يَٰمَرْيَمُ إِنَّ ٱللَّهَ يُبَشِّرُكِ بِكَلِمَةٍۢ مِّنْهُ ٱسْمُهُ ٱلْمَسِيحُ عِيسَى ٱبْنُ مَرْيَمَ وَجِيهًۭا فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَمِنَ ٱلْمُقَرَّبِينَ", transliteration: "Ith qalati almalaikatu ya maryamu inna Allaha yubashshiruki bikalimatin minhu ismuhu almaseehu AAeesa ibnu maryama wajeehan fee alddunya waalakhirati wamina almuqarrabeena", transliterationB: "Iz qaalatil malaaa'ikatu yaa Maryamu innal laaha yubashshiruki bi Kalimatim minhus muhul Maseeh u 'Eesab nu Maryama wajeehan fid dunyaa wal Aakhirati wa minal muqarrabeen", english: "Behold! the angels said: \"O Mary! Allah giveth thee glad tidings of a Word from Him: his name will be Christ Jesus, the son of Mary, held in honour in this world and the Hereafter and of (the company of) those nearest to Allah", romanUrdu: "Aur jab Farishton ne kaha, “Aey Maryam! Allah tujhey apne ek farmaan ki khush-khabri deta hai, uska naam Maseeh Isa Ibn e Maryam hoga, duniya aur aakhirat mein muazzaz (highly honoured) hoga, Allah ke muqarrab bandon mein shumaar kiya jayega" },
    { number: 46, arabic: "وَيُكَلِّمُ ٱلنَّاسَ فِى ٱلْمَهْدِ وَكَهْلًۭا وَمِنَ ٱلصَّٰلِحِينَ", transliteration: "Wayukallimu alnnasa fee almahdi wakahlan wamina alssaliheena", transliterationB: "Wa yukallimun naasa filmahdi wa kahlanw wa minassaaliheen", english: "He shall speak to the people in childhood and in maturity. And he shall be (of the company) of the righteous", romanUrdu: "Logon se gehware(cradle) mein bhi kalaam(baat) karega aur badi umar ko pahunch kar bhi, aur woh ek mard e saleeh hoga”" },
    { number: 47, arabic: "قَالَتْ رَبِّ أَنَّىٰ يَكُونُ لِى وَلَدٌۭ وَلَمْ يَمْسَسْنِى بَشَرٌۭ ۖ قَالَ كَذَٰلِكِ ٱللَّهُ يَخْلُقُ مَا يَشَآءُ ۚ إِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ", transliteration: "Qalat rabbi anna yakoonu lee waladun walam yamsasnee basharun qala kathaliki Allahu yakhluqu ma yashao itha qada amran fainnama yaqoolu lahu kun fayakoonu", transliterationB: "Qaalat Rabbi annaa yakoonu ee waladunw wa lam yamsasnee basharun qaala kazaalikil laahu yakhluqu maa yashaaa'; izaa qadaaa amran fa innamaa yaqoolu lahoo kun fayakoon", english: "She said: \"O my Lord! How shall I have a son when no man hath touched me?\" He said: \"Even so: Allah createth what He willeth: When He hath decreed a plan, He but saith to it, 'Be,' and it is", romanUrdu: "Yeh sunkar Maryam boli, “parwardigaar! Mere haan bacha kahan se hoga, muhjey to kisi shaks ne haath tak nahin lagaya” jawab mila, “aisa hi hoga, Allah jo chahta hai paida karta hai. Woh jab kisi kaam ke karne ka faisla farmata hai to bas kehta hai ke hoja aur woh ho jata hai”" },
    { number: 48, arabic: "وَيُعَلِّمُهُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ", transliteration: "WayuAAallimuhu alkitaba waalhikmata waalttawrata waalinjeela", transliterationB: "Wa yu'allimuhul Kitaaba wal Hikmata wat Tawraata wal Injeel", english: "And Allah will teach him the Book and Wisdom, the Law and the Gospel", romanUrdu: "(Farishton ne phir silsila e kalaam mein kaha) “Aur Allah usey kitab aur hikmat ki taleem dega, Taurat aur Injil ka ilm sikhayega" },
    { number: 49, arabic: "وَرَسُولًا إِلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَنِّى قَدْ جِئْتُكُم بِـَٔايَةٍۢ مِّن رَّبِّكُمْ ۖ أَنِّىٓ أَخْلُقُ لَكُم مِّنَ ٱلطِّينِ كَهَيْـَٔةِ ٱلطَّيْرِ فَأَنفُخُ فِيهِ فَيَكُونُ طَيْرًۢا بِإِذْنِ ٱللَّهِ ۖ وَأُبْرِئُ ٱلْأَكْمَهَ وَٱلْأَبْرَصَ وَأُحْىِ ٱلْمَوْتَىٰ بِإِذْنِ ٱللَّهِ ۖ وَأُنَبِّئُكُم بِمَا تَأْكُلُونَ وَمَا تَدَّخِرُونَ فِى بُيُوتِكُمْ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Warasoolan ila banee israeela annee qad jitukum biayatin min rabbikum annee akhluqu lakum mina altteeni kahayati alttayri faanfukhu feehi fayakoonu tayran biithni Allahi waobrio alakmaha waalabrasa waohyee almawta biithni Allahi waonabbiokum bima takuloona wama taddakhiroona fee buyootikum inna fee thalika laayatan lakum in kuntum mumineena", transliterationB: "Wa Rasoolan ilaa Baneee Israaa'eela annee qad ji'tukum bi Aayatim mir Rabbikum annee akhluqu lakum minatteeni kahai 'atittairi fa anfukhu feehi fayakoonu tairam bi iznil laahi wa ubri'ul akmaha wal abrasa wa uhyil mawtaa bi iznil laahi wa unabbi'ukum bimaa taakuloona wa maa taddakhiroona fee buyootikum; inna fee zaalika la Aayatal lakum in kuntum mu'mineen", english: "And (appoint him) a messenger to the Children of Israel, (with this message): \"'I have come to you, with a Sign from your Lord, in that I make for you out of clay, as it were, the figure of a bird, and breathe into it, and it becomes a bird by Allah's leave: And I heal those born blind, and the lepers, and I quicken the dead, by Allah's leave; and I declare to you what ye eat, and what ye store in your houses. Surely therein is a Sign for you if ye did believe", romanUrdu: "Aur bani Israel ki taraf apna Rasool muqarrar karega” (aur jab woh bahaisiyat e Rasool bani Israel ke paas aaya to usne kaha) “ main tumhare Rubb ki taraf se tumhare paas nishani lekar aaya hoon, main tumhare samne mitti se parinde ki surat mein ek mujassama banata hoon aur usmein phoonk maarta hoon, woh Allah ke hukum se parinda ban jata hai, main Allah ke hukum se madar zaadh (by birth) andhey aur kodi (leper) ko accha karta hoon aur murde ko zinda karta hoon, main tumhein batata hoon ke tum kya khate ho aur kya apne gharon mein zakheera (store) karke rakhte ho. Ismein tumhare liye kaafi nishani hai agar tum iman laney waley ho" },
    { number: 50, arabic: "وَمُصَدِّقًۭا لِّمَا بَيْنَ يَدَىَّ مِنَ ٱلتَّوْرَىٰةِ وَلِأُحِلَّ لَكُم بَعْضَ ٱلَّذِى حُرِّمَ عَلَيْكُمْ ۚ وَجِئْتُكُم بِـَٔايَةٍۢ مِّن رَّبِّكُمْ فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", transliteration: "Wamusaddiqan lima bayna yadayya mina alttawrati waliohilla lakum baAAda allathee hurrima AAalaykum wajitukum biayatin min rabbikum faittaqoo Allaha waateeAAooni", transliterationB: "Wa musaddiqal limaa baina yadaiya minat Tawraati wa liuhilla lakum ba'dal lazee hurrima 'alaikum; wa ji'tukum bi Aayatim mir Rabbikum fattaqul laaha wa atee'oon", english: "(I have come to you), to attest the Law which was before me. And to make lawful to you part of what was (Before) forbidden to you; I have come to you with a Sign from your Lord. So fear Allah, and obey me", romanUrdu: "Aur main us taleem o hidayat ki tasdeeq karne wala bankar aaya hoon jo Taurat mein se is waqt mere zamane mein maujood hai, aur isliye aaya hoon ke tumhare liye baaz un cheezon ko halal kardoon jo tumpar haraam kardi gayi hain. Dekho main tumhare Rubb ki taraf se tumhare paas nishani lekar aaya hoon , lihaza Allah se daro aur meri itaat karo" },
    { number: 51, arabic: "إِنَّ ٱللَّهَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۗ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ", transliteration: "Inna Allaha rabbee warabbukum faoAAbudoohu hatha siratun mustaqeemun", transliterationB: "Innal laaha Rabbee wa Rabbukum fa'budooh; haazaa Siraatum Mustaqeem", english: "It is Allah Who is my Lord and your Lord; then worship Him. This is a Way that is straight", romanUrdu: "Allah mera Rubb hai aur tumhara Rubb bhi, lihaza tum usi ki bandagi ikhtiyar karo, yahi seedha raasta hai" },
    { number: 52, arabic: "۞ فَلَمَّآ أَحَسَّ عِيسَىٰ مِنْهُمُ ٱلْكُفْرَ قَالَ مَنْ أَنصَارِىٓ إِلَى ٱللَّهِ ۖ قَالَ ٱلْحَوَارِيُّونَ نَحْنُ أَنصَارُ ٱللَّهِ ءَامَنَّا بِٱللَّهِ وَٱشْهَدْ بِأَنَّا مُسْلِمُونَ", transliteration: "Falamma ahassa AAeesa minhumu alkufra qala man ansaree ila Allahi qala alhawariyyoona nahnu ansaru Allahi amanna biAllahi waishhad bianna muslimoona", transliterationB: "Falammaaa ahassa 'Eesaa minhumul kufra qaala man ansaaree ilal laahi qaalal Hawaariyyoona nahnu ansaarul laahi aamannaa billaahi washhad bi annaa muslimoon", english: "When Jesus found Unbelief on their part He said: \"Who will be My helpers to (the work of) Allah?\" Said the disciples: \"We are Allah's helpers: We believe in Allah, and do thou bear witness that we are Muslims", romanUrdu: "Jab Isa ne mehsoos kiya ke bani Israel kufr o inkar par aamaada hain to usne kaha “kaun Allah ki raah mein mera madadgaar hota hai?” Hawariyon (desciples) ne jawab diya, “hum Allah ke madadgaar hain, hum Allah par iman laye, gawah raho ke hum muslim (Allah ke aagey sar itaat jhuka dene waley) hain" },
    { number: 53, arabic: "رَبَّنَآ ءَامَنَّا بِمَآ أَنزَلْتَ وَٱتَّبَعْنَا ٱلرَّسُولَ فَٱكْتُبْنَا مَعَ ٱلشَّٰهِدِينَ", transliteration: "Rabbana amanna bima anzalta waittabaAAna alrrasoola faoktubna maAAa alshshahideena", transliterationB: "Rabbanaaa aamannaa bimaaa anzalta wattaba'nar Rasoola faktubnaa ma'ash shaahideen", english: "Our Lord! we believe in what Thou hast revealed, and we follow the Messenger; then write us down among those who bear witness", romanUrdu: "Maalik! Jo farmaan tu nay nazil kiya hai humne usey maan liya aur Rasool ki pairwi qabool ki, hamara naam gawahi dene walon mein likh le”" },
    { number: 54, arabic: "وَمَكَرُوا۟ وَمَكَرَ ٱللَّهُ ۖ وَٱللَّهُ خَيْرُ ٱلْمَٰكِرِينَ", transliteration: "Wamakaroo wamakara Allahu waAllahu khayru almakireena", transliterationB: "Wa makaroo wa makaral laahu wallaahu khairul maakireen", english: "And (the unbelievers) plotted and planned, and Allah too planned, and the best of planners is Allah", romanUrdu: "Phir bani Israel ( Maseeh ke khilaf) khufiya tadbeerein karne lagey, jawab mein Allah ne bhi apni khufiya tadbeer ki aur aisi tadbeeron mein Allah sab se badh kar hai" },
    { number: 55, arabic: "إِذْ قَالَ ٱللَّهُ يَٰعِيسَىٰٓ إِنِّى مُتَوَفِّيكَ وَرَافِعُكَ إِلَىَّ وَمُطَهِّرُكَ مِنَ ٱلَّذِينَ كَفَرُوا۟ وَجَاعِلُ ٱلَّذِينَ ٱتَّبَعُوكَ فَوْقَ ٱلَّذِينَ كَفَرُوٓا۟ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ ۖ ثُمَّ إِلَىَّ مَرْجِعُكُمْ فَأَحْكُمُ بَيْنَكُمْ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ", transliteration: "Ith qala Allahu ya AAeesa innee mutawaffeeka warafiAAuka ilayya wamutahhiruka mina allatheena kafaroo wajaAAilu allatheena ittabaAAooka fawqa allatheena kafaroo ila yawmi alqiyamati thumma ilayya marjiAAukum faahkumu baynakum feema kuntum feehi takhtalifoona", transliterationB: "Iz qaalal laahu yaa 'Eesaaa innee mutawaffeeka wa raafi'uka ilaiya wa mutah hiruka minal lazeena kafaroo wa jaa'ilul lazeenattaba ooka fawqal lazeena kafarooo ilaa Yawmil Qiyaamati summa ilaiya marji'ukum fa ahkumu bainakum feemaa kuntum feehi takhtaliifoon", english: "Behold! Allah said: \"O Jesus! I will take thee and raise thee to Myself and clear thee (of the falsehoods) of those who blaspheme; I will make those who follow thee superior to those who reject faith, to the Day of Resurrection: Then shall ye all return unto me, and I will judge between you of the matters wherein ye dispute", romanUrdu: "(Woh Allah ki khufiya tadbeer hi thi) jab usne kaha, “ aey Isa! Ab main tujhey wapas le lunga aur tujhko apni taraf utha lunga aur jinhon ne tera inkar kiya unse (yani inki maiyat se aur unke gandey maahol mein unke saath rehne se) tujhey paak kardunga aur teri pairwi karne walon ko qayamat tak un logon par balaadast rakhunga jinhon ne tera inkar kiya hai. Phir tum sabko aakhir mere paas aana hai, us waqt main un baaton ka faisla kardunga jinmein tumhare darmiyan ikhtilaf hua hai" },
    { number: 56, arabic: "فَأَمَّا ٱلَّذِينَ كَفَرُوا۟ فَأُعَذِّبُهُمْ عَذَابًۭا شَدِيدًۭا فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَمَا لَهُم مِّن نَّٰصِرِينَ", transliteration: "Faamma allatheena kafaroo faoAAaththibuhum AAathaban shadeedan fee alddunya waalakhirati wama lahum min nasireena", transliterationB: "Fa ammal lazeena kafaroo fa u'az zibuhum 'azaaban shadeedan fiddunyaa wal Aakhirati wa maa lahum min naasireen", english: "As to those who reject faith, I will punish them with terrible agony in this world and in the Hereafter, nor will they have anyone to help", romanUrdu: "Jin logon ne kufr o inkar ki rawish ikhtiyar ki hai unhein duniya aur aakhirat dono mein sakht saza dunga aur woh koi madadgaar na payenge" },
    { number: 57, arabic: "وَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَيُوَفِّيهِمْ أُجُورَهُمْ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّٰلِمِينَ", transliteration: "Waamma allatheena amanoo waAAamiloo alssalihati fayuwaffeehim ojoorahum waAllahu la yuhibbu alththalimeena", transliterationB: "Wa ammal lazeena aamanoo wa 'amilus saalihaati fa yuwaffeehim ujoorahum; wallaahu laa yuhibbuz zaalimeen", english: "As to those who believe and work righteousness, Allah will pay them (in full) their reward; but Allah loveth not those who do wrong", romanUrdu: "Aur jinhon ne iman aur neik amal ka rawayya ikhtiyar kiya hai unhein unke ajar poorey poorey de diye jayenge, aur khoob jaan le ke zalimon se Allah hargiz muhabbat nahin karta”" },
    { number: 58, arabic: "ذَٰلِكَ نَتْلُوهُ عَلَيْكَ مِنَ ٱلْءَايَٰتِ وَٱلذِّكْرِ ٱلْحَكِيمِ", transliteration: "Thalika natloohu AAalayka mina alayati waalththikri alhakeemi", transliterationB: "Zaalika natloohu 'alaika minal Aayaati wa Zikril Hakeem", english: "This is what we rehearse unto thee of the Signs and the Message of Wisdom", romanUrdu: "Yeh ayaat aur hikmat se labrez tazkeere hain jo hum tumhein suna rahey hain" },
    { number: 59, arabic: "إِنَّ مَثَلَ عِيسَىٰ عِندَ ٱللَّهِ كَمَثَلِ ءَادَمَ ۖ خَلَقَهُۥ مِن تُرَابٍۢ ثُمَّ قَالَ لَهُۥ كُن فَيَكُونُ", transliteration: "Inna mathala AAeesa AAinda Allahi kamathali adama khalaqahu min turabin thumma qala lahu kun fayakoonu", transliterationB: "Inna masala 'Eesaa 'indal laahi kamasali Aadama khalaqahoo min turaabin summa qaala lahoo kun fayakoon", english: "The similitude of Jesus before Allah is as that of Adam; He created him from dust, then said to him: \"Be\". And he was", romanUrdu: "Allah ke nazdeek Isa ki misaal Adam ki si hai ke Allah ne usey mitti se paida kiya aur hukum diya ke hoja aur woh hogaya" },
    { number: 60, arabic: "ٱلْحَقُّ مِن رَّبِّكَ فَلَا تَكُن مِّنَ ٱلْمُمْتَرِينَ", transliteration: "Alhaqqu min rabbika fala takun mina almumtareena", transliterationB: "Alhaqqu mir Rabbika falaa takum minal mumtareen", english: "The Truth (comes) from Allah alone; so be not of those who doubt", romanUrdu: "Yeh asal haqeeqat hai jo tumhare Rubb ki tarf se batayi jaa rahi hai aur tum un logon mein shamil na ho jo ismein shakk karte hain" },
    { number: 61, arabic: "فَمَنْ حَآجَّكَ فِيهِ مِنۢ بَعْدِ مَا جَآءَكَ مِنَ ٱلْعِلْمِ فَقُلْ تَعَالَوْا۟ نَدْعُ أَبْنَآءَنَا وَأَبْنَآءَكُمْ وَنِسَآءَنَا وَنِسَآءَكُمْ وَأَنفُسَنَا وَأَنفُسَكُمْ ثُمَّ نَبْتَهِلْ فَنَجْعَل لَّعْنَتَ ٱللَّهِ عَلَى ٱلْكَٰذِبِينَ", transliteration: "Faman hajjaka feehi min baAAdi ma jaaka mina alAAilmi faqul taAAalaw nadAAu abnaana waabnaakum wanisaana wanisaakum waanfusana waanfusakum thumma nabtahil fanajAAal laAAnata Allahi AAala alkathibeena", transliterationB: "Faman haaajjaka feehi mim ba'di maa jaaa'aka minal 'ilmi faqul ta'aalaw nad'u abnaaa'anaa wa abnaaa'akum wa nisaaa'anaa wa nisaaa'akum wa anfusanaa wa anfusakum summa nabtahil fanaj'al la'natal laahi 'alal kaazibeen", english: "If any one disputes in this matter with thee, now after (full) knowledge Hath come to thee, say: \"Come! let us gather together,- our sons and your sons, our women and your women, ourselves and yourselves: Then let us earnestly pray, and invoke the curse of Allah on those who lie", romanUrdu: "Yeh ilm aa janey ke baad ab koi us maamle mein tumse jhagda karey to (aey Muhammad)! Ussey kaho, “ aao hum aur tum khud bhi aa jayein aur apne apne baal bacchon ko bhi le aayein aur khuda se dua karein ke jo jhuta ho uspar khuda ki laanat ho”" },
    { number: 62, arabic: "إِنَّ هَٰذَا لَهُوَ ٱلْقَصَصُ ٱلْحَقُّ ۚ وَمَا مِنْ إِلَٰهٍ إِلَّا ٱللَّهُ ۚ وَإِنَّ ٱللَّهَ لَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Inna hatha lahuwa alqasasu alhaqqu wama min ilahin illa Allahu wainna Allaha lahuwa alAAazeezu alhakeemu", transliterationB: "Innaa haazaa lahuwal qasasul haqq; wa maa min ilaahin illal laah; wa innal laahaa la Huwal 'Azeezul Hakeem", english: "This is the true account: There is no god except Allah; and Allah-He is indeed the Exalted in Power, the Wise", romanUrdu: "Yeh bilkul saheeh waqiyaat hain, aur haqeeqat yeh hai ke Allah ke siwa koi khuda-wand nahin hai, aur woh Allah hi ki hasti hai jiski taaqat sabse baala aur jiski hikmat nizaam-e-aalam mein kaar farma hai" },
    { number: 63, arabic: "فَإِن تَوَلَّوْا۟ فَإِنَّ ٱللَّهَ عَلِيمٌۢ بِٱلْمُفْسِدِينَ", transliteration: "Fain tawallaw fainna Allaha AAaleemun bialmufsideena", transliterationB: "Fa in tawallaw fa innal laaha'aleemun bil mufsideen", english: "But if they turn back, Allah hath full knowledge of those who do mischief", romanUrdu: "Pas agar yeh log ( is shart par muqable mein aane se) mooh moadein to (unka mufsid hona saaf khul jayega) aur Allah to mufsidon ke haal se waqif hi hai" },
    { number: 64, arabic: "قُلْ يَٰٓأَهْلَ ٱلْكِتَٰبِ تَعَالَوْا۟ إِلَىٰ كَلِمَةٍۢ سَوَآءٍۭ بَيْنَنَا وَبَيْنَكُمْ أَلَّا نَعْبُدَ إِلَّا ٱللَّهَ وَلَا نُشْرِكَ بِهِۦ شَيْـًۭٔا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًۭا مِّن دُونِ ٱللَّهِ ۚ فَإِن تَوَلَّوْا۟ فَقُولُوا۟ ٱشْهَدُوا۟ بِأَنَّا مُسْلِمُونَ", transliteration: "Qul ya ahla alkitabi taAAalaw ila kalimatin sawain baynana wabaynakum alla naAAbuda illa Allaha wala nushrika bihi shayan wala yattakhitha baAAduna baAAdan arbaban min dooni Allahi fain tawallaw faqooloo ishhadoo bianna muslimoona", transliterationB: "Qul yaa Ahlal Kitaabi ta'aalaw ilaa Kalimatin sawaaa'im bainanaa wa bainakum allaa na'buda illal laaha wa laa nushrika bihee shai'anw wa laa yattakhiza ba'dunaa ba'dan arbaabam min doonil laah; fa in tawallaw faqoolush hadoo bi annaa muslimoon", english: "Say: \"O People of the Book! come to common terms as between us and you: That we worship none but Allah; that we associate no partners with him; that we erect not, from among ourselves, Lords and patrons other than Allah.\" If then they turn back, say ye: \"Bear witness that we (at least) are Muslims (bowing to Allah's Will)", romanUrdu: "Kaho, “aey ehle kitab! Aao ek aisi baat ki taraf jo hamare aur tumhare darmiyan yaksaan hai , yeh ke hum Allah ke siwa kisi ki bandagi na karein, uske saath kisi ko shareek na thehrayein , aur hum mein se koi Allah ke siwa kisi ko apna Rubb na bana ley”. Is dawat ko qabool karne se agar woh mooh moadein to saaf kehdo ke gawah raho, hum to Muslim (sirf khuda ki bandagi o itaat karne waley) hain" },
    { number: 65, arabic: "يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تُحَآجُّونَ فِىٓ إِبْرَٰهِيمَ وَمَآ أُنزِلَتِ ٱلتَّوْرَىٰةُ وَٱلْإِنجِيلُ إِلَّا مِنۢ بَعْدِهِۦٓ ۚ أَفَلَا تَعْقِلُونَ", transliteration: "Ya ahla alkitabi lima tuhajjoona fee ibraheema wama onzilati alttawratu waalinjeelu illa min baAAdihi afala taAAqiloona", transliterationB: "Yaaa Ahlal Kitaabi limaa tuhaaajjoona feee Ibraaheema wa maaa unzilatit Tawraatu wal Injeelu illaa mim ba'dih; afala ta'qiloon", english: "Ye People of the Book! Why dispute ye about Abraham, when the Law and the Gospel Were not revealed Till after him? Have ye no understanding", romanUrdu: "Aey ehle kitab! Tum Ibrahim ke barey mein humse kyun jhagda karte ho? Taurat aur Injil to Ibrahim ke baad hi nazil hui hai, phir kya tum itni baat bhi nahin samajhte" },
    { number: 66, arabic: "هَٰٓأَنتُمْ هَٰٓؤُلَآءِ حَٰجَجْتُمْ فِيمَا لَكُم بِهِۦ عِلْمٌۭ فَلِمَ تُحَآجُّونَ فِيمَا لَيْسَ لَكُم بِهِۦ عِلْمٌۭ ۚ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", transliteration: "Haantum haolai hajajtum feema lakum bihi AAilmun falima tuhajjoona feema laysa lakum bihi AAilmun waAllahu yaAAlamu waantum la taAAlamoona", transliterationB: "Haaa antum haaa'ulaaa'i baajajtum feemaa lakum bihee 'ilmun falima tuhaaajjoonaa feemaa laisa lakum bihee 'ilm; wallaahu ya'lamu wa antum laa ta'lamoon", english: "Ah! Ye are those who fell to disputing (Even) in matters of which ye had some knowledge! but why dispute ye in matters of which ye have no knowledge? It is Allah Who knows, and ye who know not", romanUrdu: "Tum log jin cheezon kai ilm rakhte ho unmein to khoob behasein (arguments) kar chuke, ab un maamlaat mein kyun behas karne chale ho jinka tumhare paas kuch bhi ilm nahin .Allah jaanta hai , tum nahin jaantey" },
    { number: 67, arabic: "مَا كَانَ إِبْرَٰهِيمُ يَهُودِيًّۭا وَلَا نَصْرَانِيًّۭا وَلَٰكِن كَانَ حَنِيفًۭا مُّسْلِمًۭا وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Ma kana ibraheemu yahoodiyyan wala nasraniyyan walakin kana haneefan musliman wama kana mina almushrikeena", transliterationB: "Maa kaana Ibraaheemu Yahoodiyyanw wa laa Nasraa niyyanw wa laakin kaana Haneefam Muslimanw wa maa kaana minal mushrikeen", english: "Abraham was not a Jew nor yet a Christian; but he was true in Faith, and bowed his will to Allah's (Which is Islam), and he joined not gods with Allah", romanUrdu: "Ibrahim na yahudi tha na isayi , balke woh ek Muslim, yaksu tha aur woh hargiz Mushirkon mein se na tha" },
    { number: 68, arabic: "إِنَّ أَوْلَى ٱلنَّاسِ بِإِبْرَٰهِيمَ لَلَّذِينَ ٱتَّبَعُوهُ وَهَٰذَا ٱلنَّبِىُّ وَٱلَّذِينَ ءَامَنُوا۟ ۗ وَٱللَّهُ وَلِىُّ ٱلْمُؤْمِنِينَ", transliteration: "Inna awla alnnasi biibraheema lallatheena ittabaAAoohu wahatha alnnabiyyu waallatheena amanoo waAllahu waliyyu almumineena", transliterationB: "Innaa awlan naasi bi Ibraaheema lallazeenat taba 'oohu wa haazan nabiyyu wallazeena aamanoo; wallaahu waliyyul mu'mineen", english: "Without doubt, among men, the nearest of kin to Abraham, are those who follow him, as are also this Prophet and those who believe: And Allah is the Protector of those who have faith", romanUrdu: "Ibrahim se nisbat rakhne ka sabse zyada haqq agar kisi ko pahunchta hai to un logon ko pahunchta hai jinhon ne uski pairwi ki aur ab yeh Nabi aur uske maanne waley is nisbat ke zyada haqqdar hain. Allah sirf unhi ka haami o madadgaar hai jo iman rakhte hon" },
    { number: 69, arabic: "وَدَّت طَّآئِفَةٌۭ مِّنْ أَهْلِ ٱلْكِتَٰبِ لَوْ يُضِلُّونَكُمْ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمْ وَمَا يَشْعُرُونَ", transliteration: "Waddat taifatun min ahli alkitabi law yudilloonakum wama yudilloona illa anfusahum wama yashAAuroona", transliterationB: "Waddat taaa'ifatum min Ahlil Kitaabi law yudil loonakum wa maa yudilloona illaaa anfusahum wa maa yash'uroon", english: "It is the wish of a section of the People of the Book to lead you astray. But they shall lead astray (Not you), but themselves, and they do not perceive", romanUrdu: "(Aey Iman laney walon) ehle kitab mein se ek giroh chahta hai ke kisi tarah tumhein raah e raast se hata de, halaanke dar haqeeqat woh apne siwa kisi ko gumraahi mein nahin daal rahey hain magar unhein iska shaoor nahin hai" },
    { number: 70, arabic: "يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَأَنتُمْ تَشْهَدُونَ", transliteration: "Ya ahla alkitabi lima takfuroona biayati Allahi waantum tashhadoona", transliterationB: "Yaaa Ahlal Kitaabi lima takfuroona bi Aayaatil laahi wan antum tashadoon", english: "Ye People of the Book! Why reject ye the Signs of Allah, of which ye are (Yourselves) witnesses", romanUrdu: "Aey ehle kitab! Kyun Allah ki ayaat ka inkar karte ho halaanke tum khud inka mushahida kar rahey ho" },
    { number: 71, arabic: "يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَلْبِسُونَ ٱلْحَقَّ بِٱلْبَٰطِلِ وَتَكْتُمُونَ ٱلْحَقَّ وَأَنتُمْ تَعْلَمُونَ", transliteration: "Ya ahla alkitabi lima talbisoona alhaqqa bialbatili wataktumoona alhaqqa waantum taAAlamoona", transliterationB: "Yaaa Ahalal Kitaabi lima talbisoonal haqqa bilbaatili wa taktumoonal haqqa wa antum ta'lamoon", english: "Ye People of the Book! Why do ye clothe Truth with falsehood, and conceal the Truth, while ye have knowledge", romanUrdu: "Aey ehle kitab! Kyun haqq ko baatil ka rang chadha kar mushtaba (confound ) banate ho? Kyun jaante boojhte haqq ko jhutlate ho" },
    { number: 72, arabic: "وَقَالَت طَّآئِفَةٌۭ مِّنْ أَهْلِ ٱلْكِتَٰبِ ءَامِنُوا۟ بِٱلَّذِىٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَجْهَ ٱلنَّهَارِ وَٱكْفُرُوٓا۟ ءَاخِرَهُۥ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Waqalat taifatun min ahli alkitabi aminoo biallathee onzila AAala allatheena amanoo wajha alnnahari waokfuroo akhirahu laAAallahum yarjiAAoona", transliterationB: "Wa qaalat taaa'ifatum min Ahlil Kitaabi aaminoo billazeee unzila 'alal lazeena aamanoo wajhan nahaari wakfurooo aakhirahoo la'alla hum yarji'oon", english: "A section of the People of the Book say: \"Believe in the morning what is revealed to the believers, but reject it at the end of the day; perchance they may (themselves) Turn back", romanUrdu: "Ehle kitab mein se ek giroh kehta hai ke is Nabi ke maanne walon par jo kuch nazil hua hai uspar subah iman lao aur sham ko issey inkar kardo, shayad is tarkeeb se yeh log apne iman se phir jayein" },
    { number: 73, arabic: "وَلَا تُؤْمِنُوٓا۟ إِلَّا لِمَن تَبِعَ دِينَكُمْ قُلْ إِنَّ ٱلْهُدَىٰ هُدَى ٱللَّهِ أَن يُؤْتَىٰٓ أَحَدٌۭ مِّثْلَ مَآ أُوتِيتُمْ أَوْ يُحَآجُّوكُمْ عِندَ رَبِّكُمْ ۗ قُلْ إِنَّ ٱلْفَضْلَ بِيَدِ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", transliteration: "Wala tuminoo illa liman tabiAAa deenakum qul inna alhuda huda Allahi an yuta ahadun mithla ma ooteetum aw yuhajjookum AAinda rabbikum qul inna alfadla biyadi Allahi yuteehi man yashao waAllahu wasiAAun AAaleemun", transliterationB: "Wa laa tu'minooo illaa liman tabi'a deenakum qul innal hudaa hudal laahi ai yu'taaa ahadum misla maaa ooteetum aw yuhaaajjookum 'inda Rabbikum, qul innal fadla biyadil laah; yu'teehi mai yashaaa'; wallaahu Waasi'un 'Aleem", english: "And believe no one unless he follows your religion.\" Say: \"True guidance is the Guidance of Allah: (Fear ye) Lest a revelation be sent to someone (else) Like unto that which was sent unto you? or that those (Receiving such revelation) should engage you in argument before your Lord?\" Say: \"All bounties are in the hand of Allah: He granteth them to whom He pleaseth: And Allah careth for all, and He knoweth all things", romanUrdu: "Neiz yeh log aapas mein kehte hain ke apne mazhab waley ke siwa kisi ki baat na maano. Aey Nabi! Insey kehdo ke, “asal mein hidayat to Allah ki hidayat hai aur yeh usi ki dain hai ke kisi ko wahi kuch de diya jaye jo kabhi tumko diya gaya tha, ya yeh ke dusron ko tumhare Rubb ke huzoor pesh karne ke liye tumhare khilaf koi hujjat mil jaye. “(Aey Nabi)! Inse kaho ke, “ fazal o sharf Allah ke ikhtiyar mein hai, jisey chahe ata farmaye. Woh waseeh ul nazar hai aur sab kuch jaanta hai" },
    { number: 74, arabic: "يَخْتَصُّ بِرَحْمَتِهِۦ مَن يَشَآءُ ۗ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ", transliteration: "Yakhtassu birahmatihi man yashao waAllahu thoo alfadli alAAatheemi", transliterationB: "Yakhtassu birahmatihee mai yashaaa'; wallaahu zulfadil 'azeem", english: "For His Mercy He specially chooseth whom He pleaseth; for Allah is the Lord of bounties unbounded", romanUrdu: "Apni rehmat ke liye jisko chahta hai makhsoos karleta hai aur uska fazal bahut bada hai.”" },
    { number: 75, arabic: "۞ وَمِنْ أَهْلِ ٱلْكِتَٰبِ مَنْ إِن تَأْمَنْهُ بِقِنطَارٍۢ يُؤَدِّهِۦٓ إِلَيْكَ وَمِنْهُم مَّنْ إِن تَأْمَنْهُ بِدِينَارٍۢ لَّا يُؤَدِّهِۦٓ إِلَيْكَ إِلَّا مَا دُمْتَ عَلَيْهِ قَآئِمًۭا ۗ ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لَيْسَ عَلَيْنَا فِى ٱلْأُمِّيِّۦنَ سَبِيلٌۭ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُمْ يَعْلَمُونَ", transliteration: "Wamin ahli alkitabi man in tamanhu biqintarin yuaddihi ilayka waminhum man in tamanhu bideenarin la yuaddihi ilayka illa ma dumta AAalayhi qaiman thalika biannahum qaloo laysa AAalayna fee alommiyyeena sabeelun wayaqooloona AAala Allahi alkathiba wahum yaAAlamoona", transliterationB: "Wa min Ahlil Kitaabi man in taamanhu biqintaariny yu'addihee ilaika wa minhum man in taamanhu bideenaaril laa yu'addiheee ilaika illaa maa dumta 'alaihi qaaa' imaa; zaalika biannahum qaaloo laisa 'alainaa fil ummiyyeena sabeelunw wa yaqooloona 'alal laahil kaziba wa hum ya'lamoon", english: "Among the People of the Book are some who, if entrusted with a hoard of gold, will (readily) pay it back; others, who, if entrusted with a single silver coin, will not repay it unless thou constantly stoodest demanding, because, they say, \"there is no call on us (to keep faith) with these ignorant (Pagans).\" but they tell a lie against Allah, and (well) they know it", romanUrdu: "Ehle kitab mein koi to aisa hai ke agar tum uske aitamaad(bharose) par maal o daulat ka ek dhair bhi dedo to woh tumhara maal tumhein ada kardega, aur kisi ka haal yeh hai ke agar tum ek dinar ke maamle mein bhi uspar bharosa karo to woh ada na karega, illa yeh ke tum uske sar par sawar ho jao, unki is akhlaqi haalat ka sabab yeh hai ke woh kehte hain, “ummiyon (gair yahudi logon) ke maamle mein humpar koi mwazkhza (blame) nahin hai” aur yeh baat woh mehaz jhoot ghadh kar Allah ki taraf mansoob karte hai, halaanke unhein maloom hai ke Allah ne aisi koi baat nahin farmayi hai.( Aakhir kyun unse baaz purs na hogi)" },
    { number: 76, arabic: "بَلَىٰ مَنْ أَوْفَىٰ بِعَهْدِهِۦ وَٱتَّقَىٰ فَإِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَّقِينَ", transliteration: "Bala man awfa biAAahdihi waittaqa fainna Allaha yuhibbu almuttaqeena", transliterationB: "Balaa man awfaa bi'ahdihee wattaqaa fainnal laaha yuhibbul muttaqeen", english: "Nay.- Those that keep their plighted faith and act aright,-verily Allah loves those who act aright", romanUrdu: "Jo bhi apne ahad ko poora karega aur burayi se bachkar rahega woh Allah ka mehboob banega, kyunke parheizgaar log Allah ko pasand hain" },
    { number: 77, arabic: "إِنَّ ٱلَّذِينَ يَشْتَرُونَ بِعَهْدِ ٱللَّهِ وَأَيْمَٰنِهِمْ ثَمَنًۭا قَلِيلًا أُو۟لَٰٓئِكَ لَا خَلَٰقَ لَهُمْ فِى ٱلْءَاخِرَةِ وَلَا يُكَلِّمُهُمُ ٱللَّهُ وَلَا يَنظُرُ إِلَيْهِمْ يَوْمَ ٱلْقِيَٰمَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Inna allatheena yashtaroona biAAahdi Allahi waaymanihim thamanan qaleelan olaika la khalaqa lahum fee alakhirati wala yukallimuhumu Allahu wala yanthuru ilayhim yawma alqiyamati wala yuzakkeehim walahum AAathabun aleemun", transliterationB: "Innal lazeena yashtaroona bi'ahdil laahi wa aymaanihim samanan qaleelan ulaaa'ika laa khalaaqa lahum fil Aakhirati wa laa yukallimuhumul laahu wa laa yanzuru ilaihim Yawmal Qiyaamati wa laa yuzakkeehim wa lahum 'azabun 'aleem", english: "As for those who sell the faith they owe to Allah and their own plighted word for a small price, they shall have no portion in the Hereafter: Nor will Allah (Deign to) speak to them or look at them on the Day of Judgment, nor will He cleans them (of sin): They shall have a grievous penalty", romanUrdu: "Rahey woh log jo Allah ke ahad aur apne kasamo ko thodi keemat par bech daalte hain, to unke liye aakhirat mein koi hissa nahin, Allah qayamat ke roz na unse baat karega na unki taraf dekhega aur na unhein paak karega, balke unke liye to sakht dardnaak saza hai" },
    { number: 78, arabic: "وَإِنَّ مِنْهُمْ لَفَرِيقًۭا يَلْوُۥنَ أَلْسِنَتَهُم بِٱلْكِتَٰبِ لِتَحْسَبُوهُ مِنَ ٱلْكِتَٰبِ وَمَا هُوَ مِنَ ٱلْكِتَٰبِ وَيَقُولُونَ هُوَ مِنْ عِندِ ٱللَّهِ وَمَا هُوَ مِنْ عِندِ ٱللَّهِ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُمْ يَعْلَمُونَ", transliteration: "Wainna minhum lafareeqan yalwoona alsinatahum bialkitabi litahsaboohu mina alkitabi wama huwa mina alkitabi wayaqooloona huwa min AAindi Allahi wama huwa min AAindi Allahi wayaqooloona AAala Allahi alkathiba wahum yaAAlamoona", transliterationB: "Wa inna minhum lafaree qany yalwoona alsinatahum bil Kitaabi litahsaboohu minal Kitaab, wa maa huwa minal Kitaabi wa yaqooloon huwa min 'indillaahi wa maa huwa min 'indillaahi wa yaqooloona 'alal laahil kaziba wa hum ya'lamoon", english: "There is among them a section who distort the Book with their tongues: (As they read) you would think it is a part of the Book, but it is no part of the Book; and they say, \"That is from Allah,\" but it is not from Allah: It is they who tell a lie against Allah, and (well) they know it", romanUrdu: "Unmein kuch log aise hain jo kitab padhte huey is tarah zubaan ka ulat pher karte hain ke tum samjho jo kuch woh padh rahey hain woh kitab hi ki ibarat hai, halaanke woh kitab ki ibarat nahin hoti. Woh kehte hain ke yeh jo kuch hum padh rahey hain yeh khuda ki taraf se hai, halaanke woh khuda ki taraf se nahin hota. Woh jaan boojh kar jhoot baat Allah ki taraf mansoob kardete hain" },
    { number: 79, arabic: "مَا كَانَ لِبَشَرٍ أَن يُؤْتِيَهُ ٱللَّهُ ٱلْكِتَٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ ثُمَّ يَقُولَ لِلنَّاسِ كُونُوا۟ عِبَادًۭا لِّى مِن دُونِ ٱللَّهِ وَلَٰكِن كُونُوا۟ رَبَّٰنِيِّۦنَ بِمَا كُنتُمْ تُعَلِّمُونَ ٱلْكِتَٰبَ وَبِمَا كُنتُمْ تَدْرُسُونَ", transliteration: "Ma kana libasharin an yutiyahu Allahu alkitaba waalhukma waalnnubuwwata thumma yaqoola lilnnasi koonoo AAibadan lee min dooni Allahi walakin koonoo rabbaniyyeena bima kuntum tuAAallimoona alkitaba wabima kuntum tadrusoona", transliterationB: "Maa kaana libasharin ai yu'tiyahul laahul Kitaaba walhukma wan Nubuwwata summa yaqoola linnaasi koonoo 'ibaadal lee min doonil laahi wa laakin koonoo rabbaaniy yeena bimaa kuntum tu'allimoonal Kitaaba wa bimaa kuntum tadrusoon", english: "It is not (possible) that a man, to whom is given the Book, and Wisdom, and the prophetic office, should say to people: \"Be ye my worshippers rather than Allah's\": on the contrary (He would say) \"Be ye worshippers of Him Who is truly the Cherisher of all: For ye have taught the Book and ye have studied it earnestly", romanUrdu: "Kisi Insaan ka yeh kaam nahin hai ke Allah to usko kitab aur hukum aur nabuwat ata farmaye aur woh logon se kahey ke Allah ke bajaye tum mere banday ban jao. Woh to yahi kahega ke sacchey Rabbani bano jaisa ke is kitab ki taleem ka taqaza hai jisey tum padhte aur padhate ho" },
    { number: 80, arabic: "وَلَا يَأْمُرَكُمْ أَن تَتَّخِذُوا۟ ٱلْمَلَٰٓئِكَةَ وَٱلنَّبِيِّۦنَ أَرْبَابًا ۗ أَيَأْمُرُكُم بِٱلْكُفْرِ بَعْدَ إِذْ أَنتُم مُّسْلِمُونَ", transliteration: "Wala yamurakum an tattakhithoo almalaikata waalnnabiyyeena arbaban ayamurukum bialkufri baAAda ith antum muslimoona", transliterationB: "Wa laa yaamurakum an tattakhizul malaaa 'ikata wan Nabiyyeena arbaabaa; a yaamurukum bilkufri ba'da iz antum muslimoon", english: "Nor would he instruct you to take angels and prophets for Lords and patrons. What! would he bid you to unbelief after ye have bowed your will (To Allah in Islam)", romanUrdu: "Woh tumse hargiz yeh na kahega ke Farishton ko ya paigambaron ko apna Rubb bana lo, kya yeh mumkin hai ke ek Nabi tumhein kufr ka hukum de jab ke tum Muslim ho" },
    { number: 81, arabic: "وَإِذْ أَخَذَ ٱللَّهُ مِيثَٰقَ ٱلنَّبِيِّۦنَ لَمَآ ءَاتَيْتُكُم مِّن كِتَٰبٍۢ وَحِكْمَةٍۢ ثُمَّ جَآءَكُمْ رَسُولٌۭ مُّصَدِّقٌۭ لِّمَا مَعَكُمْ لَتُؤْمِنُنَّ بِهِۦ وَلَتَنصُرُنَّهُۥ ۚ قَالَ ءَأَقْرَرْتُمْ وَأَخَذْتُمْ عَلَىٰ ذَٰلِكُمْ إِصْرِى ۖ قَالُوٓا۟ أَقْرَرْنَا ۚ قَالَ فَٱشْهَدُوا۟ وَأَنَا۠ مَعَكُم مِّنَ ٱلشَّٰهِدِينَ", transliteration: "Waith akhatha Allahu meethaqa alnnabiyyeena lama ataytukum min kitabin wahikmatin thumma jaakum rasoolun musaddiqun lima maAAakum latuminunna bihi walatansurunnahu qala aaqrartum waakhathtum AAala thalikum isree qaloo aqrarna qala faishhadoo waana maAAakum mina alshshahideena", transliterationB: "Wa iz akhazal laahu meesaaqan Nabiyyeena lamaaa aataitukum min Kitaabinw wa Hikmatin summa jaaa'akum Rasoolum musaddiqul limaa ma'akum latu'minunna bihee wa latansurunnah; qaala 'aaqrartum wa akhaztum alaa zaalikum isree qaalooo aqrarnaa; qaala fashhadoo wa ana ma'akum minash shaahideen", english: "Behold! Allah took the covenant of the prophets, saying: \"I give you a Book and Wisdom; then comes to you a messenger, confirming what is with you; do ye believe in him and render him help.\" Allah said: \"Do ye agree, and take this my Covenant as binding on you?\" They said: \"We agree.\" He said: \"Then bear witness, and I am with you among the witnesses", romanUrdu: "Yaad karo , Allah ne paigambaron se ahad liya tha ke, “aaj humne tumhein kitab aur hikmat o Danish se Nawaza hai, kal agar koi doosra Rasool tumhare paas usi taleem ki tasdeeq karta hua aaye jo pehle se tumhare paas maujood hai, to tumko uspar iman lana hoga aur uski madad karni hogi”. Yeh irshad farma kar Allah be pucha, “kya tum iska iqrar karte ho aur ispar meri taraf se ahad ki bhari zimmedari uthate ho?” Unhon ne kaha haan hum iqrar karte hain, Allah ne farmaya, “accha to gawah raho aur main bhi tumhare saath gawaah hoon" },
    { number: 82, arabic: "فَمَن تَوَلَّىٰ بَعْدَ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ", transliteration: "Faman tawalla baAAda thalika faolaika humu alfasiqoona", transliterationB: "Faman tawallaa ba'da zaalika fa ulaaa'ika humul faasiqoon", english: "If any turn back after this, they are perverted transgressors", romanUrdu: "Iske baad jo apne ahad se phir jaye wahi faasiq hai”" },
    { number: 83, arabic: "أَفَغَيْرَ دِينِ ٱللَّهِ يَبْغُونَ وَلَهُۥٓ أَسْلَمَ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ طَوْعًۭا وَكَرْهًۭا وَإِلَيْهِ يُرْجَعُونَ", transliteration: "Afaghayra deeni Allahi yabghoona walahu aslama man fee alssamawati waalardi tawAAan wakarhan wailayhi yurjaAAoona", transliterationB: "Afaghaira deenil laahi yabghoona wa lahooo aslama man fis samaawaati wal ardi taw'anw wa karhanw wa ilaihi yurja'oon", english: "Do they seek for other than the Religion of Allah?-while all creatures in the heavens and on earth have, willing or unwilling, bowed to His Will (Accepted Islam), and to Him shall they all be brought back", romanUrdu: "Ab kya yeh log Allah ki itaat ka tareeqa (deen Allah) chodh kar koi aur tareeqa chahte hain? Halaanke asmaan o zameen ki saari cheezein char o nachaar (willingly or un willingly) Allah hi ki taabeh farmaan (Muslim) hain aur usi ki taraf sabko palatna hai" },
    { number: 84, arabic: "قُلْ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ عَلَيْنَا وَمَآ أُنزِلَ عَلَىٰٓ إِبْرَٰهِيمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَمَآ أُوتِىَ مُوسَىٰ وَعِيسَىٰ وَٱلنَّبِيُّونَ مِن رَّبِّهِمْ لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّنْهُمْ وَنَحْنُ لَهُۥ مُسْلِمُونَ", transliteration: "Qul amanna biAllahi wama onzila AAalayna wama onzila AAala ibraheema waismaAAeela waishaqa wayaAAqooba waalasbati wama ootiya moosa waAAeesa waalnnabiyyoona min rabbihim la nufarriqu bayna ahadin minhum wanahnu lahu muslimoona", transliterationB: "Qul aamannaa billaahi wa maaa unzila 'alainaa wa maaa unzila 'alaaa Ibraaheema wa Ismaa'eela wa Ishaaqa wa Ya'qooba wal Asbaati wa maaa ootiya Moosaa wa 'Eesaa wan Nabiyyoona mir Rabbihim laa nufarriqu baina ahadim minhum wa nahnu lahoo muslimoon", english: "Say: \"We believe in Allah, and in what has been revealed to us and what was revealed to Abraham, Isma'il, Isaac, Jacob, and the Tribes, and in (the Books) given to Moses, Jesus, and the prophets, from their Lord: We make no distinction between one and another among them, and to Allah do we bow our will (in Islam)", romanUrdu: "(Aey Nabi)! Kaho ke “ hum Allah ko maante hain, us taleem ko maante hain jo humpar nazil ki gayi hai, un taleemat ko bhi maante hain jo Ibrahim, Ismael, Ishaq, Yaqub aur aulad e Yaqub par nazil hui thi aur un hidayaat par bhi iman rakhte hain jo Moosa aur Isa aur dusre paigambaron ko unke Rubb ki taraf se di gayi. Hum inke darmiyan farq nahin karte aur hum Allah ke taabey farmaan (Muslim) hain”" },
    { number: 85, arabic: "وَمَن يَبْتَغِ غَيْرَ ٱلْإِسْلَٰمِ دِينًۭا فَلَن يُقْبَلَ مِنْهُ وَهُوَ فِى ٱلْءَاخِرَةِ مِنَ ٱلْخَٰسِرِينَ", transliteration: "Waman yabtaghi ghayra alislami deenan falan yuqbala minhu wahuwa fee alakhirati mina alkhasireena", transliterationB: "Wa mai yabtaghi ghairal Islaami deenan falany yuqbala minhu wa huwa fil Aakhirati minal khaasireen", english: "If anyone desires a religion other than Islam (submission to Allah), never will it be accepted of him; and in the Hereafter He will be in the ranks of those who have lost (All spiritual good)", romanUrdu: "Is farmabardari (Islam) ke siwa jo shaks koi aur tareeqa ikhtiyar karna chahe uska woh tareeqa hargiz qabool na kiya jayega aur aakhirat mein woh nakaam o na-murad rahega" },
    { number: 86, arabic: "كَيْفَ يَهْدِى ٱللَّهُ قَوْمًۭا كَفَرُوا۟ بَعْدَ إِيمَٰنِهِمْ وَشَهِدُوٓا۟ أَنَّ ٱلرَّسُولَ حَقٌّۭ وَجَآءَهُمُ ٱلْبَيِّنَٰتُ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ", transliteration: "Kayfa yahdee Allahu qawman kafaroo baAAda eemanihim washahidoo anna alrrasoola haqqun wajaahumu albayyinatu waAllahu la yahdee alqawma alththalimeena", transliterationB: "Kaifa yahdil laahu qawman kafaroo ba'da eemaanihim wa shahidooo annar Rasoola haqqunw wa jaaa'ahumul baiyinaat; wallaahu laa yahdil qawmaz zaalimeen", english: "How shall Allah Guide those who reject Faith after they accepted it and bore witness that the Messenger was true and that Clear Signs had come unto them? but Allah guides not a people unjust", romanUrdu: "Kaise ho sakta hai ke Allah un logon o hidayat bakshe jinhon ne niyamat e iman paa lene ke baad phir kufr ikhtiyar kiya halaanke woh khud is baat par gawahi de chuke hain ke yeh Rasool haqq par hai aur inke paas roshan nishaniyan bhi aa chuki hain, Allah zalimon ko to hidayat nahin diya karta" },
    { number: 87, arabic: "أُو۟لَٰٓئِكَ جَزَآؤُهُمْ أَنَّ عَلَيْهِمْ لَعْنَةَ ٱللَّهِ وَٱلْمَلَٰٓئِكَةِ وَٱلنَّاسِ أَجْمَعِينَ", transliteration: "Olaika jazaohum anna AAalayhim laAAnata Allahi waalmalaikati waalnnasi ajmaAAeena", transliterationB: "Ulaaa'ika jazaaa'uhum anna 'alaihim la'natal laahi walmalaaa'ikati wannaasi ajma'een", english: "Of such the reward is that on them (rests) the curse of Allah, of His angels, and of all mankind", romanUrdu: "Unke zulm ka saheeh badla yahi hai ke unpar Allah aur Farishton aur tamaam Insaano ki phitkar hai" },
    { number: 88, arabic: "خَٰلِدِينَ فِيهَا لَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنظَرُونَ", transliteration: "Khalideena feeha la yukhaffafu AAanhumu alAAathabu wala hum yuntharoona", transliterationB: "Khaalideena feehaa laa yukhaffafu 'anhumul 'azaabu wa laa hum yunzaroon", english: "In that will they dwell; nor will their penalty be lightened, nor respite be (their lot)", romanUrdu: "Isi halat mein woh hamesha rahenge, na unki saza mein takhfif(kami) hogi aur na unhein mohlat di jayegi" },
    { number: 89, arabic: "إِلَّا ٱلَّذِينَ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ", transliteration: "Illa allatheena taboo min baAAdi thalika waaslahoo fainna Allaha ghafoorun raheemun", transliterationB: "Illal lazeena taaboo mim ba'di zaalika wa aslahoo fa innal laaha Ghafoorur Raheem", english: "Except for those that repent (Even) after that, and make amends; for verily Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Albatta woh log bach jayenge jo iske baad tawba karke apne tarz e amal ki islah karlein, Allah bakhsne wala aur reham farmane wala hai" },
    { number: 90, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ بَعْدَ إِيمَٰنِهِمْ ثُمَّ ٱزْدَادُوا۟ كُفْرًۭا لَّن تُقْبَلَ تَوْبَتُهُمْ وَأُو۟لَٰٓئِكَ هُمُ ٱلضَّآلُّونَ", transliteration: "Inna allatheena kafaroo baAAda eemanihim thumma izdadoo kufran lan tuqbala tawbatuhum waolaika humu alddalloona", transliterationB: "Innal lazeena kafaroo ba'da eemaanihim summaz daadoo kufral lan tuqbala tawbatuhum wa ulaaa'ika humud daaalloon", english: "But those who reject Faith after they accepted it, and then go on adding to their defiance of Faith,- never will their repentance be accepted; for they are those who have (of set purpose) gone astray", romanUrdu: "Magar jin logon ne iman laney ke baad kufr ikhtiyar kiya phir apne kufr mein badhte chale gaye unki tawba bhi qabool na hogi, aisey log to pakke gumraah hain" },
    { number: 91, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَمَاتُوا۟ وَهُمْ كُفَّارٌۭ فَلَن يُقْبَلَ مِنْ أَحَدِهِم مِّلْءُ ٱلْأَرْضِ ذَهَبًۭا وَلَوِ ٱفْتَدَىٰ بِهِۦٓ ۗ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ وَمَا لَهُم مِّن نَّٰصِرِينَ", transliteration: "Inna allatheena kafaroo wamatoo wahum kuffarun falan yuqbala min ahadihim milo alardi thahaban walawi iftada bihi olaika lahum AAathabun aleemun wama lahum min nasireena", transliterationB: "Innal lazeena kafaroo wa maatoo wa hum kuffaarun falany yuqbala min ahadihim mil'ul ardi zahabanw wa lawiftadaa bih; ulaaa 'ika lahum 'azaabun aleemunw wa maa lahum min naasireen", english: "As to those who reject Faith, and die rejecting,- never would be accepted from any such as much gold as the earth contains, though they should offer it for ransom. For such is (in store) a penalty grievous, and they will find no helpers", romanUrdu: "Yaqeen rakkho, jin logon ne kufr ikhtiyar kiya aur kufr hi ki haalat mein jaan di unmein se koi agar apne aap ko saza se bachane ke liye rooh-e-zameen bhar kar bhi sona(gold) fidye (expiation) mein de to usey qabool na kiya jayege, aisey logon ke liye dardnaak saza tayyar hai aur woh apna koi madadgaar na payenge" },
    { number: 92, arabic: "لَن تَنَالُوا۟ ٱلْبِرَّ حَتَّىٰ تُنفِقُوا۟ مِمَّا تُحِبُّونَ ۚ وَمَا تُنفِقُوا۟ مِن شَىْءٍۢ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌۭ", transliteration: "Lan tanaloo albirra hatta tunfiqoo mimma tuhibboona wama tunfiqoo min shayin fainna Allaha bihi AAaleemun", transliterationB: "Lan tanaalul birra hattaa tunfiqoo mimmaa tuhibboon; wa maa tunfiqoo min shai'in fa innal laaha bihee 'Aleem", english: "By no means shall ye attain righteousness unless ye give (freely) of that which ye love; and whatever ye give, of a truth Allah knoweth it well", romanUrdu: "Tum neki ko nahin pahunch sakte jab tak ke apni woh cheezein (khuda ki raah mein) kharch na karo jinhein tum azeez rakthe to, aur jo kuch tum kharch karoge Allah ussey be khabar na hoga" },
    { number: 93, arabic: "۞ كُلُّ ٱلطَّعَامِ كَانَ حِلًّۭا لِّبَنِىٓ إِسْرَٰٓءِيلَ إِلَّا مَا حَرَّمَ إِسْرَٰٓءِيلُ عَلَىٰ نَفْسِهِۦ مِن قَبْلِ أَن تُنَزَّلَ ٱلتَّوْرَىٰةُ ۗ قُلْ فَأْتُوا۟ بِٱلتَّوْرَىٰةِ فَٱتْلُوهَآ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Kullu alttaAAami kana hillan libanee israeela illa ma harrama israeelu AAala nafsihi min qabli an tunazzala alttawratu qul fatoo bialttawrati faotlooha in kuntum sadiqeena", transliterationB: "Kullut ta'aami kaana hillal li Baneee Israaa'eela illaa maa harrama Israaa'eelu 'alaa nafsihee min qabli an tunzzalat Tawraah; qul faatoo bit Tawraati fatloohaaa in kuntum saadiqeen", english: "All food was lawful to the Children of Israel, except what Israel Made unlawful for itself, before the Law (of Moses) was revealed. Say: \"Bring ye the Law and study it, if ye be men of truth", romanUrdu: "Khane ki yeh saari cheezein (jo shariyat e Muhammadi mein halal hain) bani Israel ke liye bhi halal thi, albatta baaz chezein aisi thi jinhein Tourat ke nazil kiye janey se pehle Israel (Yakub) ne khud apne upar haraam karliya tha. Unsey kaho, agar tum (apne aitraaz mein) sacchey ho to lao Taurat aur pesh karo uski koi ibarat" },
    { number: 94, arabic: "فَمَنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ ٱلْكَذِبَ مِنۢ بَعْدِ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ", transliteration: "Famani iftara AAala Allahi alkathiba min baAAdi thalika faolaika humu althalimoona", transliterationB: "Famanif taraa 'alal laahilkaziba mim ba'di zaalika fa ulaaa'ika humuz zaalimoon", english: "If any, after this, invent a lie and attribute it to Allah, they are indeed unjust wrong-doers", romanUrdu: "Iske baad bhi jo log apni jhooti ghadi hui baatein Allah ki taraf mansoob karte rahein wahi dar-haqeeqat zalim hain" },
    { number: 95, arabic: "قُلْ صَدَقَ ٱللَّهُ ۗ فَٱتَّبِعُوا۟ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًۭا وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Qul sadaqa Allahu faittabiAAoo millata ibraheema haneefan wama kana mina almushrikeena", transliterationB: "Qul sadaqal laah; fattabi'oo Millata Ibraaheema Haneefanw wa maa kaana minal mush rikeen", english: "Say: \"Allah speaketh the Truth: follow the religion of Abraham, the sane in faith; he was not of the Pagans", romanUrdu: "Kaho, Allah ne jo kuch farmaya hai sach farmaya hai. Tumko yaksu hokar Ibrahim ke tareeqe ki pairwi karni chahiye, aur Ibrahim shirk karne walon mein se na tha" },
    { number: 96, arabic: "إِنَّ أَوَّلَ بَيْتٍۢ وُضِعَ لِلنَّاسِ لَلَّذِى بِبَكَّةَ مُبَارَكًۭا وَهُدًۭى لِّلْعَٰلَمِينَ", transliteration: "Inna awwala baytin wudiAAa lilnnasi lallathee bibakkata mubarakan wahudan lilAAalameena", transliterationB: "Inna awwala Baitinw wudi'a linnaasi lallazee bi Bakkata mubaarakanw wa hudal lil 'aalameen", english: "The first House (of worship) appointed for men was that at Bakka: Full of blessing and of guidance for all kinds of beings", romanUrdu: "Beshak sabse pehli ibadat-gaah jo Insaano ke liye tameer hui woh wahi hai jo Makkah mein waqeh hai, usko khair o barakat di gayi thi aur tamaam jahaan walon ke liye markaz e hidayat banaya gaya tha" },
    { number: 97, arabic: "فِيهِ ءَايَٰتٌۢ بَيِّنَٰتٌۭ مَّقَامُ إِبْرَٰهِيمَ ۖ وَمَن دَخَلَهُۥ كَانَ ءَامِنًۭا ۗ وَلِلَّهِ عَلَى ٱلنَّاسِ حِجُّ ٱلْبَيْتِ مَنِ ٱسْتَطَاعَ إِلَيْهِ سَبِيلًۭا ۚ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِىٌّ عَنِ ٱلْعَٰلَمِينَ", transliteration: "Feehi ayatun bayyinatun maqamu ibraheema waman dakhalahu kana aminan walillahi AAala alnnasi hijju albayti mani istataAAa ilayhi sabeelan waman kafara fainna Allaha ghaniyyun AAani alAAalameena", transliterationB: "Feehi Aayaatum baiyinaatum Maqaamu Ibraaheema wa man dakhalahoo kaana aaminaa; wa lillaahi 'alan naasi Hijjul Baiti manis tataa'a ilaihi sabeelaa; wa man kafara fa innal laaha ghaniyyun 'anil 'aalameen", english: "In it are Signs Manifest; (for example), the Station of Abraham; whoever enters it attains security; Pilgrimage thereto is a duty men owe to Allah,- those who can afford the journey; but if any deny faith, Allah stands not in need of any of His creatures", romanUrdu: "Ismein khuli hui nishaniyan hain, Ibrahim ka muqaam e ibadat hai, aur iska haal yeh hai ke jo ismein dakhil hua mamoon(secure) ho gaya. Logon par Allah ka yeh haqq hai ke jo is ghar tak pahuchne ki istitaat rakhta ho woh iska hajj karey, aur jo koi is hukum ki pairwi se inkar karey to usey maloom ho jana chahiye ke Allah tamaam duniya walon se be-niyaz hai" },
    { number: 98, arabic: "قُلْ يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَٱللَّهُ شَهِيدٌ عَلَىٰ مَا تَعْمَلُونَ", transliteration: "Qul ya ahla alkitabi lima takfuroona biayati Allahi waAllahu shaheedun AAala ma taAAmaloona", transliterationB: "Qul yaaa Ahlal Kitaabi lima takfuroona bi Aayaatillaahi wallaahu shaheedun 'alaa maa ta'maloon", english: "Say: \"O People of the Book! Why reject ye the Signs of Allah, when Allah is Himself witness to all ye do", romanUrdu: "Kaho, aey ehle kitab! Tum kyun Allah ki baatein maanne se inkar karte ho? Jo harkatein tum kar rahey ho Allah sab kuch dekh raha hai" },
    { number: 99, arabic: "قُلْ يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنْ ءَامَنَ تَبْغُونَهَا عِوَجًۭا وَأَنتُمْ شُهَدَآءُ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Qul ya ahla alkitabi lima tasuddoona AAan sabeeli Allahi man amana tabghoonaha AAiwajan waantum shuhadao wama Allahu bighafilin AAamma taAAmaloona", transliterationB: "Qul yaaa Ahlal Kitaabi lima tusuddoona 'an sabeelil laahi man aamana tabghoonahaa 'iwajanw wa antum shuhadaaa'; wa mallaahu bighaafilin 'ammaa ta'maloon", english: "Say: \"O ye People of the Book! Why obstruct ye those who believe, from the path of Allah, Seeking to make it crooked, while ye were yourselves witnesses (to Allah's Covenant)? but Allah is not unmindful of all that ye do", romanUrdu: "Kaho, aey ehle kitab! yeh tumhari kya rawish hai ke jo Allah ki baat maanta hai usey bhi tum Allah ke raaste se rokte ho aur chahte ho ke woh tedhi raah chale, halaanke tum khud (iske raah e raast honay par) gawah ho. Tumhari harkaton se Allah gaafil nahin hai" },
    { number: 100, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًۭا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ يَرُدُّوكُم بَعْدَ إِيمَٰنِكُمْ كَٰفِرِينَ", transliteration: "Ya ayyuha allatheena amanoo in tuteeAAoo fareeqan mina allatheena ootoo alkitaba yaruddookum baAAda eemanikum kafireena", transliterationB: "Yaaa ayyuhal lazeena aamanoo in tutee'oo fareeqam minal lazeena ootul Kitaaba yaruddookum ba'da eemaanikum kaafireen", english: "O ye who believe! If ye listen to a faction among the People of the Book, they would (indeed) render you apostates after ye have believed", romanUrdu: "Aey logon jo iman laye ho, agar tumne in ehle kitab mein se ek giroh ki baat maani to yeh tumhein iman se phir kufr ki taraf pher le jayenge" },
    { number: 101, arabic: "وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلَىٰ عَلَيْكُمْ ءَايَٰتُ ٱللَّهِ وَفِيكُمْ رَسُولُهُۥ ۗ وَمَن يَعْتَصِم بِٱللَّهِ فَقَدْ هُدِىَ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Wakayfa takfuroona waantum tutla AAalaykum ayatu Allahi wafeekum rasooluhu waman yaAAtasim biAllahi faqad hudiya ila siratin mustaqeemin", transliterationB: "Wa kaifa takfuroona wa antum tutlaa 'alaikum Aayaatul laahi wa feekum Rasooluh; wa mai ya'tasim baillaahi faqad hudiya ilaa Siraatim Mustaqeem", english: "And how would ye deny Faith while unto you are rehearsed the Signs of Allah, and among you Lives the Messenger? Whoever holds firmly to Allah will be shown a way that is straight", romanUrdu: "Tumhare liye kufr ki taraf janey ka ab kya mauqa baki hai jabke tumko Allah ki aayat sunayi jaa rahi hain aur tumhare darmiyan uska Rasool maujood hai? Jo Allah ka daaman mazbooti ke saath thaamega woh zaroor raah e raast payega" },
    { number: 102, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ حَقَّ تُقَاتِهِۦ وَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسْلِمُونَ", transliteration: "Ya ayyuha allatheena amanoo ittaqoo Allaha haqqa tuqatihi wala tamootunna illa waantum muslimoona", transliterationB: "Yaaa ayyuhal lazeena aamanut taqul laaha haqqa tuqaatihee wa laa tamoontunna illaa wa antum muslimoon", english: "O ye who believe! Fear Allah as He should be feared, and die not except in a state of Islam", romanUrdu: "Aey logon jo iman laye ho, Allah se daro jaisa ke ussey darne ka haqq hai, tumko maut na aaye magar is haal mein ke tum Muslim ho" },
    { number: 103, arabic: "وَٱعْتَصِمُوا۟ بِحَبْلِ ٱللَّهِ جَمِيعًۭا وَلَا تَفَرَّقُوا۟ ۚ وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ كُنتُمْ أَعْدَآءًۭ فَأَلَّفَ بَيْنَ قُلُوبِكُمْ فَأَصْبَحْتُم بِنِعْمَتِهِۦٓ إِخْوَٰنًۭا وَكُنتُمْ عَلَىٰ شَفَا حُفْرَةٍۢ مِّنَ ٱلنَّارِ فَأَنقَذَكُم مِّنْهَا ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَٰتِهِۦ لَعَلَّكُمْ تَهْتَدُونَ", transliteration: "WaiAAtasimoo bihabli Allahi jameeAAan wala tafarraqoo waothkuroo niAAmata Allahi AAalaykum ith kuntum aAAdaan faallafa bayna quloobikum faasbahtum biniAAmatihi ikhwanan wakuntum AAala shafa hufratin mina alnnari faanqathakum minha kathalika yubayyinu Allahu lakum ayatihi laAAallakum tahtadoona", transliterationB: "Wa'tasimoo bi Hablil laahi jamee'anw wa laa tafarraqoo; wazkuroo ni'matal laahi alaikum iz kuntum a'daaa'an fa allafa baina quloobikum fa asbah tum bini'matiheee ikhwaananw wa kuntum 'alaa shafaa hufratim minan Naari fa anqazakum minhaa; kazaalika yubaiyinul laahu lakum aayaatihee la'allakum tahtadoon", english: "And hold fast, all together, by the rope which Allah (stretches out for you), and be not divided among yourselves; and remember with gratitude Allah's favour on you; for ye were enemies and He joined your hearts in love, so that by His Grace, ye became brethren; and ye were on the brink of the pit of Fire, and He saved you from it. Thus doth Allah make His Signs clear to you: That ye may be guided", romanUrdu: "Sab milkar Allah ki rassi ko mazboot pakad lo aur tafraqe (divide) mein na pado. Allah ke us ehsan ko yaad rakkho jo usne tumpar kiya hai, tum ek dusre ke dusman thay, usne tumhare dil joad diye aur uske fazal o karam se tum bhai bhai ban gaye. Tum aag se bhare huey ek gadhe (pit) ke kinare khade thay, Allah ne tumko ussey bacha liya, is tarah Allah apni nishaniyan tumhare saamne roshan karta hai shayad ke in alamaton se tumhein apni falaah ka seedha raasta nazar aa jaye" },
    { number: 104, arabic: "وَلْتَكُن مِّنكُمْ أُمَّةٌۭ يَدْعُونَ إِلَى ٱلْخَيْرِ وَيَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ ۚ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Waltakun minkum ommatun yadAAoona ila alkhayri wayamuroona bialmaAAroofi wayanhawna AAani almunkari waolaika humu almuflihoona", transliterationB: "Waltakum minkum ummatuny yad'oona ilal khairi wa yaamuroona bilma 'roofi wa yanhawna 'anil munkar; wa ulaaa'ika humul muflihoon", english: "Let there arise out of you a band of people inviting to all that is good, enjoining what is right, and forbidding what is wrong: They are the ones to attain felicity", romanUrdu: "Tum mein kuch log to aisey zaroor hi rehne chahiye jo neki ki taraf bulayein, bhalayi ka hukum dein, aur burayion se roakte rahein, jo log yeh kaam karenge wahi falaah payenge" },
    { number: 105, arabic: "وَلَا تَكُونُوا۟ كَٱلَّذِينَ تَفَرَّقُوا۟ وَٱخْتَلَفُوا۟ مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْبَيِّنَٰتُ ۚ وَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ عَظِيمٌۭ", transliteration: "Wala takoonoo kaallatheena tafarraqoo waikhtalafoo min baAAdi ma jaahumu albayyinatu waolaika lahum AAathabun AAatheemun", transliterationB: "Wa laa takoonoo kallazeena tafarraqoo wakhtalafoo mim ba'di maa jaaa'ahumul baiyinaat; wa ulaaa'ika lahum 'azaabun 'azeem", english: "Be not like those who are divided amongst themselves and fall into disputations after receiving Clear Signs: For them is a dreadful penalty", romanUrdu: "Kahin tum un logon ki tarah na ho jana jo firqon mein batt gaye aur khuli khuli wazeh hidayaat paney ke baad phir ikhtilafaat mein mubtila huey. Jinhon ne yeh rawish ikhtiyar ki woh us roz sakht saza payenge" },
    { number: 106, arabic: "يَوْمَ تَبْيَضُّ وُجُوهٌۭ وَتَسْوَدُّ وُجُوهٌۭ ۚ فَأَمَّا ٱلَّذِينَ ٱسْوَدَّتْ وُجُوهُهُمْ أَكَفَرْتُم بَعْدَ إِيمَٰنِكُمْ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ", transliteration: "Yawma tabyaddu wujoohun wataswaddu wujoohun faamma allatheena iswaddat wujoohuhum akafartum baAAda eemanikum fathooqoo alAAathaba bima kuntum takfuroona", transliterationB: "Yawma tabyaddu wujoohunw wa taswaddu wujooh; faammal lazeenas waddat wujoohum akafartum ba'da eemaanikum fazooqul 'azaaba bimaa kuntum takfuroon", english: "On the Day when some faces will be (lit up with) white, and some faces will be (in the gloom of) black: To those whose faces will be black, (will be said): \"Did ye reject Faith after accepting it? Taste then the penalty for rejecting Faith", romanUrdu: "Jabke kuch log surkhru (bright) hongey aur kuch ka mooh kala hoga, jinka mooh kala hoga (unse kaha jayega ke) niyamat e iman paney ke baad bhi tumne kaafirana rawayya ikhtiyar kiya? Accha to ab is kufraan e niyamat ke siley mein azaab ka maza chakkho" },
    { number: 107, arabic: "وَأَمَّا ٱلَّذِينَ ٱبْيَضَّتْ وُجُوهُهُمْ فَفِى رَحْمَةِ ٱللَّهِ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Waamma allatheena ibyaddat wujoohuhum fafee rahmati Allahi hum feeha khalidoona", transliterationB: "Wa ammal lazeenabyadd at wujoohuhum fafee rahmatil laahi hum feehaa khaalidoon", english: "But those whose faces will be (lit with) white,- they will be in (the light of) Allah's mercy: therein to dwell (for ever)", romanUrdu: "Rahey woh log jinke chehre roshan hongay to unko Allah ke daaman e rehmat mein jagah milegi aur hamesha woh isi haalat mein rahenge" },
    { number: 108, arabic: "تِلْكَ ءَايَٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۗ وَمَا ٱللَّهُ يُرِيدُ ظُلْمًۭا لِّلْعَٰلَمِينَ", transliteration: "Tilka ayatu Allahi natlooha AAalayka bialhaqqi wama Allahu yureedu thulman lilAAalameena", transliterationB: "Tilka Aayaatul laahi natloohaa 'alaika bilhaqq; wa mal laahu yureedu zulmallil 'aalameen", english: "These are the Signs of Allah: We rehearse them to thee in Truth: And Allah means no injustice to any of His creatures", romanUrdu: "Yeh Allah ke irshadaat hain jo hum tumhein theek theek suna rahey hain kyunke Allah duniya walon par zulm karne ka koi irada nahin rakhta" },
    { number: 109, arabic: "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ", transliteration: "Walillahi ma fee alssamawati wama fee alardi waila Allahi turjaAAu alomooru", transliterationB: "Wa lillaahi maa fissamaawaati wa maa fil ard; wa ilal laahi turja;ul umoor", english: "To Allah belongs all that is in the heavens and on earth: To Him do all questions go back (for decision)", romanUrdu: "Zameen o asmaan ki sari cheezon ka maalik Allah hai aur sarey maamlaat Allah hi ke huzoor pesh hotey hain" },
    { number: 110, arabic: "كُنتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ تَأْمُرُونَ بِٱلْمَعْرُوفِ وَتَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَتُؤْمِنُونَ بِٱللَّهِ ۗ وَلَوْ ءَامَنَ أَهْلُ ٱلْكِتَٰبِ لَكَانَ خَيْرًۭا لَّهُم ۚ مِّنْهُمُ ٱلْمُؤْمِنُونَ وَأَكْثَرُهُمُ ٱلْفَٰسِقُونَ", transliteration: "Kuntum khayra ommatin okhrijat lilnnasi tamuroona bialmaAAroofi watanhawna AAani almunkari watuminoona biAllahi walaw amana ahlu alkitabi lakana khayran lahum minhumu almuminoona waaktharuhumu alfasiqoona", transliterationB: "Kuntum khaira ummatin ukhrijat linnaasi taamuroona bilma'roofi wa tanhawna 'anil munkari wa tu'minoona billaah; wa law aamana Ahlul Kitaabi lakaana khairal lahum minhumul mu'minoona wa aksaruhumul faasiqoon", english: "Ye are the best of peoples, evolved for mankind, enjoining what is right, forbidding what is wrong, and believing in Allah. If only the People of the Book had faith, it were best for them: among them are some who have faith, but most of them are perverted transgressors", romanUrdu: "Ab duniya mein woh behtareen giroh tum ho jisey Insano ki hidayat o Islah ke liye maidan mein laya gaya hai, tum neki ka hukum dete ho, badi (burayi) se roakte ho aur Allah par iman rakhte ho. Yeh ehle kitab iman latey to inhi ke haqq mein behtar tha, agarchey inmein kuch log imandaar bhi paye jatey hain magar inke beshtar (aksar) afraad nafarmaan hain" },
    { number: 111, arabic: "لَن يَضُرُّوكُمْ إِلَّآ أَذًۭى ۖ وَإِن يُقَٰتِلُوكُمْ يُوَلُّوكُمُ ٱلْأَدْبَارَ ثُمَّ لَا يُنصَرُونَ", transliteration: "Lan yadurrookum illa athan wain yuqatilookum yuwallookumu aladbara thumma la yunsaroona", transliterationB: "Lai yadurrookum 'illaaa azanw wa ai yuqaatilookum yuwallookumul adbaara summa laa yunsaroon", english: "They will do you no harm, barring a trifling annoyance; if they come out to fight you, they will show you their backs, and no help shall they get", romanUrdu: "Yeh tumhara kuch bigaad nahin sakte, zyada se zyada bas kuch sataa sakte hain, agar yeh tumse ladenge to muqable mein peet dikhayenge, phir aisey bebas honge ke kahin se inko madad na milegi" },
    { number: 112, arabic: "ضُرِبَتْ عَلَيْهِمُ ٱلذِّلَّةُ أَيْنَ مَا ثُقِفُوٓا۟ إِلَّا بِحَبْلٍۢ مِّنَ ٱللَّهِ وَحَبْلٍۢ مِّنَ ٱلنَّاسِ وَبَآءُو بِغَضَبٍۢ مِّنَ ٱللَّهِ وَضُرِبَتْ عَلَيْهِمُ ٱلْمَسْكَنَةُ ۚ ذَٰلِكَ بِأَنَّهُمْ كَانُوا۟ يَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّۢ ۚ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ", transliteration: "Duribat AAalayhimu alththillatu ayna ma thuqifoo illa bihablin mina Allahi wahablin mina alnnasi wabaoo bighadabin mina Allahi waduribat AAalayhimu almaskanatu thalika biannahum kanoo yakfuroona biayati Allahi wayaqtuloona alanbiyaa bighayri haqqin thalika bima AAasaw wakanoo yaAAtadoona", transliterationB: "Duribat 'alaihimuz zillatu aina maa suqifooo illaa bihablim minal laahi wa hablim minan naasi wa baaa'oo bighadabim minallaahi wa duribat 'alaihimul maskanah; zaalika bi-annahum kaanoo yakfuroona bi Aayaatil laahi wa yaqtuloonal Ambiyaaa'a bighairi haqq; zaalika bimaa 'asaw wa kaanoo ya'tadoon", english: "Shame is pitched over them (Like a tent) wherever they are found, except when under a covenant (of protection) from Allah and from men; they draw on themselves wrath from Allah, and pitched over them is (the tent of) destitution. This because they rejected the Signs of Allah, and slew the prophets in defiance of right; this because they rebelled and transgressed beyond bounds", romanUrdu: "Yeh jahan bhi paye gaye inpar zillat ki maar hi padi, kahin Allah ke zimme ya Insaano ke zimme mein panaah mil gayi to yeh aur baat hai, yeh Allah ke gazab mein ghir chuke hain, inpar mohtaji o magloobi musallat kardi gayi hai (Allah's wrath, and humiliation is stuck upon them), aur yeh sabkuch sirf is wajah se hua hai ke yeh Allah ki aayat se kufr karte rahey aur inhon ne paigambaron ko na-haqq qatal kiya. Yeh inki nafarmaniyon aur zyadatiyon ka anjam hai" },
    { number: 113, arabic: "۞ لَيْسُوا۟ سَوَآءًۭ ۗ مِّنْ أَهْلِ ٱلْكِتَٰبِ أُمَّةٌۭ قَآئِمَةٌۭ يَتْلُونَ ءَايَٰتِ ٱللَّهِ ءَانَآءَ ٱلَّيْلِ وَهُمْ يَسْجُدُونَ", transliteration: "Laysoo sawaan min ahli alkitabi ommatun qaimatun yatloona ayati Allahi anaa allayli wahum yasjudoona", transliterationB: "Laisoo sawaaa'a; min Ahlil Kitaabi ummatun qaaa'imatuny yatloona Aayaatil laahi aanaaa'al laili wa hum yasjudoon", english: "Not all of them are alike: Of the People of the Book are a portion that stand (For the right): They rehearse the Signs of Allah all night long, and they prostrate themselves in adoration", romanUrdu: "Magar sarey ehle kitab yaksan nahin hain, inmein kuch log aisey bhi hain jo raah e raast par qayam hain, raaton ko Allah ki ayaat padhte hain aur uske aagey sajdarez hotey hain" },
    { number: 114, arabic: "يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَيَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَيُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَأُو۟لَٰٓئِكَ مِنَ ٱلصَّٰلِحِينَ", transliteration: "Yuminoona biAllahi waalyawmi alakhiri wayamuroona bialmaAAroofi wayanhawna AAani almunkari wayusariAAoona fee alkhayrati waolaika mina alssaliheena", transliterationB: "Yu'minoona billaahi wal Yawmil Aakhiri wa yaa muroona bilma'roofi wa yanhawna 'anil munkari wa yusaari'oona fil khairaati wa ulaa'ika minas saaliheen", english: "They believe in Allah and the Last Day; they enjoin what is right, and forbid what is wrong; and they hasten (in emulation) in (all) good works: They are in the ranks of the righteous", romanUrdu: "Allah aur roz e aakhirt par iman rakhte hain, neki ka hukum dete hain, buraiyon se roakte hain aur bhalayi ke kaamon mein sargarm rehte hain, yeh saleh log hain" },
    { number: 115, arabic: "وَمَا يَفْعَلُوا۟ مِنْ خَيْرٍۢ فَلَن يُكْفَرُوهُ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلْمُتَّقِينَ", transliteration: "Wama yafAAaloo min khayrin falan yukfaroohu waAllahu AAaleemun bialmuttaqeena", transliterationB: "Wa maa yaf'aloo min khairin falai yukfarooh; wallaahu 'aleemun bilmuttaqeen", english: "Of the good that they do, nothing will be rejected of them; for Allah knoweth well those that do right", romanUrdu: "Aur jo neki bhi yeh karenge uski na-qadari na ki jayegi, Allah parheizgaar logon ko khoob jaanta hai" },
    { number: 116, arabic: "إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَٰدُهُم مِّنَ ٱللَّهِ شَيْـًۭٔا ۖ وَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۚ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Inna allatheena kafaroo lan tughniya AAanhum amwaluhum wala awladuhum mina Allahi shayan waolaika ashabu alnnari hum feeha khalidoona", transliterationB: "Innal lazeena kafaroo lan tughniya 'anhum amwaalum wa laaa awlaaduhum minal laahi shai anw wa ulaaa'ika Ashaabun Naar; hum feehaa khaalidoon", english: "Those who reject Faith,- neither their possessions nor their (numerous) progeny will avail them aught against Allah: They will be companions of the Fire,-dwelling therein (for ever)", romanUrdu: "Rahey woh log jinhon ne kufr ka rawayya ikhtiyar kiya to Allah ke muqable mein unko na unka maal kuch kaam dega na aulad, woh to aag mein janey waley log hain aur aag hi mein hamesha rahenge" },
    { number: 117, arabic: "مَثَلُ مَا يُنفِقُونَ فِى هَٰذِهِ ٱلْحَيَوٰةِ ٱلدُّنْيَا كَمَثَلِ رِيحٍۢ فِيهَا صِرٌّ أَصَابَتْ حَرْثَ قَوْمٍۢ ظَلَمُوٓا۟ أَنفُسَهُمْ فَأَهْلَكَتْهُ ۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَٰكِنْ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "Mathalu ma yunfiqoona fee hathihi alhayati alddunya kamathali reehin feeha sirrun asabat hartha qawmin thalamoo anfusahum faahlakathu wama thalamahumu Allahu walakin anfusahum yathlimoona", transliterationB: "Masalu maa yunfiqoona fee haazihil hayaatid dunyaa kamasali reehin feehaa sirrun as aabat harsa qawmin zalamooo anfusahum fa ahlakath; wa maa zalamahumul laahu wa laakin anfusahum yazlimoon", english: "What they spend in the life of this (material) world May be likened to a wind which brings a nipping frost: It strikes and destroys the harvest of men who have wronged their own souls: it is not Allah that hath wronged them, but they wrong themselves", romanUrdu: "Jo kuch woh apni is duniya ki zindagi mein kharch kar rahey hain uski misaal us hawa ki si hai jismein pala ho (accompanied with frost) aur woh un logon ki kheti par chale jinhon ne apne upar aap zulm kiya hai aur usey barbaad karke rakhde, Allah ne inpar zulm nahin kiya, darhaqeeqat yeh khud apne upar zulm kar rahey hain" },
    { number: 118, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ بِطَانَةًۭ مِّن دُونِكُمْ لَا يَأْلُونَكُمْ خَبَالًۭا وَدُّوا۟ مَا عَنِتُّمْ قَدْ بَدَتِ ٱلْبَغْضَآءُ مِنْ أَفْوَٰهِهِمْ وَمَا تُخْفِى صُدُورُهُمْ أَكْبَرُ ۚ قَدْ بَيَّنَّا لَكُمُ ٱلْءَايَٰتِ ۖ إِن كُنتُمْ تَعْقِلُونَ", transliteration: "Ya ayyuha allatheena amanoo la tattakhithoo bitanatan min doonikum la yaloonakum khabalan waddoo ma AAanittum qad badati albaghdao min afwahihim wama tukhfee sudooruhum akbaru qad bayyanna lakumu alayati in kuntum taAAqiloona", transliterationB: "Yaaa ayyuhal lazeena aamanoo laa tattakhizoo bitaanatam min doonikum laa yaaloonakum khabaalanw waddoo maa 'anittum qad badatil baghdaaa'u min afwaahihim; wa maa tukhfee sudooruhum akbar; qad baiyannaa lakumul Aayaati in kuntum ta'qiloon", english: "O ye who believe! Take not into your intimacy those outside your ranks: They will not fail to corrupt you. They only desire your ruin: Rank hatred has already appeared from their mouths: What their hearts conceal is far worse. We have made plain to you the Signs, if ye have wisdom", romanUrdu: "Aey logon jo iman laye ho, apni jamaat ke logon ke siwa dusron ko apna raazdaar na banao, woh tumhari kharabi ke kisi mauqe se faiyda uthane mein nahin chukte, tumhein jis cheez se nuqsan pahunche wahi unko mehboob hai, unke dil ka bugz unke mooh se nikla padhta hai aur jo kuch woh apne seeno mein chupaye huey hain woh issey shadeed-tar hai. Humne tumhein saaf saaf hidayaat de di hain, agar tum aqal rakhte ho (to unsey taaluq rakhne mein ehtiyat bartoge)" },
    { number: 119, arabic: "هَٰٓأَنتُمْ أُو۟لَآءِ تُحِبُّونَهُمْ وَلَا يُحِبُّونَكُمْ وَتُؤْمِنُونَ بِٱلْكِتَٰبِ كُلِّهِۦ وَإِذَا لَقُوكُمْ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَوْا۟ عَضُّوا۟ عَلَيْكُمُ ٱلْأَنَامِلَ مِنَ ٱلْغَيْظِ ۚ قُلْ مُوتُوا۟ بِغَيْظِكُمْ ۗ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Haantum olai tuhibboonahum wala yuhibboonakum watuminoona bialkitabi kullihi waitha laqookum qaloo amanna waitha khalaw AAaddoo AAalaykumu alanamila mina alghaythi qul mootoo bighaythikum inna Allaha AAaleemun bithati alssudoori", transliterationB: "Haaa antum ulaaa'i tuhibboonahum wa laa yuhibboonakum wa tu'minoona bil kitaabi kullihee wa izaa laqookum qaalooo aamannaa wa izaa khalaw 'addoo 'alaikumul anaamila minal ghaiz; qul mootoo bighai zikum; innal laaha 'aleemum bizaatis sudoor", english: "Ah! ye are those who love them, but they love you not,- though ye believe in the whole of the Book. When they meet you, they say, \"We believe\": But when they are alone, they bite off the very tips of their fingers at you in their rage. Say: \"Perish in your rage; Allah knoweth well all the secrets of the heart", romanUrdu: "Tum unse muhabbat rakhte ho magar woh tumse muhabbat nahin rakhte, halaanke tum tamaam kutoob e asmaani ko maante ho. Jab woh tumse milte hain to kehte hain ke humne bhi (tumhare Rasool aur tumhari kitab ko) maan liya hai, magar jab juda hotey hain to tumhare khilaf unke gaiz o gazab ka yeh haal hota hai ke apni ungliyan chabane lagte hain. Unsey kehdo ke apne gussey mein aap jal maro, Allah dilon ke chupey huey raaz tak jaanta hai" },
    { number: 120, arabic: "إِن تَمْسَسْكُمْ حَسَنَةٌۭ تَسُؤْهُمْ وَإِن تُصِبْكُمْ سَيِّئَةٌۭ يَفْرَحُوا۟ بِهَا ۖ وَإِن تَصْبِرُوا۟ وَتَتَّقُوا۟ لَا يَضُرُّكُمْ كَيْدُهُمْ شَيْـًٔا ۗ إِنَّ ٱللَّهَ بِمَا يَعْمَلُونَ مُحِيطٌۭ", transliteration: "In tamsaskum hasanatun tasuhum wain tusibkum sayyiatun yafrahoo biha wain tasbiroo watattaqoo la yadurrukum kayduhum shayan inna Allaha bima yaAAmaloona muheetun", transliterationB: "In tamsaskum hasanatun tasu'hum wa in tusibkum saiyi'atuny yafrahoo bihaa wa in tasbiroo wa tattaqoo laa yad urrukum kaiduhum shai'aa; innal laaha bimaa ya'maloona muheet", english: "If aught that is good befalls you, it grieves them; but if some misfortune overtakes you, they rejoice at it. But if ye are constant and do right, not the least harm will their cunning do to you; for Allah Compasseth round about all that they do", romanUrdu: "Tumhara bhala hota hai to unko bura maloom hota hai, aur tumpar koi museebat aati hai to yeh khush hotey hain, magar inki koi tadbeer tumhare khilaf kaargar nahin ho sakti basharth yeh ke tum sabr se kaam lo aur Allah se darr kar kaam karte raho. Jo kuch yeh kar rahey hain Allah uspar haawi hai" },
    { number: 121, arabic: "وَإِذْ غَدَوْتَ مِنْ أَهْلِكَ تُبَوِّئُ ٱلْمُؤْمِنِينَ مَقَٰعِدَ لِلْقِتَالِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ", transliteration: "Waith ghadawta min ahlika tubawwio almumineena maqaAAida lilqitali waAllahu sameeAAun AAaleemun", transliterationB: "Wa iz ghadawta min ahlika tubawwi'ul mu'mineena maqaa'ida lilqitaal; wallaahu samee'un 'aleem", english: "Remember that morning Thou didst leave Thy household (early) to post the faithful at their stations for battle: And Allah heareth and knoweth all things", romanUrdu: "(Aey paigambar! Musalmano ke samne us mauqe ka zikr karo) jab tum subah sawere apne ghar se nikle thay aur ( Uhud ke maidan mein) musalmaano ko jung ke liye ja-baja mamoor (placed the believers in battle arrays) kar rahey thay , Allah saari baatein sunta hai aur woh nihayat bakhabar hai" },
    { number: 122, arabic: "إِذْ هَمَّت طَّآئِفَتَانِ مِنكُمْ أَن تَفْشَلَا وَٱللَّهُ وَلِيُّهُمَا ۗ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ", transliteration: "Ith hammat taifatani minkum an tafshala waAllahu waliyyuhuma waAAala Allahi falyatawakkali almuminoona", transliterationB: "Iz hammat taaa'ifataani minkum an tafshalaa wallaahu waliyyuhumaa; wa 'alal laahi falyatawakkalil mu'minoon", english: "Remember two of your parties Meditated cowardice; but Allah was their protector, and in Allah should the faithful (Ever) put their trust", romanUrdu: "Yaad karo jab tum mein se do giroh buzdili dikhane par aamaada ho gaye thay, halaanke Allah unki madad par maujood tha aur mominon ko Allah hi par bharosa rakhna chahiye" },
    { number: 123, arabic: "وَلَقَدْ نَصَرَكُمُ ٱللَّهُ بِبَدْرٍۢ وَأَنتُمْ أَذِلَّةٌۭ ۖ فَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Walaqad nasarakumu Allahu bibadrin waantum athillatun faittaqoo Allaha laAAallakum tashkuroona", transliterationB: "Wa laqad nasarakumul laahu bi-Badrinw wa antum azillatun fattaqul laaha la'allakum tashkuroon", english: "Allah had helped you at Badr, when ye were a contemptible little force; then fear Allah; thus May ye show your gratitude", romanUrdu: "Aakhir issey pehle jung e badr mein Allah tumhari madad kar chuka tha , halaanke us waqt tum bahut kamzoar thay, lihaza tumko chahiye ke Allah ki nashukri se bacho, umeed hai ke ab tum shukarguzar banoge" },
    { number: 124, arabic: "إِذْ تَقُولُ لِلْمُؤْمِنِينَ أَلَن يَكْفِيَكُمْ أَن يُمِدَّكُمْ رَبُّكُم بِثَلَٰثَةِ ءَالَٰفٍۢ مِّنَ ٱلْمَلَٰٓئِكَةِ مُنزَلِينَ", transliteration: "Ith taqoolu lilmumineena alan yakfiyakum an yumiddakum rabbukum bithalathati alafin mina almalaikati munzaleena", transliterationB: "Iz taqoolu lilmu'mineena alai yakfiyakum ai-yumiddakum Rabbukum bisalaasati aalaafim minal malaaa'ikati munzaleen", english: "Remember thou saidst to the Faithful: \"Is it not enough for you that Allah should help you with three thousand angels (Specially) sent down", romanUrdu: "Yaad karo jab tum momino se keh rahey thay, “ kya tumhare liye yeh baat kafi nahin ke Allah teen hazaar farishte utar kar tumhari madad karey?”" },
    { number: 125, arabic: "بَلَىٰٓ ۚ إِن تَصْبِرُوا۟ وَتَتَّقُوا۟ وَيَأْتُوكُم مِّن فَوْرِهِمْ هَٰذَا يُمْدِدْكُمْ رَبُّكُم بِخَمْسَةِ ءَالَٰفٍۢ مِّنَ ٱلْمَلَٰٓئِكَةِ مُسَوِّمِينَ", transliteration: "Bala in tasbiroo watattaqoo wayatookum min fawrihim hatha yumdidkum rabbukum bikhamsati alafin mina almalaikati musawwimeena", transliterationB: "Balaaa; in tasbiroo wa tattaqoo wa yaatookum min fawrihim haazaa yumdidkum Rabbukum bikhamsati aalaafim minal malaaa'ikati musawwaimeen", english: "Yea, - if ye remain firm, and act aright, even if the enemy should rush here on you in hot haste, your Lord would help you with five thousand angels Making a terrific onslaught", romanUrdu: "Beshak, Agar tum sabr karo aur khuda se darte huey kaam karo to jis aan dushman tumhare upar chadh kar aayenge usi aan tumhara Rubb (teen hazaar nahin) paanch hazaar saahib e nishan farishton se tumhari madad karega" },
    { number: 126, arabic: "وَمَا جَعَلَهُ ٱللَّهُ إِلَّا بُشْرَىٰ لَكُمْ وَلِتَطْمَئِنَّ قُلُوبُكُم بِهِۦ ۗ وَمَا ٱلنَّصْرُ إِلَّا مِنْ عِندِ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ", transliteration: "Wama jaAAalahu Allahu illa bushra lakum walitatmainna quloobukum bihi wama alnnasru illa min AAindi Allahi alAAazeezi alhakeemi", transliterationB: "Wa maa ja'alahul laahu illaa bushraa lakum wa litatma'inna quloobukum bih' wa man-nasru illaa min 'indilllaahil 'Azeezil Hakeem", english: "Allah made it but a message of hope for you, and an assurance to your hearts: (in any case) there is no help except from Allah. The Exalted, the Wise", romanUrdu: "Yeh baat Allah ne tumhein isliye bata di hai ke tum khush ho jao aur tumhare dil mutmaeen ho jayein, fatah o nusrat jo kuch bhi hai Allah ki taraf se hai jo badi quwwat wala aur dana o beena hai (the All-Mighty, the All-Wise)" },
    { number: 127, arabic: "لِيَقْطَعَ طَرَفًۭا مِّنَ ٱلَّذِينَ كَفَرُوٓا۟ أَوْ يَكْبِتَهُمْ فَيَنقَلِبُوا۟ خَآئِبِينَ", transliteration: "LiyaqtaAAa tarafan mina allatheena kafaroo aw yakbitahum fayanqaliboo khaibeena", transliterationB: "Laiyaqta'a tarafam minal lazeena kafarooo aw yakbitahum fayanqaliboo khaaa'ibeen", english: "That He might cut off a fringe of the Unbelievers or expose them to infamy, and they should then be turned back, frustrated of their purpose", romanUrdu: "(Aur yeh madad woh tumhein isliye dega) taa-ke kufr ki raah chalne waalon ka ek bazu kaat de, ya unko aisi zaleel shikast de ke woh na-muradi ke saath paspan ho jayein" },
    { number: 128, arabic: "لَيْسَ لَكَ مِنَ ٱلْأَمْرِ شَىْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَٰلِمُونَ", transliteration: "Laysa laka mina alamri shayon aw yatooba AAalayhim aw yuAAaththibahum fainnahum thalimoona", transliterationB: "Laisa laka minal amrishai'un aw yatooba 'alaihim aw yu'az zi bahum fa innahum zaalimoon", english: "Not for thee, (but for Allah), is the decision: Whether He turn in mercy to them, or punish them; for they are indeed wrong-doers", romanUrdu: "(Aey paigambar) faisle ke ikhtiyaraat mein tumhara koi hissa nahin, Allah ko ikhtiyar hai chahey unhein maaf karey chahey saza de, kyunke woh zalim hain" },
    { number: 129, arabic: "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ يَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Walillahi ma fee alssamawati wama fee alardi yaghfiru liman yashao wayuAAaththibu man yashao waAllahu ghafoorun raheemun", transliterationB: "Wa lilaahi maa fissamaawaati wa maa fil-ard; yaghfiru limai-yashaaa'u wa yu'azzibu mai-yashaaa'; wallaahu Ghafoorur Raheem", english: "To Allah belongeth all that is in the heavens and on earth. He forgiveth whom He pleaseth and punisheth whom He pleaseth; but Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Zameen aur asmaano mein jo kuch hai uska Maalik Allah hai, jisko chahe baksh de aur jisko chahe azaab de, woh maaf karne wala aur raheem hai" },
    { number: 130, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَأْكُلُوا۟ ٱلرِّبَوٰٓا۟ أَضْعَٰفًۭا مُّضَٰعَفَةًۭ ۖ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ", transliteration: "Ya ayyuha allatheena amanoo la takuloo alrriba adAAafan mudaAAafatan waittaqoo Allaha laAAallakum tuflihoona", transliterationB: "Yaaa ayyuhal lazeena aamanoo la taakuhur ribaaa ad'aafam mudaa'afatanw wattaqul laaha la'allakum tuflihoon", english: "O ye who believe! Devour not usury, doubled and multiplied; but fear Allah; that ye may (really) prosper", romanUrdu: "Aey logon jo iman laye ho , yeh badhta aur chadhta sood (usury) khana chodh do aur Allah se daro, umeed hai ke falaah paogey" },
    { number: 131, arabic: "وَٱتَّقُوا۟ ٱلنَّارَ ٱلَّتِىٓ أُعِدَّتْ لِلْكَٰفِرِينَ", transliteration: "Waittaqoo alnnara allatee oAAiddat lilkafireena", transliterationB: "Wattaqun Naaral lateee u'iddat lilkaafireen", english: "Fear the Fire, which is repaired for those who reject Faith", romanUrdu: "Us aag se bacho jo kafiron ke liye muhaiyya ki gayi hai" },
    { number: 132, arabic: "وَأَطِيعُوا۟ ٱللَّهَ وَٱلرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَ", transliteration: "WaateeAAoo Allaha waalrrasoola laAAallakum turhamoona", transliterationB: "Wa atee'ul laaha war Rasoola la'allakum turhamoon", english: "And obey Allah and the Messenger; that ye may obtain mercy", romanUrdu: "Aur Allah aur Rasool ka hukum maan lo, tawaqqu hai ke tumpar reham kiya jayega" },
    { number: 133, arabic: "۞ وَسَارِعُوٓا۟ إِلَىٰ مَغْفِرَةٍۢ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ أُعِدَّتْ لِلْمُتَّقِينَ", transliteration: "WasariAAoo ila maghfiratin min rabbikum wajannatin AAarduha alssamawatu waalardu oAAiddat lilmuttaqeena", transliterationB: "Wa saari'ooo ilaa maghfiratim mir Rabbikum wa Jannatin arduhassamaawaatu wal ardu u'iddat lilmuttaqeen", english: "Be quick in the race for forgiveness from your Lord, and for a Garden whose width is that (of the whole) of the heavens and of the earth, prepared for the righteous", romanUrdu: "Daud kar chalo us raah par jo tumhare Rubb ki bakshish aur us jannat ki taraf jati hai jiski wusat (vastness) zameen aur asmaano jaisi hai, aur woh un khuda-tars logon ke liye muhaiyaa ki gayi" },
    { number: 134, arabic: "ٱلَّذِينَ يُنفِقُونَ فِى ٱلسَّرَّآءِ وَٱلضَّرَّآءِ وَٱلْكَٰظِمِينَ ٱلْغَيْظَ وَٱلْعَافِينَ عَنِ ٱلنَّاسِ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ", transliteration: "Allatheena yunfiqoona fee alssarrai waalddarrai waalkathimeena alghaytha waalAAafeena AAani alnnasi waAllahu yuhibbu almuhsineena", transliterationB: "Allazeena yunfiqoona fissarraaa'i waddarraaa'i wal kaazimeenal ghaiza wal aafeena 'anin-naas; wallaahu yuhibbul muhsineen", english: "Those who spend (freely), whether in prosperity, or in adversity; who restrain anger, and pardon (all) men;- for Allah loves those who do good", romanUrdu: "Jo har haal mein apne maal kharch karte hain khwah badh haal hon ya khush haal , jo gussey ko pee jatey hain aur dusron ke kasoor maaf kardete hain, aisey neik log Allah ko bahut pasand hain" },
    { number: 135, arabic: "وَٱلَّذِينَ إِذَا فَعَلُوا۟ فَٰحِشَةً أَوْ ظَلَمُوٓا۟ أَنفُسَهُمْ ذَكَرُوا۟ ٱللَّهَ فَٱسْتَغْفَرُوا۟ لِذُنُوبِهِمْ وَمَن يَغْفِرُ ٱلذُّنُوبَ إِلَّا ٱللَّهُ وَلَمْ يُصِرُّوا۟ عَلَىٰ مَا فَعَلُوا۟ وَهُمْ يَعْلَمُونَ", transliteration: "Waallatheena itha faAAaloo fahishatan aw thalamoo anfusahum thakaroo Allaha faistaghfaroo lithunoobihim waman yaghfiru alththunooba illa Allahu walam yusirroo AAala ma faAAaloo wahum yaAAlamoona", transliterationB: "Wallazeena izaa fa'aloo faahishatan aw zalamooo anfusahum zakarul laaha fastaghfaroo lizunoobihim; wa mai yaghfiruz zunooba illal laahu wa lam yusirroo 'alaa maa fa'aloo wa hum ya'lamooo", english: "And those who, having done something to be ashamed of, or wronged their own souls, earnestly bring Allah to mind, and ask for forgiveness for their sins,- and who can forgive sins except Allah?- and are never obstinate in persisting knowingly in (the wrong) they have done", romanUrdu: "Aur jinka haal yeh hai ke agar kabhi koi fahash kaam unse sarzad ho jata hai ya kisi gunaah ka irtikaab karke woh apne upar zulm kar baithte hain to ma’an Allah unhein yaad aa jata hai aur ussey woh apne kasooron ki maafi chahte hain, kyunke Allah ke siwa aur kaun hai jo gunaah maaf kar sakta ho aur woh deedha o daanista(wilfully persist) apne kiye par israr nahin karte" },
    { number: 136, arabic: "أُو۟لَٰٓئِكَ جَزَآؤُهُم مَّغْفِرَةٌۭ مِّن رَّبِّهِمْ وَجَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ وَنِعْمَ أَجْرُ ٱلْعَٰمِلِينَ", transliteration: "Olaika jazaohum maghfiratun min rabbihim wajannatun tajree min tahtiha alanharu khalideena feeha waniAAma ajru alAAamileena", transliterationB: "Ulaaa'ika jazaaa'uhum maghfiratum mir Rabbihim wa Jannaatun tajree min tahtihal anhaaru khaalideena feeha; wa ni'ma ajrul 'aamileen", english: "For such the reward is forgiveness from their Lord, and Gardens with rivers flowing underneath,- an eternal dwelling: How excellent a recompense for those who work (and strive)", romanUrdu: "Aisey logon ki jazaa unke Rubb ke paas yeh hai ke woh unko maaf kardega aur aise baaghon mein unhein daakil karega jinke nichey nehrein bethi hongi aur wahan woh hamesha rahenge. Kaisa accha badla hai neik amal karne walon ke liye" },
    { number: 137, arabic: "قَدْ خَلَتْ مِن قَبْلِكُمْ سُنَنٌۭ فَسِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُكَذِّبِينَ", transliteration: "Qad khalat min qablikum sunanun faseeroo fee alardi faonthuroo kayfa kana AAaqibatu almukaththibeena", transliterationB: "Qad khalat min qablikum sunanum faseeroo fil ardi fanzuroo kaifa kaana 'aaqiba tul mukazzibeen", english: "Many were the Ways of Life that have passed away before you: travel through the earth, and see what was the end of those who rejected Truth", romanUrdu: "Tumse pehle bahut se daur guzar chuke hain, zameen mein chal phir kar dekhlo ke un logon ka kya anjaam hua jinhon ne (Allah ke ehkam o hidayat ko) jhutlaya" },
    { number: 138, arabic: "هَٰذَا بَيَانٌۭ لِّلنَّاسِ وَهُدًۭى وَمَوْعِظَةٌۭ لِّلْمُتَّقِينَ", transliteration: "Hatha bayanun lilnnasi wahudan wamawAAithatun lilmuttaqeena", transliterationB: "Haazaa bayaanul linnaasi wa hudanw wa maw'izatul lilmuttaqeen", english: "Here is a plain statement to men, a guidance and instruction to those who fear Allah", romanUrdu: "Yeh logon ke liye ek saaf aur sareeh tambeeh hai aur jo Allah se darte hon unke liye hidayat aur naseehat" },
    { number: 139, arabic: "وَلَا تَهِنُوا۟ وَلَا تَحْزَنُوا۟ وَأَنتُمُ ٱلْأَعْلَوْنَ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Wala tahinoo wala tahzanoo waantumu alaAAlawna in kuntum mumineena", transliterationB: "Wa laa tahinoo wa laa tahzanoo wa antumul a'lawna in kuntum mu'mineen", english: "So lose not heart, nor fall into despair: For ye must gain mastery if ye are true in Faith", romanUrdu: "Dil shikasta na ho, gham na karo , tum hi galib rahoge agar tum momin ho" },
    { number: 140, arabic: "إِن يَمْسَسْكُمْ قَرْحٌۭ فَقَدْ مَسَّ ٱلْقَوْمَ قَرْحٌۭ مِّثْلُهُۥ ۚ وَتِلْكَ ٱلْأَيَّامُ نُدَاوِلُهَا بَيْنَ ٱلنَّاسِ وَلِيَعْلَمَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَيَتَّخِذَ مِنكُمْ شُهَدَآءَ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّٰلِمِينَ", transliteration: "In yamsaskum qarhun faqad massa alqawma qarhun mithluhu watilka alayyamu nudawiluha bayna alnnasi waliyaAAlama Allahu allatheena amanoo wayattakhitha minkum shuhadaa waAllahu la yuhibbu alththalimeena", transliterationB: "Iny-yamsaskum qarhum faqad massal qawma qarhum misluh; wa tilkal ayyaamu nudaawiluhaa bainan naasi wa liya'lamal laahul lazeena aamanoo wa yattakhiza minkum shuhadaaa'; wallaahu laa yuh ibbuz zaalimeen", english: "If a wound hath touched you, be sure a similar wound hath touched the others. Such days (of varying fortunes) We give to men and men by turns: that Allah may know those that believe, and that He may take to Himself from your ranks Martyr-witnesses (to Truth). And Allah loveth not those that do wrong", romanUrdu: "Is waqt agar tumhein chot(wound) lagi hai to issey pehle aisi hi chot tumhare mukhalif fareeq ko bhi lag chuki hai. Yeh to zamane ke nasheb o faraaz hain jinhein hum logon ke darmiyan gardish dete rehte hain, tumpar yeh waqt isliye laya gaya ke Allah dekhna chahta tha ke tum mein sacchey momin kaun hain, aur un logon ko chant lena chahta tha jo waqayi (raasti ke) gawaah hon, kyunke zalim log Allah ko pasand nahin hain" },
    { number: 141, arabic: "وَلِيُمَحِّصَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَيَمْحَقَ ٱلْكَٰفِرِينَ", transliteration: "Waliyumahhisa Allahu allatheena amanoo wayamhaqa alkafireena", transliterationB: "Wa liyumahhisal laahul lazeena aamanoo wa yamhaqal kaafireen", english: "Allah's object also is to purge those that are true in Faith and to deprive of blessing Those that resist Faith", romanUrdu: "Aur woh is aazmaish ke zariye se momino ko alag chant (purge )kar kafiron ki sarkobi (blot out )kardena chahta tha" },
    { number: 142, arabic: "أَمْ حَسِبْتُمْ أَن تَدْخُلُوا۟ ٱلْجَنَّةَ وَلَمَّا يَعْلَمِ ٱللَّهُ ٱلَّذِينَ جَٰهَدُوا۟ مِنكُمْ وَيَعْلَمَ ٱلصَّٰبِرِينَ", transliteration: "Am hasibtum an tadkhuloo aljannata walamma yaAAlami Allahu allatheena jahadoo minkum wayaAAlama alssabireena", transliterationB: "Am hasibtum an tadkhulul Jannnata wa lammaa ya'lamil laahul lazeena jaahadoo minkum wa ya'lamas saabireen", english: "Did ye think that ye would enter Heaven without Allah testing those of you who fought hard (In His Cause) and remained steadfast", romanUrdu: "Kya tumne yeh samajh rakkha hai ke yunhi jannat mein chale jaogey halaanke abhi Allah ne yeh to dekha hi nahin ke tum mein kaun woh log hain jo uski raah mein jaanein ladane waley aur uski khatir sabr karne waley hain" },
    { number: 143, arabic: "وَلَقَدْ كُنتُمْ تَمَنَّوْنَ ٱلْمَوْتَ مِن قَبْلِ أَن تَلْقَوْهُ فَقَدْ رَأَيْتُمُوهُ وَأَنتُمْ تَنظُرُونَ", transliteration: "Walaqad kuntum tamannawna almawta min qabli an talqawhu faqad raaytumoohu waantum tanthuroona", transliterationB: "Wa laqad kuntum tamannnawnal mawta min qabli an talqawhu faqad ra aitumoohu wa antum tanzuroon", english: "Ye did indeed wish for death before ye met him: Now ye have seen him with your own eyes, (And ye flinch)", romanUrdu: "Tum to maut ki tamannayein kar rahey thay ! magar yeh us waqt ki baat thi jab maut samne na aayi thi, lo ab woh tumhare samne aa gayi aur tumne usey aankhon dekh liya" },
    { number: 144, arabic: "وَمَا مُحَمَّدٌ إِلَّا رَسُولٌۭ قَدْ خَلَتْ مِن قَبْلِهِ ٱلرُّسُلُ ۚ أَفَإِي۟ن مَّاتَ أَوْ قُتِلَ ٱنقَلَبْتُمْ عَلَىٰٓ أَعْقَٰبِكُمْ ۚ وَمَن يَنقَلِبْ عَلَىٰ عَقِبَيْهِ فَلَن يَضُرَّ ٱللَّهَ شَيْـًۭٔا ۗ وَسَيَجْزِى ٱللَّهُ ٱلشَّٰكِرِينَ", transliteration: "Wama muhammadun illa rasoolun qad khalat min qablihi alrrusulu afain mata aw qutila inqalabtum AAala aAAqabikum waman yanqalib AAala AAaqibayhi falan yadurra Allaha shayan wasayajzee Allahu alshshakireena", transliterationB: "Wa maa Muhammadun illaa Rasoolun qad khalat min qablihir Rusul; afa'im maata aw qutilan qalabtum 'alaaa a'qaabikum; wa mai yanqalib 'alaa aqibihi falai yadurral laaha shai'aa; wa sayajzil laahush shaakireen", english: "Muhammad is no more than a messenger: many Were the messenger that passed away before him. If he died or were slain, will ye then Turn back on your heels? If any did turn back on his heels, not the least harm will he do to Allah; but Allah (on the other hand) will swiftly reward those who (serve Him) with gratitude", romanUrdu: "Muhammad iske siwa kuch nahin ke bas ek Rasool hain, unsey pehle aur Rasool bhi guzar chuke hain. Phir kya agar woh marr jayein ya qatal kardiye jayein to tum log ultey paon phir jaogey? Yaad rakkho! Jo ulta phir gaya woh Allah ka kuch nuksaan na karega, albatta jo Allah ke shukarguzar banday bankar rahenge unhein woh iski jaza dega" },
    { number: 145, arabic: "وَمَا كَانَ لِنَفْسٍ أَن تَمُوتَ إِلَّا بِإِذْنِ ٱللَّهِ كِتَٰبًۭا مُّؤَجَّلًۭا ۗ وَمَن يُرِدْ ثَوَابَ ٱلدُّنْيَا نُؤْتِهِۦ مِنْهَا وَمَن يُرِدْ ثَوَابَ ٱلْءَاخِرَةِ نُؤْتِهِۦ مِنْهَا ۚ وَسَنَجْزِى ٱلشَّٰكِرِينَ", transliteration: "Wama kana linafsin an tamoota illa biithni Allahi kitaban muajjalan waman yurid thawaba alddunya nutihi minha waman yurid thawaba alakhirati nutihi minha wasanajzee alshshakireena", transliterationB: "Wa maa kaana linafsin an tamoota illaa bi iznillaahi kitaabam mu'ajjalaa; wa mai yurid sawaabad dunyaa nu'tihee minhaa wa mai yurid sawaabal Aakhirati nu'tihee minhaa; wa sanajzish shaakireen", english: "Nor can a soul die except by Allah's leave, the term being fixed as by writing. If any do desire a reward in this life, We shall give it to him; and if any do desire a reward in the Hereafter, We shall give it to him. And swiftly shall We reward those that (serve us with) gratitude", romanUrdu: "Koi zi rooh Allah ke izan ke bagair nahin marr sakta. Maut ka waqt to likha hua hai, jo shaks sawab e duniya ke irade se kaam karega usko hum duniya hi mein se denge, aur jo sawab e aakhirat ke irade se kaam karega woh aakhirat ka sawab payega aur shukar karne walon ko hum unki jaza zaroor ata karenge" },
    { number: 146, arabic: "وَكَأَيِّن مِّن نَّبِىٍّۢ قَٰتَلَ مَعَهُۥ رِبِّيُّونَ كَثِيرٌۭ فَمَا وَهَنُوا۟ لِمَآ أَصَابَهُمْ فِى سَبِيلِ ٱللَّهِ وَمَا ضَعُفُوا۟ وَمَا ٱسْتَكَانُوا۟ ۗ وَٱللَّهُ يُحِبُّ ٱلصَّٰبِرِينَ", transliteration: "Wakaayyin min nabiyyin qatala maAAahu ribbiyyoona katheerun fama wahanoo lima asabahum fee sabeeli Allahi wama daAAufoo wama istakanoo waAllahu yuhibbu alssabireena", transliterationB: "Wa ka aiyim min Nabiyyin qaatala ma'ahoo ribbiyyoona kaseerun famaa wahanoo limaaa Asaabahum fee sabeelil laahi wa maa da'ufoo wa mas takaanoo; wallaahu yuhibbus saabireen", english: "How many of the prophets fought (in Allah's way), and with them (fought) Large bands of godly men? but they never lost heart if they met with disaster in Allah's way, nor did they weaken (in will) nor give in. And Allah Loves those who are firm and steadfast", romanUrdu: "Issey pehle kitne hi Nabi aisey guzar chuke hain jinke saath milkar bahut se khuda paraston ne jung ki, Allah ki raah mein jo museebatein unpar padin unse woh dil shikashta nahin huey, unhon ne kamzori nahin dikhayi, woh ( baatil ke aagey) sarnagon (abase) nahin huey, aisey hi saabiron ko Allah pasand karta hai" },
    { number: 147, arabic: "وَمَا كَانَ قَوْلَهُمْ إِلَّآ أَن قَالُوا۟ رَبَّنَا ٱغْفِرْ لَنَا ذُنُوبَنَا وَإِسْرَافَنَا فِىٓ أَمْرِنَا وَثَبِّتْ أَقْدَامَنَا وَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", transliteration: "Wama kana qawlahum illa an qaloo rabbana ighfir lana thunoobana waisrafana fee amrina wathabbit aqdamana waonsurna AAala alqawmi alkafireena", transliterationB: "Wa maa kaana qawlahum illaa an qaaloo Rabbanagh fir lanaa zunoobanaa wa israafanaa feee amirnaa wa sabbit aqdaamanaa wansurnaa 'alal qawmil kaafireen", english: "All that they said was: \"Our Lord! Forgive us our sins and anything We may have done that transgressed our duty: Establish our feet firmly, and help us against those that resist Faith", romanUrdu: "Unki dua bas yeh thi ke “aey hamare Rubb! Hamari galatiyon aur kotahiyon se darguzar farma, hamare kaam mein tere hudood se jo kuch tajawuz ho gaya ho usey maaf karde, hamare qadam jamaa de aur kafiron ke muqable mein hamari madad kar.”" },
    { number: 148, arabic: "فَـَٔاتَىٰهُمُ ٱللَّهُ ثَوَابَ ٱلدُّنْيَا وَحُسْنَ ثَوَابِ ٱلْءَاخِرَةِ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ", transliteration: "Faatahumu Allahu thawaba alddunya wahusna thawabi alakhirati waAllahu yuhibbu almuhsineena", transliterationB: "Fa aataahumul laahu sawaabad dunyaa wa husna sawaabil Aakhirah; wallaahu yuhibbul muhsineen", english: "And Allah gave them a reward in this world, and the excellent reward of the Hereafter. For Allah Loveth those who do good", romanUrdu: "Aakhir e kaar Allah ne unko duniya ka sawab bhi diya aur issey behtar sawab e aakhirat bhi ata kiya. Allah ko aisey hi neik amal log pasand hain" },
    { number: 149, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ ٱلَّذِينَ كَفَرُوا۟ يَرُدُّوكُمْ عَلَىٰٓ أَعْقَٰبِكُمْ فَتَنقَلِبُوا۟ خَٰسِرِينَ", transliteration: "Ya ayyuha allatheena amanoo in tuteeAAoo allatheena kafaroo yaruddookum AAala aAAqabikum fatanqaliboo khasireena", transliterationB: "Yaaa 'aiyuhal lazeena aamanoo in tutee'ullazeena kafaroo yaruddookum 'alaaa a'qaabkum fatanqaliboo khaasireen", english: "O ye who believe! If ye obey the Unbelievers, they will drive you back on your heels, and ye will turn back (from Faith) to your own loss", romanUrdu: "Aey logon jo iman laye ho, agar tum un logon ke isharon par chaloge jinhon ne kufr ki raah ikhtiyar ki hai to woh tumko ulta pher le jayenge aur tum na-murad ho jaogey" },
    { number: 150, arabic: "بَلِ ٱللَّهُ مَوْلَىٰكُمْ ۖ وَهُوَ خَيْرُ ٱلنَّٰصِرِينَ", transliteration: "Bali Allahu mawlakum wahuwa khayru alnnasireena", transliterationB: "Balil laahu mawlaakum wa Huwa khairun naasireen", english: "Nay, Allah is your protector, and He is the best of helpers", romanUrdu: "(Unki baatein galat hain) haqeeqat yeh hai ke Allah tumhara haami o madadgaar hai aur woh behtareen madad karne wala hai" },
    { number: 151, arabic: "سَنُلْقِى فِى قُلُوبِ ٱلَّذِينَ كَفَرُوا۟ ٱلرُّعْبَ بِمَآ أَشْرَكُوا۟ بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَٰنًۭا ۖ وَمَأْوَىٰهُمُ ٱلنَّارُ ۚ وَبِئْسَ مَثْوَى ٱلظَّٰلِمِينَ", transliteration: "Sanulqee fee quloobi allatheena kafaroo alrruAAba bima ashrakoo biAllahi ma lam yunazzil bihi sultanan wamawahumu alnnaru wabisa mathwa alththalimeena", transliterationB: "Sanulqee fee quloobil lazeena kafarur ru'ba bimaaa ashrakoo billaahi maa lam yunazzil bihee sultaana-nw wa maawaahumun Naar; wa bi'sa maswaz zaalimeen", english: "Soon shall We cast terror into the hearts of the Unbelievers, for that they joined companions with Allah, for which He had sent no authority: their abode will be the Fire: And evil is the home of the wrong-doers", romanUrdu: "Anqareeb woh waqt aane wala hai jab hum munkireen e haqq ke dilon mein roab (terror/darr) bitha denge, isliye ke unhon ne Allah ke saath unko khudayi mein shareek thehraya hai jinke shareek honay par Allah ne koi sanad nazil nahin ki, unka aakhri thikana jahannum hai aur bahut hi buri hai woh qayaam-gaah jo un zalimon ko naseeb hogi" },
    { number: 152, arabic: "وَلَقَدْ صَدَقَكُمُ ٱللَّهُ وَعْدَهُۥٓ إِذْ تَحُسُّونَهُم بِإِذْنِهِۦ ۖ حَتَّىٰٓ إِذَا فَشِلْتُمْ وَتَنَٰزَعْتُمْ فِى ٱلْأَمْرِ وَعَصَيْتُم مِّنۢ بَعْدِ مَآ أَرَىٰكُم مَّا تُحِبُّونَ ۚ مِنكُم مَّن يُرِيدُ ٱلدُّنْيَا وَمِنكُم مَّن يُرِيدُ ٱلْءَاخِرَةَ ۚ ثُمَّ صَرَفَكُمْ عَنْهُمْ لِيَبْتَلِيَكُمْ ۖ وَلَقَدْ عَفَا عَنكُمْ ۗ وَٱللَّهُ ذُو فَضْلٍ عَلَى ٱلْمُؤْمِنِينَ", transliteration: "Walaqad sadaqakumu Allahu waAAdahu ith tahussoonahum biithnihi hatta itha fashiltum watanazaAAtum fee alamri waAAasaytum min baAAdi ma arakum ma tuhibboona minkum man yureedu alddunya waminkum man yureedu alakhirata thumma sarafakum AAanhum liyabtaliyakum walaqad AAafa AAankum waAllahu thoo fadlin AAala almumineena", transliterationB: "Wa laqad sadaqakumul laahu wa'dahooo iz tahussoo nahum bi iznihee hattaaa izaa fashiltim wa tanaaza'tum fil amri wa 'asaitum mim ba'di maaa araakum maa tuhibboon; minkum mai yureedud dunyaa wa minkum mai yureedul Aakhirah; summa sarafakum 'anhum sarafakum 'anhum liyabtaliyakum wa laqad 'afaa 'ankum; wallaahu zoo fadlin 'alal mu'mineen", english: "Allah did indeed fulfil His promise to you when ye with His permission Were about to annihilate your enemy,-until ye flinched and fell to disputing about the order, and disobeyed it after He brought you in sight (of the booty) which ye covet. Among you are some that hanker after this world and some that desire the Hereafter. Then did He divert you from your foes in order to test you but He forgave you: For Allah is full of grace to those who believe", romanUrdu: "Allah ne (taeed o nusrat ka) jo wada tumse kiya tha woh to usne poora kardiya, ibteda mein uske hukum se tumhi unko qatal kar rahey thay magar jab tumne kamzori dikhayi aur apne kaam mein baham ikhtilaf kiya, aur junhi ke woh cheez Allah ne tumhein dikhayi jiski muhabbat mein tum giraftar thay ( yani maal o ganeemat) tum apne sardar ke hukum ki khilaf warzi kar baithey isliye ke tum mein se kuch log duniya ke taalib thay aur kuch aakhirat ki khwahish rakhte thay, tab Allah ne tumhein kafiron ke muqable mein paspan kardiya taa-ke tumhari aazmaish karey aur haqq yeh hai ke Allah ne phir bhi tumhein maaf hi kardiya kyunke momino par Allah badi nazar e inayat rakhta hai" },
    { number: 153, arabic: "۞ إِذْ تُصْعِدُونَ وَلَا تَلْوُۥنَ عَلَىٰٓ أَحَدٍۢ وَٱلرَّسُولُ يَدْعُوكُمْ فِىٓ أُخْرَىٰكُمْ فَأَثَٰبَكُمْ غَمًّۢا بِغَمٍّۢ لِّكَيْلَا تَحْزَنُوا۟ عَلَىٰ مَا فَاتَكُمْ وَلَا مَآ أَصَٰبَكُمْ ۗ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ", transliteration: "Ith tusAAidoona wala talwoona AAala ahadin waalrrasoolu yadAAookum fee okhrakum faathabakum ghamman bighammin likayla tahzanoo AAala ma fatakum wala ma asabakum waAllahu khabeerun bima taAAmaloona", transliterationB: "Iz tus'idoona wa laa talwoona 'alaaa ahadinw war Rasoolu yad'ookum feee ukhraakum fa asaabakum ghammam bighammil likailaa tahzanoo 'alaa maa faatakum wa laa maaa asaabakum; wallaahu khabeerum bimaa ta'maloon", english: "Behold! ye were climbing up the high ground, without even casting a side glance at any one, and the Messenger in your rear was calling you back. There did Allah give you one distress after another by way of requital, to teach you not to grieve for (the booty) that had escaped you and for (the ill) that had befallen you. For Allah is well aware of all that ye do", romanUrdu: "Yaad karo jab tum bhaage chale jaa rhey thay, kisi ki taraf palat kar dekhne tak ka hosh tumhein na tha, aur Rasool tumhare pichey tumko pukar raha tha us waqt tumhari is rawish ka badla Allah ne tumhein yeh diya ke tumko ranjh par ranjh diye taa-ke aainda ke liye tumhein yeh sabaq miley ke jo kuch tumhare haath se jaye ya jo museebat tumpar nazil ho uspar malul (grieve)na ho, Allah tumhare sab amaal se bakhabar hai" },
    { number: 154, arabic: "ثُمَّ أَنزَلَ عَلَيْكُم مِّنۢ بَعْدِ ٱلْغَمِّ أَمَنَةًۭ نُّعَاسًۭا يَغْشَىٰ طَآئِفَةًۭ مِّنكُمْ ۖ وَطَآئِفَةٌۭ قَدْ أَهَمَّتْهُمْ أَنفُسُهُمْ يَظُنُّونَ بِٱللَّهِ غَيْرَ ٱلْحَقِّ ظَنَّ ٱلْجَٰهِلِيَّةِ ۖ يَقُولُونَ هَل لَّنَا مِنَ ٱلْأَمْرِ مِن شَىْءٍۢ ۗ قُلْ إِنَّ ٱلْأَمْرَ كُلَّهُۥ لِلَّهِ ۗ يُخْفُونَ فِىٓ أَنفُسِهِم مَّا لَا يُبْدُونَ لَكَ ۖ يَقُولُونَ لَوْ كَانَ لَنَا مِنَ ٱلْأَمْرِ شَىْءٌۭ مَّا قُتِلْنَا هَٰهُنَا ۗ قُل لَّوْ كُنتُمْ فِى بُيُوتِكُمْ لَبَرَزَ ٱلَّذِينَ كُتِبَ عَلَيْهِمُ ٱلْقَتْلُ إِلَىٰ مَضَاجِعِهِمْ ۖ وَلِيَبْتَلِىَ ٱللَّهُ مَا فِى صُدُورِكُمْ وَلِيُمَحِّصَ مَا فِى قُلُوبِكُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Thumma anzala AAalaykum min baAAdi alghammi amanatan nuAAasan yaghsha taifatan minkum wataifatun qad ahammathum anfusuhum yathunnoona biAllahi ghayra alhaqqi thanna aljahiliyyati yaqooloona hal lana mina alamri min shayin qul inna alamra kullahu lillahi yukhfoona fee anfusihim ma la yubdoona laka yaqooloona law kana lana mina alamri shayon ma qutilna hahuna qul law kuntum fee buyootikum labaraza allatheena kutiba AAalayhimu alqatlu ila madajiAAihim waliyabtaliya Allahu ma fee sudoorikum waliyumahhisa ma fee quloobikum waAllahu AAaleemun bithati alssudoori", transliterationB: "Summa anzala 'alaikum mim ba'dil ghammi amanatan nu'aasai yaghshaa taaa' ifatam minkum wa taaa'ifatun qad ahammathum anfusuhum yazunnoona billaahi ghairal haqqi zannal jaahiliyyati yaqooloona hal lanaa minal amri min shai'; qul innal amra kullahoo lillaah; yukhfoona fee anfusihim maa laa yubdoona laka yaqooloona law kaana lanaa minal amri shai'ummaa qutilnaa haahunaa; qul law kuntum fee buyootikum labarazal lazeena kutiba 'alaihimul qatlu ilaa madaaji'ihim wa liyabtaliyal laahu maa fee sudoorikum wa liyumah hisa maa fee quloobikum; wallaahu 'aleemum bizaatis sudoor", english: "After (the excitement) of the distress, He sent down calm on a band of you overcome with slumber, while another band was stirred to anxiety by their own feelings, Moved by wrong suspicions of Allah-suspicions due to ignorance. They said: \"What affair is this of ours?\" Say thou: \"Indeed, this affair is wholly Allah's.\" They hide in their minds what they dare not reveal to thee. They say (to themselves): \"If we had had anything to do with this affair, We should not have been in the slaughter here.\" Say: \"Even if you had remained in your homes, those for whom death was decreed would certainly have gone forth to the place of their death\"; but (all this was) that Allah might test what is in your breasts and purge what is in your hearts. For Allah knoweth well the secrets of your hearts", romanUrdu: "Is gham ke baad phir Allah ne tum mein se kuch logon par aisi itminaan ki si halat taari kardi ke woh unghne lagey, magar ek dusra giroh jiske liye sari ehmiyat bas apne mafaad hi ki thi, Allah ke mutaaliq tarah tarah ke jahilana gumaan karne laga jo sarasar khilaf e haqq thay, yeh log ab kehte hain ke, “ is kaam ke chalane mein hamara bhi koi hissa hai?” Unsey kaho, (kisi ka koi hissa nahin) is kaam ke sarey ikhtiyaraat Allah ke haath mein hain. “Darasal yeh log apne dilon mein jo baat chupaye huey hain usey tumpar zaahir nahin karte, inka asal matlab yeh hai ke, “agar (qayadat ke) ikhtiyaraat mein hamara kuch hissa hota to yahan hum na maarey jatey”. Insey kehdo ke, “agar tum apne gharon mein bhi hotey to jin logon ki maut likhi hui thi woh khud apni qatal-gaahon ki taraf nikal aatey”, aur yeh maamla jo pesh aaya, yeh to isliye tha ke jo kuch tumhare seeno mein posheeda(hidden) hai Allah usey aazma le aur jo khot tumhare dilon mein hai usey chaant de. Allah dilon ka haal khoob jaanta hai" },
    { number: 155, arabic: "إِنَّ ٱلَّذِينَ تَوَلَّوْا۟ مِنكُمْ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ إِنَّمَا ٱسْتَزَلَّهُمُ ٱلشَّيْطَٰنُ بِبَعْضِ مَا كَسَبُوا۟ ۖ وَلَقَدْ عَفَا ٱللَّهُ عَنْهُمْ ۗ إِنَّ ٱللَّهَ غَفُورٌ حَلِيمٌۭ", transliteration: "Inna allatheena tawallaw minkum yawma iltaqa aljamAAani innama istazallahumu alshshaytanu bibaAAdi ma kasaboo walaqad AAafa Allahu AAanhum inna Allaha ghafoorun haleemun", transliterationB: "Innal lazeena tawallaw minkum yawmal taqal jam'aani innamas tazallahumush Shaitaanu biba'di maa kasaboo wa laqad 'afal laahu 'anhum; innnal laaha Ghafoorum Haleem", english: "Those of you who turned back on the day the two hosts Met,-it was Satan who caused them to fail, because of some (evil) they had done. But Allah Has blotted out (their fault): For Allah is Oft-Forgiving, Most Forbearing", romanUrdu: "Tum mein se jo log muqable ke din peeth pher gaye thay unki is lagzish ka sabab yeh tha ke unki baaz kamzoriyon ki wajah se shaytan nay unke qadam dagmaga diye thay. Allah ne unhein maaf kardiya, Allah bahut darguzar karne wala aur burdbaar (All-Forbearing) hai" },
    { number: 156, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَكُونُوا۟ كَٱلَّذِينَ كَفَرُوا۟ وَقَالُوا۟ لِإِخْوَٰنِهِمْ إِذَا ضَرَبُوا۟ فِى ٱلْأَرْضِ أَوْ كَانُوا۟ غُزًّۭى لَّوْ كَانُوا۟ عِندَنَا مَا مَاتُوا۟ وَمَا قُتِلُوا۟ لِيَجْعَلَ ٱللَّهُ ذَٰلِكَ حَسْرَةًۭ فِى قُلُوبِهِمْ ۗ وَٱللَّهُ يُحْىِۦ وَيُمِيتُ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌۭ", transliteration: "Ya ayyuha allatheena amanoo la takoonoo kaallatheena kafaroo waqaloo liikhwanihim itha daraboo fee alardi aw kanoo ghuzzan law kanoo AAindana ma matoo wama qutiloo liyajAAala Allahu thalika hasratan fee quloobihim waAllahu yuhyee wayumeetu waAllahu bima taAAmaloona baseerun", transliterationB: "Yaaa ayyuhul lazeena aamanoo laa takoonoo kallazeena kafaroo wa qaaloo li ikhwaanihim izaa daraboo fil ardi aw kaanoo ghuzzal law kaanoo 'indanaa maa maatoo wa maa qutiloo liyaj'alal laahu zaalika hasratan fee quloobihim; qallaahu yuhyee wa yumeet; wallaahu bimaa ta'maloona Baseer", english: "O ye who believe! Be not like the Unbelievers, who say of their brethren, when they are travelling through the Earth or engaged in fighting: \"If they had stayed with us, they would not have died, or been slain.\" This that Allah may make it a cause of sighs and regrets in their hearts. It is Allah that gives Life and Death, and Allah sees well all that ye do", romanUrdu: "Aey logon jo iman laye ho, kafiron ki si baatein na karo jinke azeez o aqarib agar kabhi safar par jatey hain ya jung mein shareek hotey hain ( aur wahan kisi haadse se do-char ho jatey hain ) to woh kehte hain ke agar woh hamare paas hotey to na marey jatey aur na qatal hotey. Allah is qism ki baaton ko unke dilon mein hasrat o andoh ka sabab bana deta hai, warna dar-asal maarne aur jilane wala to Allah hi hai aur tumhari tamaam harakaat par wahi nigraan hai" },
    { number: 157, arabic: "وَلَئِن قُتِلْتُمْ فِى سَبِيلِ ٱللَّهِ أَوْ مُتُّمْ لَمَغْفِرَةٌۭ مِّنَ ٱللَّهِ وَرَحْمَةٌ خَيْرٌۭ مِّمَّا يَجْمَعُونَ", transliteration: "Walain qutiltum fee sabeeli Allahi aw muttum lamaghfiratun mina Allahi warahmatun khayrun mimma yajmaAAoona", transliterationB: "Wa la'in qutiltum fee sabeelil laahi aw muttum lamaghfiratum minal laahi wa rahmatun khairum mimmaa yajma'oon", english: "And if ye are slain, or die, in the way of Allah, forgiveness and mercy from Allah are far better than all they could amass", romanUrdu: "Agar tum Allah ki raah mein maarey jao ya marr jao to Allah ki jo rehmat aur bakshish tumhare hissey mein aayegi woh un saari cheezon se zyada behtar hai jinhein yeh log jamaa karte hain" },
    { number: 158, arabic: "وَلَئِن مُّتُّمْ أَوْ قُتِلْتُمْ لَإِلَى ٱللَّهِ تُحْشَرُونَ", transliteration: "Walain muttum aw qutiltum laila Allahi tuhsharoona", transliterationB: "Wa la'im muttum 'aw qutiltumla ilal laahi tuhsharoon", english: "And if ye die, or are slain, Lo! it is unto Allah that ye are brought together", romanUrdu: "Aur khwah tum maro ya maarey jao bahar-haal tum sabko simat kar jana Allah hi ki taraf hai" },
    { number: 159, arabic: "فَبِمَا رَحْمَةٍۢ مِّنَ ٱللَّهِ لِنتَ لَهُمْ ۖ وَلَوْ كُنتَ فَظًّا غَلِيظَ ٱلْقَلْبِ لَٱنفَضُّوا۟ مِنْ حَوْلِكَ ۖ فَٱعْفُ عَنْهُمْ وَٱسْتَغْفِرْ لَهُمْ وَشَاوِرْهُمْ فِى ٱلْأَمْرِ ۖ فَإِذَا عَزَمْتَ فَتَوَكَّلْ عَلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَوَكِّلِينَ", transliteration: "Fabima rahmatin mina Allahi linta lahum walaw kunta faththan ghaleetha alqalbi lainfaddoo min hawlika faoAAfu AAanhum waistaghfir lahum washawirhum fee alamri faitha AAazamta fatawakkal AAala Allahi inna Allaha yuhibbu almutawakkileena", transliterationB: "Fabimaa rahmatim minal laahi linta lahum wa law kunta fazzan ghaleezal qalbi lanfaddoo min hawlika fafu 'anhum wastaghfir lahum wa shaawirhum fil amri fa izaa 'azamta fatawakkal 'alal laah; innallaaha yuhibbul mutawak kileen", english: "It is part of the Mercy of Allah that thou dost deal gently with them Wert thou severe or harsh-hearted, they would have broken away from about thee: so pass over (Their faults), and ask for (Allah's) forgiveness for them; and consult them in affairs (of moment). Then, when thou hast Taken a decision put thy trust in Allah. For Allah loves those who put their trust (in Him)", romanUrdu: "(Aey paighambar) yeh Allah ki badi rehmat hai ke tum in logon ke liye bahut narm mijaz waqey huye ho, warna agar kahin tum tundh-khu (rough) aur sangh dil hotey to yeh sab tumhare gird o pesh se chath jatey. Inke kasoor maaf kardo, inke haqq mein dua-e-magfirat karo, aur deen ke kaam mein inko bhi shareek e mashwara rakkho. Phir jab tumhara azam (resolve) kisi rai par mustahkam ho jaye to Allah par bharosa karo, Allah ko woh log pasand hain jo usi ke bharose par kaam karte hain" },
    { number: 160, arabic: "إِن يَنصُرْكُمُ ٱللَّهُ فَلَا غَالِبَ لَكُمْ ۖ وَإِن يَخْذُلْكُمْ فَمَن ذَا ٱلَّذِى يَنصُرُكُم مِّنۢ بَعْدِهِۦ ۗ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ", transliteration: "In yansurkumu Allahu fala ghaliba lakum wain yakhthulkum faman tha allathee yansurukum min baAAdihi waAAala Allahi falyatawakkali almuminoona", transliterationB: "Iny-yansurkumul laahu falaa ghaaliba lakum wa iny-yakhzulkum faman zal lazee yansurukum mim ba'dih; wa 'alal laahi falyatawakkalil mu'minoon", english: "If Allah helps you, none can overcome you: If He forsakes you, who is there, after that, that can help you? in Allah, then, Let believers put their trust", romanUrdu: "Allah tumhari madad par ho to koi taaqat tumpar gaalib aane wali nahin, aur woh tumhein chodh de to iske baad kaun hain jo tumhari madad kar sakta ho? Pas jo sacchey momin hain unko Allah hi par bharosa rakhna chahiye" },
    { number: 161, arabic: "وَمَا كَانَ لِنَبِىٍّ أَن يَغُلَّ ۚ وَمَن يَغْلُلْ يَأْتِ بِمَا غَلَّ يَوْمَ ٱلْقِيَٰمَةِ ۚ ثُمَّ تُوَفَّىٰ كُلُّ نَفْسٍۢ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", transliteration: "Wama kana linabiyyin an yaghulla waman yaghlul yati bima ghalla yawma alqiyamati thumma tuwaffa kullu nafsin ma kasabat wahum la yuthlamoona", transliterationB: "Wa maa kaana li Nabiyyin ai yaghull; wa mai yaghlul yaati bimaa ghalla Yawmal Qiyaamah; summa tuwaffaa kullu nafsim maa kasabat wa hum laa yuzlamoon", english: "No prophet could (ever) be false to his trust. If any person is so false, He shall, on the Day of Judgment, restore what he misappropriated; then shall every soul receive its due,- whatever it earned,- and none shall be dealt with unjustly", romanUrdu: "Kisi Nabi ka yeh kaam nahin ho sakta ke woh khayanat kar jaye aur jo koi khayanat karey to woh apni khayanat samaith qayamat ke roz hazir ho jayega, phir har mutanaffis ko uski kamayi ka poora poora badla mil jayega aur kisi par kuch zulm na hoga" },
    { number: 162, arabic: "أَفَمَنِ ٱتَّبَعَ رِضْوَٰنَ ٱللَّهِ كَمَنۢ بَآءَ بِسَخَطٍۢ مِّنَ ٱللَّهِ وَمَأْوَىٰهُ جَهَنَّمُ ۚ وَبِئْسَ ٱلْمَصِيرُ", transliteration: "Afamani ittabaAAa ridwana Allahi kaman baa bisakhatin mina Allahi wamawahu jahannamu wabisa almaseeru", transliterationB: "Afamanit taba'a Ridwaanal laahi kamam baaa'a bisakhatim minal laahi wa maawaahu Jahannam; wa bi'sal maseer", english: "Is the man who follows the good pleasure of Allah Like the man who draws on himself the wrath of Allah, and whose abode is in Hell?- A woeful refuge", romanUrdu: "Bhala yeh kaise ho sakta hai ke jo shaks hamesha Allah ki raza par chalne wala ho woh us shaks ke say kaam karey jo Allah ke gazab mein ghir gaya ho, aur jiska aakhri thikana jahannum ho jo badhtareen thikana hai" },
    { number: 163, arabic: "هُمْ دَرَجَٰتٌ عِندَ ٱللَّهِ ۗ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ", transliteration: "Hum darajatun AAinda Allahi waAllahu baseerun bima yaAAmaloona", transliterationB: "Hum darajaatun 'indal laah; wallaahu baseerum bimaa ya'maloon", english: "They are in varying gardens in the sight of Allah, and Allah sees well all that they do", romanUrdu: "Allah ke nazdeek dono qism ke aadmiyon mein badarjaha farq hai aur Allah sabke aamaal par nazar rakhta hai" },
    { number: 164, arabic: "لَقَدْ مَنَّ ٱللَّهُ عَلَى ٱلْمُؤْمِنِينَ إِذْ بَعَثَ فِيهِمْ رَسُولًۭا مِّنْ أَنفُسِهِمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِهِۦ وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَإِن كَانُوا۟ مِن قَبْلُ لَفِى ضَلَٰلٍۢ مُّبِينٍ", transliteration: "Laqad manna Allahu AAala almumineena ith baAAatha feehim rasoolan min anfusihim yatloo AAalayhim ayatihi wayuzakkeehim wayuAAallimuhumu alkitaba waalhikmata wain kanoo min qablu lafee dalalin mubeenin", transliterationB: "Laqad mannal laahu 'alal mu'mineena iz ba'asa feehim Rasoolam min anfusihim yatloo 'alaihim Aayaatihee wa yuzakkeehim wa yu'allimu humul Kitaaba wal Hikmata wa in kaanoo min qablu lafee dalaalim mubeen", english: "Allah did confer a great favour on the believers when He sent among them a messenger from among themselves, rehearsing unto them the Signs of Allah, sanctifying them, and instructing them in Scripture and Wisdom, while, before that, they had been in manifest error", romanUrdu: "Dar-haqeeqat ehle iman par to Allah ne yeh bahut bada ehsaan kiya hai ke unke darmiyan khud unhi mein se ek aisa paigambar uthaya jo uski ayaat unhein sunata hai, unki zindagiyon ko sanwaarta hai aur unko kitab aur danayi (wisdom) ki taleem deta hai, halaanke issey pehle yahi log sareeh gumraahiyon mein padey huey thay" },
    { number: 165, arabic: "أَوَلَمَّآ أَصَٰبَتْكُم مُّصِيبَةٌۭ قَدْ أَصَبْتُم مِّثْلَيْهَا قُلْتُمْ أَنَّىٰ هَٰذَا ۖ قُلْ هُوَ مِنْ عِندِ أَنفُسِكُمْ ۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Awalamma asabatkum museebatun qad asabtum mithlayha qultum anna hatha qul huwa min AAindi anfusikum inna Allaha AAala kulli shayin qadeerun", transliterationB: "Awa lammaaa asaabatkum museebatun qad asabtum mislaihaa qultum annaa haazaa qul huwa min 'indi anfusikum; innal laaha 'alaa kulli shai'in Qadeer", english: "What! When a single disaster smites you, although ye smote (your enemies) with one twice as great, do ye say?- \"Whence is this?\" Say (to them): \"It is from yourselves: For Allah hath power over all things", romanUrdu: "Aur yeh tumhara kya haal hai ke jab tumpar museebat aa padi to tum kehne lagey yeh kahan se aayi? Halaanke ( jung e Badr mein) issey dugni (double) museebat tumhare haathon [ fareeq e mukhalif (enemies) par] padh chuki hai. (Aey Nabi)! Insey kaho, yeh museebat tumhari apni layi hui hai, Allah har cheez par qaadir hai" },
    { number: 166, arabic: "وَمَآ أَصَٰبَكُمْ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ فَبِإِذْنِ ٱللَّهِ وَلِيَعْلَمَ ٱلْمُؤْمِنِينَ", transliteration: "Wama asabakum yawma iltaqa aljamAAani fabiithni Allahi waliyaAAlama almumineena", transliterationB: "Wa maa asaabakum yawmal taqal jam'aani fabiiznil laahi wa liya'lamal mu'mineen", english: "What ye suffered on the day the two armies Met, was with the leave of Allah, in order that He might test the believers", romanUrdu: "Jo nuqsaan ladayi ke din tumhein pahuncha woh Allah ke izan se tha aur isliye tha ke Allah dekhle tum mein se momin kaun hain" },
    { number: 167, arabic: "وَلِيَعْلَمَ ٱلَّذِينَ نَافَقُوا۟ ۚ وَقِيلَ لَهُمْ تَعَالَوْا۟ قَٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَوِ ٱدْفَعُوا۟ ۖ قَالُوا۟ لَوْ نَعْلَمُ قِتَالًۭا لَّٱتَّبَعْنَٰكُمْ ۗ هُمْ لِلْكُفْرِ يَوْمَئِذٍ أَقْرَبُ مِنْهُمْ لِلْإِيمَٰنِ ۚ يَقُولُونَ بِأَفْوَٰهِهِم مَّا لَيْسَ فِى قُلُوبِهِمْ ۗ وَٱللَّهُ أَعْلَمُ بِمَا يَكْتُمُونَ", transliteration: "WaliyaAAlama allatheena nafaqoo waqeela lahum taAAalaw qatiloo fee sabeeli Allahi awi idfaAAoo qaloo law naAAlamu qitalan laittabaAAnakum hum lilkufri yawmaithin aqrabu minhum lileemani yaqooloona biafwahihim ma laysa fee quloobihim waAllahu aAAlamu bima yaktumoona", transliterationB: "Wa liya'lamal lazeena naafaqoo; wa qeela lahum ta'aalaw qaatiloo fee sabeelil laahi awid fa'oo qaaloo law na'lamu qitaalallat taba'naakum; hum lilkufri yawma'izin aqrabu minhum lil eemaan; yaqooloona bi afwaahihim maa laisa fee quloobihim; wallaahu a'lamu bimaa yaktumoon", english: "And the Hypocrites also. These were told: \"Come, fight in the way of Allah, or (at least) drive (The foe from your city).\" They said: \"Had we known how to fight, we should certainly have followed you.\" They were that day nearer to Unbelief than to Faith, saying with their lips what was not in their hearts but Allah hath full knowledge of all they conceal", romanUrdu: "Aur munafiq kaun. Woh munafiq ke jab unsey kaha gaya, aao Allah ki raah mein jung karo ya kam az kam (apne shehar ki) mudafiyat (defense) hi karo, to kehne lagey agar humein ilm hota ke aaj jung hogi to hum zaroor tumhare saath chalte. Yeh baat jab woh keh rahey thay us waqt woh iman ki ba-nisbat kufr se zyada qareeb thay. Woh apni zubaano se woh baatein kehte hain jo unke dilon mein nahin hoti, aur jo kuch woh dilon mein chupate hain Allah usey khoob jaanta hai" },
    { number: 168, arabic: "ٱلَّذِينَ قَالُوا۟ لِإِخْوَٰنِهِمْ وَقَعَدُوا۟ لَوْ أَطَاعُونَا مَا قُتِلُوا۟ ۗ قُلْ فَٱدْرَءُوا۟ عَنْ أَنفُسِكُمُ ٱلْمَوْتَ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Allatheena qaloo liikhwanihim waqaAAadoo law ataAAoona ma qutiloo qul faidraoo AAan anfusikumu almawta in kuntum sadiqeena", transliterationB: "Allazeena qaaloo liikhwaanihim wa qa'adoo law ataa'oonaa maa qutiloo; qul fadra'oo'an anfusikumul mawta in kuntum saadiqeen", english: "(They are) the ones that say, (of their brethren slain), while they themselves sit (at ease): \"If only they had listened to us they would not have been slain.\" Say: \"Avert death from your own selves, if ye speak the truth", romanUrdu: "Yeh wahi log hain jo khud to baithey rahey aur unke jo bhai-band ladne gaye aur maarey gaye unke mutaaliq inhon ne kehdiya ke agar woh hamari baat maan lete to na marey jatey. Insey kaho agar tum apne is qaul mein sachhey ho to khud tumhari maut jab aaye usey taal kar dikha dena" },
    { number: 169, arabic: "وَلَا تَحْسَبَنَّ ٱلَّذِينَ قُتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتًۢا ۚ بَلْ أَحْيَآءٌ عِندَ رَبِّهِمْ يُرْزَقُونَ", transliteration: "Wala tahsabanna allatheena qutiloo fee sabeeli Allahi amwatan bal ahyaon AAinda rabbihim yurzaqoona", transliterationB: "Wa laa tahsabannal lazeena qutiloo fee sabeelillaahi amwaata; bal ahyaaa'un 'inda Rabbihim yurzaqoon", english: "Think not of those who are slain in Allah's way as dead. Nay, they live, finding their sustenance in the presence of their Lord", romanUrdu: "Jo log Allah ki raah mein qatal huey hain unhein murda na samjho, woh to haqeeqat mein zinda hain, apne Rubb ke paas rizq paa rahey hain" },
    { number: 170, arabic: "فَرِحِينَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ وَيَسْتَبْشِرُونَ بِٱلَّذِينَ لَمْ يَلْحَقُوا۟ بِهِم مِّنْ خَلْفِهِمْ أَلَّا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Fariheena bima atahumu Allahu min fadlihi wayastabshiroona biallatheena lam yalhaqoo bihim min khalfihim alla khawfun AAalayhim wala hum yahzanoona", transliterationB: "Fariheena bimaaa aataa humul laahu min fadlihee wa yastabshiroona billazeena lam yalhaqoo bihim min fadlihee wa yastabshiroona billazeena lam yalhaqoo bihim min khalfihim allaa khawfun 'alaihim wa laa hum yahzanoon", english: "They rejoice in the bounty provided by Allah: And with regard to those left behind, who have not yet joined them (in their bliss), the (Martyrs) glory in the fact that on them is no fear, nor have they (cause to) grieve", romanUrdu: "Jo kuch Allah ne apne fazal se unhein diya hai uspar khush o khurram hain, aur mutmaeen hain ke jo ehle iman unke pichey duniya mein reh gaye hain aur abhi wahaan nahin pahunchey hain unke liye bhi kisi khauf aur ranjh ka mauqa nahin hai" },
    { number: 171, arabic: "۞ يَسْتَبْشِرُونَ بِنِعْمَةٍۢ مِّنَ ٱللَّهِ وَفَضْلٍۢ وَأَنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُؤْمِنِينَ", transliteration: "Yastabshiroona biniAAmatin mina Allahi wafadlin waanna Allaha la yudeeAAu ajra almumineena", transliterationB: "Yastabshiroona bini'matim minal laahi wa fad linw wa annal laaha laa yudee'u ajral mu'mineen", english: "They glory in the Grace and the bounty from Allah, and in the fact that Allah suffereth not the reward of the Faithful to be lost (in the least)", romanUrdu: "Woh Allah ke inam aur uske fazal par shadaan o farhaan hain aur unko maloom ho chuka hai ke Allah momino ke ajar ko zaya nahin karta" },
    { number: 172, arabic: "ٱلَّذِينَ ٱسْتَجَابُوا۟ لِلَّهِ وَٱلرَّسُولِ مِنۢ بَعْدِ مَآ أَصَابَهُمُ ٱلْقَرْحُ ۚ لِلَّذِينَ أَحْسَنُوا۟ مِنْهُمْ وَٱتَّقَوْا۟ أَجْرٌ عَظِيمٌ", transliteration: "Allatheena istajaboo lillahi waalrrasooli min baAAdi ma asabahumu alqarhu lillatheena ahsanoo minhum waittaqaw ajrun AAatheemun", transliterationB: "Allazeenas tajaaboo lil laahi war Rasooli mim ba'di maaa asaabahumulqarh; lillazeena ahsanoo minhum wattaqaw ajrun 'azeem", english: "Of those who answered the call of Allah and the Messenger, even after being wounded, those who do right and refrain from wrong have a great reward", romanUrdu: "Jin logon ne zakm khane ke baad bhi Allah aur Rasool ki pukar par labbaik kaha(responded) un mein jo ashkhaas neikukar aur parheizgaar hain unke liye bada ajar hai" },
    { number: 173, arabic: "ٱلَّذِينَ قَالَ لَهُمُ ٱلنَّاسُ إِنَّ ٱلنَّاسَ قَدْ جَمَعُوا۟ لَكُمْ فَٱخْشَوْهُمْ فَزَادَهُمْ إِيمَٰنًۭا وَقَالُوا۟ حَسْبُنَا ٱللَّهُ وَنِعْمَ ٱلْوَكِيلُ", transliteration: "Allatheena qala lahumu alnnasu inna alnnasa qad jamaAAoo lakum faikhshawhum fazadahum eemanan waqaloo hasbuna Allahu waniAAma alwakeelu", transliterationB: "Allazeena qaala lahumun naasu innan naasa qad jama'oo lakum fakhshawhuin fazaadahum eemaannanwa wa qaaloo hasbunal laahu wa ni'malwakeel", english: "Men said to them: \"A great army is gathering against you\": And frightened them: But it (only) increased their Faith: They said: \"For us Allah sufficeth, and He is the best disposer of affairs", romanUrdu: "Aur woh jinse logon ne kaha ke, “ tumhare khilaf badi faujein jamaa hui hain, unsey daro”, to yeh sunkar unka iman aur badh gaya (increased) aur unhon ne jawab diya ke hamare liye Allah kafi hai aur wahi behtareen kaarsaaz hai" },
    { number: 174, arabic: "فَٱنقَلَبُوا۟ بِنِعْمَةٍۢ مِّنَ ٱللَّهِ وَفَضْلٍۢ لَّمْ يَمْسَسْهُمْ سُوٓءٌۭ وَٱتَّبَعُوا۟ رِضْوَٰنَ ٱللَّهِ ۗ وَٱللَّهُ ذُو فَضْلٍ عَظِيمٍ", transliteration: "Fainqalaboo biniAAmatin mina Allahi wafadlin lam yamsashum sooon waittabaAAoo ridwana Allahi waAllahu thoo fadlin AAatheemin", transliterationB: "Fanqalaboo bini'matim minal laahi wa fadlil lam yamsashum sooo'unw wattaba'oo ridwaanal laah; wallaahu zoo fadlin 'azeem", english: "And they returned with Grace and bounty from Allah: no harm ever touched them: For they followed the good pleasure of Allah: And Allah is the Lord of bounties unbounded", romanUrdu: "Aakhir e kaar woh Allah taala ki niyamat aur fazal ke saath palat aaye, unko kisi qism ka zarar bhi na pahuncha aur Allah ki raza par chalne ka sharaf bhi unhein haasil ho gaya, Allah bada fazal farmane wala hai" },
    { number: 175, arabic: "إِنَّمَا ذَٰلِكُمُ ٱلشَّيْطَٰنُ يُخَوِّفُ أَوْلِيَآءَهُۥ فَلَا تَخَافُوهُمْ وَخَافُونِ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Innama thalikumu alshshaytanu yukhawwifu awliyaahu fala takhafoohum wakhafooni in kuntum mumineena", transliterationB: "Innamaa zaalikumush Shaitaanu yukhawwifu awliyaaa'ahoo falaa takhaafoohum wa khaafooni in kuntum mu'mineen", english: "It is only the Evil One that suggests to you the fear of his votaries: Be ye not afraid of them, but fear Me, if ye have Faith", romanUrdu: "Ab tumhein maloom hogaya ke woh dar-asal shaytan tha jo apne doston se khwa-ma-khwa (tumko) dara raha tha, lihaza aainda tum Insaano se na darna, mujhse darna agar tum haqeeqat mein saahib e iman ho" },
    { number: 176, arabic: "وَلَا يَحْزُنكَ ٱلَّذِينَ يُسَٰرِعُونَ فِى ٱلْكُفْرِ ۚ إِنَّهُمْ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًۭٔا ۗ يُرِيدُ ٱللَّهُ أَلَّا يَجْعَلَ لَهُمْ حَظًّۭا فِى ٱلْءَاخِرَةِ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ", transliteration: "Wala yahzunka allatheena yusariAAoona fee alkufri innahum lan yadurroo Allaha shayan yureedu Allahu alla yajAAala lahum haththan fee alakhirati walahum AAathabun AAatheemun", transliterationB: "Wa laa yahzunkal lazeena yusaari'oona fil Kufr; innahum lai yadurrul laaha shai'aa; yureedul laahu allaa yaj'ala lahum hazzan fil Aakhirati wa lahum 'azaabun 'azeem", english: "Let not those grieve thee who rush headlong into Unbelief: Not the least harm will they do to Allah: Allah's plan is that He will give them no portion in the Hereafter, but a severe punishment", romanUrdu: "(Aey Paighambar) jo log aaj kufr ki raah mein badi daud dhoop kar rahey hain unki sargarmiyan tumhein azurda na karein(grieve you). Yeh Allah ka kuch bhi na bigaad sakenge. Allah ka irada yeh hai ke unke liye aakhirat mein koi hissa na rakkhey, aur bil aakhir unko sakht saza milne wali hai" },
    { number: 177, arabic: "إِنَّ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلْكُفْرَ بِٱلْإِيمَٰنِ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًۭٔا وَلَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Inna allatheena ishtarawoo alkufra bialeemani lan yadurroo Allaha shayan walahum AAathabun aleemun", transliterationB: "Innal lazeenash tarawul kufra bil eemaani lai yadurrul laaha shai anw wa lahum 'azdaabun aleem", english: "Those who purchase Unbelief at the price of faith,- not the least harm will they do to Allah, but they will have a grievous punishment", romanUrdu: "Jo log iman ko chodh kar kufr ke kharidaar baney hain woh yaqeenan Allah ka koi nuqsaan nahin kar rahey hain. Unke liye dardnaak azaab tayyar hai" },
    { number: 178, arabic: "وَلَا يَحْسَبَنَّ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّمَا نُمْلِى لَهُمْ خَيْرٌۭ لِّأَنفُسِهِمْ ۚ إِنَّمَا نُمْلِى لَهُمْ لِيَزْدَادُوٓا۟ إِثْمًۭا ۚ وَلَهُمْ عَذَابٌۭ مُّهِينٌۭ", transliteration: "Wala yahsabanna allatheena kafaroo annama numlee lahum khayrun lianfusihim innama numlee lahum liyazdadoo ithman walahum AAathabun muheenun", transliterationB: "Wa laa yahsabannal lazeena kafarooo annamaa numlee lahum khairulli anfusihim; innamaa numlee lahum liyazdaadooo ismaa wa lahum 'azaabum muheen", english: "Let not the Unbelievers think that our respite to them is good for themselves: We grant them respite that they may grow in their iniquity: But they will have a shameful punishment", romanUrdu: "Yeh dheel jo hum unhein diye jatey hain isko yeh kaafir apne haqq mein behtari na samjhein. Hum to unhein isliye dheel de rahey hain ke yeh khoob baar-e-gunaah sameit lein, phir unke liye sakht zaleel karne wali saza hai" },
    { number: 179, arabic: "مَّا كَانَ ٱللَّهُ لِيَذَرَ ٱلْمُؤْمِنِينَ عَلَىٰ مَآ أَنتُمْ عَلَيْهِ حَتَّىٰ يَمِيزَ ٱلْخَبِيثَ مِنَ ٱلطَّيِّبِ ۗ وَمَا كَانَ ٱللَّهُ لِيُطْلِعَكُمْ عَلَى ٱلْغَيْبِ وَلَٰكِنَّ ٱللَّهَ يَجْتَبِى مِن رُّسُلِهِۦ مَن يَشَآءُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۚ وَإِن تُؤْمِنُوا۟ وَتَتَّقُوا۟ فَلَكُمْ أَجْرٌ عَظِيمٌۭ", transliteration: "Ma kana Allahu liyathara almumineena AAala ma antum AAalayhi hatta yameeza alkhabeetha mina alttayyibi wama kana Allahu liyutliAAakum AAala alghaybi walakinna Allaha yajtabee min rusulihi man yashao faaminoo biAllahi warusulihi wain tuminoo watattaqoo falakum ajrun AAatheemun", transliterationB: "Maa kaanal laahu liyazaral mu'mineena 'alaa maaa antum 'alaihi hattaa yameezal khabeesa minat taiyib; wa maa kaanal laahu liyutli'akum 'alal ghaibi wa laakinnal laaha yajtabee mir Rusulihii mai yashaaa'u fa aaminoo billaahi wa Rusulih; wa in tu 'minoo wa tattaqoo falakum ajrun 'azeem", english: "Allah will not leave the believers in the state in which ye are now, until He separates what is evil from what is good nor will He disclose to you the secrets of the Unseen. But He chooses of His Messengers (For the purpose) whom He pleases. So believe in Allah. And His messengers: And if ye believe and do right, ye have a reward without measure", romanUrdu: "Allah momino ko is haalat mein hargiz na rehne dega jismein tum is waqt paye jatey ho. Woh paak logon ko napaak logon se alag karke rahega. Magar Allah ka yeh tareeqa nahin hai ke tumko gaib par muttala karde. Gaib ki baatein batane ke liye to woh apne Rasoolon mein jisko chahta hai muntakhab karleta hai. Lihaza (umoor e gaib ke baarey mein) Allah aur uske Rasool par iman rakkho agar tum iman aur khuda tarsi ki rawish par chaloge to tumko bada ajar milega" },
    { number: 180, arabic: "وَلَا يَحْسَبَنَّ ٱلَّذِينَ يَبْخَلُونَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ هُوَ خَيْرًۭا لَّهُم ۖ بَلْ هُوَ شَرٌّۭ لَّهُمْ ۖ سَيُطَوَّقُونَ مَا بَخِلُوا۟ بِهِۦ يَوْمَ ٱلْقِيَٰمَةِ ۗ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", transliteration: "Wala yahsabanna allatheena yabkhaloona bima atahummu Allahu min fadlihi huwa khayran lahum bal huwa sharrun lahum sayutawwaqoona ma bakhiloo bihi yawma alqiyamati walillahi meerathu alssamawati waalardi waAllahu bima taAAmaloona khabeerun", transliterationB: "Wa laa yahsabannal lazeena yabkhaloon bimaa aataahumul lahu min fadilhee huwa khairal lahum bal huwa sharrul lahum sayutaw waqoona maa bakhiloo bihee Yawmal Qiyaamah; wa lillaahi meeraasus samaawaati wal ard; wallaahu bimaa ta'maloona Khabeer", english: "And let not those who covetously withhold of the gifts which Allah Hath given them of His Grace, think that it is good for them: Nay, it will be the worse for them: soon shall the things which they covetously withheld be tied to their necks Like a twisted collar, on the Day of Judgment. To Allah belongs the heritage of the heavens and the earth; and Allah is well-acquainted with all that ye do", romanUrdu: "Jin logon ko Allah ne apne fazal se nawaza hai aur phir woh bukhl (kanjoosi/niggardly) se kaam lete hain woh is khayal mein na rahein ke yeh bakheeli unke liye acchi hai. Nahin, yeh unke haqq mein nihayat buri hai, Jo kuch woh apni kanjoosi se jamaa kar rahey hain wahi qayamat ke roz unke galey ka tauq ban jayega. Zameen aur asmaano ki miras Allah hi ke liye hai aur tum jo kuch karte ho Allah ussey bakhabar hai" },
    { number: 181, arabic: "لَّقَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ فَقِيرٌۭ وَنَحْنُ أَغْنِيَآءُ ۘ سَنَكْتُبُ مَا قَالُوا۟ وَقَتْلَهُمُ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّۢ وَنَقُولُ ذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ", transliteration: "Laqad samiAAa Allahu qawla allatheena qaloo inna Allaha faqeerun wanahnu aghniyaon sanaktubu ma qaloo waqatlahumu alanbiyaa bighayri haqqin wanaqoolu thooqoo AAathaba alhareeqi", transliterationB: "Laqad sami'al laahu qawlal lazeena qaalooo innal laaha faqeerunw wa nahnu aghniyaaa'; sanaktubu maa qaaloo wa qatlahumul Ambiyaa'a bighairi haqqinw wa naqoolu zooqoo 'azaaba Ihreeq", english: "Allah hath heard the taunt of those who say: \"Truly, Allah is indigent and we are rich!\"- We shall certainly record their word and (their act) of slaying the prophets in defiance of right, and We shall say: \"Taste ye the penalty of the Scorching Fire", romanUrdu: "Allah ne un logon ka qaul suna jo kehte hain ke Allah fakeer hai aur hum gani hain. Unki yeh baatein bhi hum likh lenge, aur issey pehle jo woh paigambaron ko na-haqq qatal karte rahey hain woh bhi unke naam e aamaal mein sabt hai (jab faisle ka waqt aayega us waqt) hum unse kahenge ke lo ab azaab e jahannum ka maza chakkho" },
    { number: 182, arabic: "ذَٰلِكَ بِمَا قَدَّمَتْ أَيْدِيكُمْ وَأَنَّ ٱللَّهَ لَيْسَ بِظَلَّامٍۢ لِّلْعَبِيدِ", transliteration: "Thalika bima qaddamat aydeekum waanna Allaha laysa bithallamin lilAAabeedi", transliterationB: "Zaalika bimaa qaddamat aideekum wa annal laaha laisa bizallaamil lil'abeed", english: "This is because of the (unrighteous deeds) which your hands sent on before ye: For Allah never harms those who serve Him", romanUrdu: "Yeh tumhare apne haathon ki kamayi hai, Allah apne bandon ke liye zalim nahin hai" },
    { number: 183, arabic: "ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ عَهِدَ إِلَيْنَآ أَلَّا نُؤْمِنَ لِرَسُولٍ حَتَّىٰ يَأْتِيَنَا بِقُرْبَانٍۢ تَأْكُلُهُ ٱلنَّارُ ۗ قُلْ قَدْ جَآءَكُمْ رُسُلٌۭ مِّن قَبْلِى بِٱلْبَيِّنَٰتِ وَبِٱلَّذِى قُلْتُمْ فَلِمَ قَتَلْتُمُوهُمْ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Allatheena qaloo inna Allaha AAahida ilayna alla numina lirasoolin hatta yatiyana biqurbanin takuluhu alnnaru qul qad jaakum rusulun min qablee bialbayyinati wabiallathee qultum falima qataltumoohum in kutum sadiqeena", transliterationB: "Allazeena qaalooo innal laaha 'ahida ilainaaa allaa nu'mina liRasoolin hatta yaa tiyanaa biqurbaanin taa kuluhun naar; qul qad jaaa'akum Rusulum min qablee bilbaiyinaati wa billazee qultum falima qataltumoohum in kuntum saadiqeen", english: "They (also) said: \"Allah took our promise not to believe in an messenger unless He showed us a sacrifice consumed by Fire (From heaven).\" Say: \"There came to you messengers before me, with clear Signs and even with what ye ask for: why then did ye slay them, if ye speak the truth", romanUrdu: "Jo log kehte hain “Allah ne humko hidayat kardi hai ke hum kisi ko Rasool tasleem na karein jab tak woh hamare saamne aisi qurbani na karey jisey (gaib se aakar) aag kha le”, unsey kaho, “ tumhare paas mujhse pehle bahut se Rasool aa chuke hain jo bahut si roshan nishaniyan laye thay aur woh nishani bhi laye thay jiska tum zikr karte ho. Phir agar (iman laney ke liye yeh sharth pesh karne mein) tum sacchey ho to un Rasoolon ko tumne kyun qatal kiya?”" },
    { number: 184, arabic: "فَإِن كَذَّبُوكَ فَقَدْ كُذِّبَ رُسُلٌۭ مِّن قَبْلِكَ جَآءُو بِٱلْبَيِّنَٰتِ وَٱلزُّبُرِ وَٱلْكِتَٰبِ ٱلْمُنِيرِ", transliteration: "Fain kaththabooka faqad kuththiba rusulun min qablika jaoo bialbayyinati waalzzuburi waalkitabi almuneeri", transliterationB: "Fa in kaz zabooka faqad kuz ziba Rusulum min qablika jaaa'oo bilbaiyinaati waz Zuburi wal Kitaabil Muneer", english: "Then if they reject thee, so were rejected messengers before thee, who came with Clear Signs, Books of dark prophecies, and the Book of Enlightenment", romanUrdu: "Ab (aey Muhammad)!Agar yeh log tumhein jhutlate hain to bahut se Rasool tumse pehle jhutlaye jaa chuke hain jo khuli khuli nishaniyan aur sahifey (scriptures) aur roshni bakshne wali kitabein laye thay" },
    { number: 185, arabic: "كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۗ وَإِنَّمَا تُوَفَّوْنَ أُجُورَكُمْ يَوْمَ ٱلْقِيَٰمَةِ ۖ فَمَن زُحْزِحَ عَنِ ٱلنَّارِ وَأُدْخِلَ ٱلْجَنَّةَ فَقَدْ فَازَ ۗ وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا مَتَٰعُ ٱلْغُرُورِ", transliteration: "Kullu nafsin thaiqatu almawti wainnama tuwaffawna ojoorakum yawma alqiyamati faman zuhziha AAani alnnari waodkhila aljannata faqad faza wama alhayatu alddunya illa mataAAu alghuroori", transliterationB: "Kulu nafsin zaaa'iqatul mawt; wa innamaa tuwaffawna ujoorakum Yawmal Qiyaamati faman zuhziha 'anin Naari waudkhilal Jannata faqad faaz; wa mal hayaatud dunyaaa illaa mataa'ul ghuroor", english: "Every soul shall have a taste of death: And only on the Day of Judgment shall you be paid your full recompense. Only he who is saved far from the Fire and admitted to the Garden will have attained the object (of Life): For the life of this world is but goods and chattels of deception", romanUrdu: "Aakhir e kaar har shaks ko marna hai aur tum sab apne apne poorey ajar qayamat ke roz paney waley ho. Kamiyab dar-asal woh hai jo wahaan aatish e dozakh se bach jaye aur jannat mein dakhil kardiya jaye. Rahi yeh duniya, to yeh mehaz ek zaahir fareb cheez hai" },
    { number: 186, arabic: "۞ لَتُبْلَوُنَّ فِىٓ أَمْوَٰلِكُمْ وَأَنفُسِكُمْ وَلَتَسْمَعُنَّ مِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ مِن قَبْلِكُمْ وَمِنَ ٱلَّذِينَ أَشْرَكُوٓا۟ أَذًۭى كَثِيرًۭا ۚ وَإِن تَصْبِرُوا۟ وَتَتَّقُوا۟ فَإِنَّ ذَٰلِكَ مِنْ عَزْمِ ٱلْأُمُورِ", transliteration: "Latublawunna fee amwalikum waanfusikum walatasmaAAunna mina allatheena ootoo alkitaba min qablikum wamina allatheena ashrakoo athan katheeran wain tasbiroo watattaqoo fainna thalika min AAazmi alomoori", transliterationB: "Latublawunna feee amwaalikum wa anfusikum wa latasma'unna minal lazeena ootul Kitaaba min qablikum wa minal lazeena ashrakooo azan kaseeraa; wa in tasbiroo wa tattaqoo fa inna zaalika min 'azmil umoor", english: "Ye shall certainly be tried and tested in your possessions and in your personal selves; and ye shall certainly Hear much that will grieve you, from those who received the Book before you and from those who worship many gods. But if ye persevere patiently, and guard against evil,-then that will be a determining factor in all affairs", romanUrdu: "(Musalmaano)! Tumhein maal aur jaan dono ki aazmaishein pesh aakar rahengi, aur tum ehle kitab aur mushrikeen se bahut se takleef-de baatein sunogey. Agar in sab haalat mein tum sabr aur khuda tarsi ki rawish par qayam raho to yeh baday hausle ka kaam hai" },
    { number: 187, arabic: "وَإِذْ أَخَذَ ٱللَّهُ مِيثَٰقَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ لَتُبَيِّنُنَّهُۥ لِلنَّاسِ وَلَا تَكْتُمُونَهُۥ فَنَبَذُوهُ وَرَآءَ ظُهُورِهِمْ وَٱشْتَرَوْا۟ بِهِۦ ثَمَنًۭا قَلِيلًۭا ۖ فَبِئْسَ مَا يَشْتَرُونَ", transliteration: "Waith akhatha Allahu meethaqa allatheena ootoo alkitaba latubayyinunnahu lilnnasi wala taktumoonahu fanabathoohu waraa thuhoorihim waishtaraw bihi thamanan qaleelan fabisa ma yashtaroona", transliterationB: "Wa iz akhazal laahu meesaaqal lazeena ootul Kitaaba latubaiyinunnahoo linnaasi wa laa taktumoona hoo fanabazoohu waraaa'a zuhoorihim washtaraw bihee samanan qaleelan fabi'sa maa yashtaroon", english: "And remember Allah took a covenant from the People of the Book, to make it known and clear to mankind, and not to hide it; but they threw it away behind their backs, and purchased with it some miserable gain! And vile was the bargain they made", romanUrdu: "In ehle kitab ko woh ahad bhi yaad dilao jo Allah ne unse liya tha ke tumhein kitab ki taleemat ko logon mein phaylana hoga, inhein posheeda rakhna nahin hoga. Magar unhon ne kitab ko pas-e-pusht (behind their backs) daal diya aur thodi keemat par usey bech daala. Kitna bura kaarobaar hai jo yeh kar rahey hain" },
    { number: 188, arabic: "لَا تَحْسَبَنَّ ٱلَّذِينَ يَفْرَحُونَ بِمَآ أَتَوا۟ وَّيُحِبُّونَ أَن يُحْمَدُوا۟ بِمَا لَمْ يَفْعَلُوا۟ فَلَا تَحْسَبَنَّهُم بِمَفَازَةٍۢ مِّنَ ٱلْعَذَابِ ۖ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "La tahsabanna allatheena yafrahoona bima ataw wayuhibboona an yuhmadoo bima lam yafAAaloo fala tahsabannahum bimafazatin mina alAAathabi walahum AAathabun aleemun", transliterationB: "Laa tahsabannal lazeena yafrahoona bimaaa ataw wa yuhibbona ai yuhmadoo bimaa lam yaf'aloo falaa tahsabunnahum bimafaazatim minal 'azaabi wa lahum 'azaabun aleem", english: "Think not that those who exult in what they have brought about, and love to be praised for what they have not done,- think escape the penalty. For them is a penalty Grievous indeed", romanUrdu: "Tum un logon ko azaab se mehfooz na samjho jo apne kartooton par khush hain aur chahte hain ke aisey kaamon ki tareef unhein hasil ho jo fil waqey unhon ne nahin kiye hain. Haqeeqat mein unke liye dardnaak saza tayyar hai" },
    { number: 189, arabic: "وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Walillahi mulku alssamawati waalardi waAllahu AAala kulli shayin qadeerun", transliterationB: "Wa lillaahi mulkus samaawaati wal ard; wallaahu 'alaa kulli shai'in Qadeer", english: "To Allah belongeth the dominion of the heavens and the earth; and Allah hath power over all things", romanUrdu: "Zameen aur asmaano ka maalik Allah hai aur uski qudrat sab par haawi hai" },
    { number: 190, arabic: "إِنَّ فِى خَلْقِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَٰفِ ٱلَّيْلِ وَٱلنَّهَارِ لَءَايَٰتٍۢ لِّأُو۟لِى ٱلْأَلْبَٰبِ", transliteration: "Inna fee khalqi alssamawati waalardi waikhtilafi allayli waalnnahari laayatin liolee alalbabi", transliterationB: "Inna fee khalqis samaawati wal ardi wakhtilaafil laili wannahaari la Aayaatil liulil albaab", english: "Behold! in the creation of the heavens and the earth, and the alternation of night and day,- there are indeed Signs for men of understanding", romanUrdu: "Zameen aur asmaano ki paidaish mein aur raat aur din ke bari bari se aane mein un hoshmand logon ke liye bahut nishaniyan hain" },
    { number: 191, arabic: "ٱلَّذِينَ يَذْكُرُونَ ٱللَّهَ قِيَٰمًۭا وَقُعُودًۭا وَعَلَىٰ جُنُوبِهِمْ وَيَتَفَكَّرُونَ فِى خَلْقِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ رَبَّنَا مَا خَلَقْتَ هَٰذَا بَٰطِلًۭا سُبْحَٰنَكَ فَقِنَا عَذَابَ ٱلنَّارِ", transliteration: "Allatheena yathkuroona Allaha qiyaman waquAAoodan waAAala junoobihim wayatafakkaroona fee khalqi alssamawati waalardi rabbana ma khalaqta hatha batilan subhanaka faqina AAathaba alnnari", transliterationB: "Allazeena yazkuroonal laaha qiyaamaiw-wa qu'oodanw-wa 'alaa juno obihim wa yatafakkaroona fee khalqis samaawaati wal ardi Rabbanaa maa khalaqta haaza baatilan Subhaanak faqinaa 'azaaban Naar", english: "Men who celebrate the praises of Allah, standing, sitting, and lying down on their sides, and contemplate the (wonders of) creation in the heavens and the earth, (With the thought): \"Our Lord! not for naught Hast Thou created (all) this! Glory to Thee! Give us salvation from the penalty of the Fire", romanUrdu: "Jo uthte, baithte aur latetey, har haal mein khuda ko yaad karte hain aur asmaan o zameen ki saakht (creation) mein gaur o fikr karte hain. (Woh be-ikhtiyar bol uthte hain) “ parwardigar! Yeh sab kuch tu nay fizul aur be-maqsad nahin banaya hai, tu paak hai issey ke abas (bekar / in vain) kaam karey. Pas aey Rubb! Humein dozakh ke azaab se bacha le" },
    { number: 192, arabic: "رَبَّنَآ إِنَّكَ مَن تُدْخِلِ ٱلنَّارَ فَقَدْ أَخْزَيْتَهُۥ ۖ وَمَا لِلظَّٰلِمِينَ مِنْ أَنصَارٍۢ", transliteration: "Rabbana innaka man tudkhili alnnara faqad akhzaytahu wama lilththalimeena min ansarin", transliterationB: "Rabbanaaa innaka man tudkhilin Naara faqad akhzai tahoo wa maa lizzaalimeena min ansaar", english: "Our Lord! any whom Thou dost admit to the Fire, Truly Thou coverest with shame, and never will wrong-doers Find any helpers", romanUrdu: "Tu nay jisey dozakh mein dala usey dar haqeeqat badi zillat o ruswayi mein daal diya, aur phir aisey zalimon ka koi madadgaar na hoga" },
    { number: 193, arabic: "رَّبَّنَآ إِنَّنَا سَمِعْنَا مُنَادِيًۭا يُنَادِى لِلْإِيمَٰنِ أَنْ ءَامِنُوا۟ بِرَبِّكُمْ فَـَٔامَنَّا ۚ رَبَّنَا فَٱغْفِرْ لَنَا ذُنُوبَنَا وَكَفِّرْ عَنَّا سَيِّـَٔاتِنَا وَتَوَفَّنَا مَعَ ٱلْأَبْرَارِ", transliteration: "Rabbana innana samiAAna munadiyan yunadee lileemani an aminoo birabbikum faamanna rabbana faighfir lana thunoobana wakaffir AAanna sayyiatina watawaffana maAAa alabrari", transliterationB: "Rabbanaaa innanaa sami'naa munaadiyai yunaadee lil eemaani an aaminoo bi Rabbikum fa aamannaa; Rabbanaa faghfir lanaa zunoobanaa wa kaffir 'annaa saiyi aatina wa tawaffanaa ma'al abraar", english: "Our Lord! we have heard the call of one calling (Us) to Faith, 'Believe ye in the Lord,' and we have believed. Our Lord! Forgive us our sins, blot out from us our iniquities, and take to Thyself our souls in the company of the righteous", romanUrdu: "Maalik! Humne ek pukarne waley ko suna jo iman ki taraf bulata tha aur kehta tha ke apne Rubb ko maano, humne uski dawat qabool karli, pas aey hamare aaqa! Jo kasoor humse huey hain unsey darguzar farma. Jo buraiyan hum mein hain unhein door karde aur hamara khaatma neik logon ke saath kar" },
    { number: 194, arabic: "رَبَّنَا وَءَاتِنَا مَا وَعَدتَّنَا عَلَىٰ رُسُلِكَ وَلَا تُخْزِنَا يَوْمَ ٱلْقِيَٰمَةِ ۗ إِنَّكَ لَا تُخْلِفُ ٱلْمِيعَادَ", transliteration: "Rabbana waatina ma waAAadtana AAala rusulika wala tukhzina yawma alqiyamati innaka la tukhlifu almeeAAada", transliterationB: "Rabbanaa wa aatinaa maa wa'attanaa 'alaa Rusulika wa laa tukhzinaa Yawmal Qiyaamah; innaka laa tukhliful mee'aad", english: "Our Lord! Grant us what Thou didst promise unto us through Thine messengers, and save us from shame on the Day of Judgment: For Thou never breakest Thy promise", romanUrdu: "Khudawanda! Jo wadey tu nay apne Rasoolon ke zariye se kiye hain unko hamare saath poora kar aur qayamat ke din humein ruswayi mein na daal, beshak tu apne wadey ke khilaf karne wala nahin hai”" },
    { number: 195, arabic: "فَٱسْتَجَابَ لَهُمْ رَبُّهُمْ أَنِّى لَآ أُضِيعُ عَمَلَ عَٰمِلٍۢ مِّنكُم مِّن ذَكَرٍ أَوْ أُنثَىٰ ۖ بَعْضُكُم مِّنۢ بَعْضٍۢ ۖ فَٱلَّذِينَ هَاجَرُوا۟ وَأُخْرِجُوا۟ مِن دِيَٰرِهِمْ وَأُوذُوا۟ فِى سَبِيلِى وَقَٰتَلُوا۟ وَقُتِلُوا۟ لَأُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَأُدْخِلَنَّهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ثَوَابًۭا مِّنْ عِندِ ٱللَّهِ ۗ وَٱللَّهُ عِندَهُۥ حُسْنُ ٱلثَّوَابِ", transliteration: "Faistajaba lahum rabbuhum annee la odeeAAu AAamala AAamilin minkum min thakarin aw ontha baAAdukum min baAAdin faallatheena hajaroo waokhrijoo min diyarihim waoothoo fee sabeelee waqataloo waqutiloo laokaffiranna AAanhum sayyiatihim walaodkhilannahum jannatin tajree min tahtiha alanharu thawaban min AAindi Allahi waAllahu AAindahu husnu alththawabi", transliterationB: "Fastajaaba lahum Rabbuhum annee laaa Udee'u 'amala 'aamilim minkum min zakarin aw unsaa ba'dukum mim ba'din fal lazeena haajaroo wa ukhrijoo min diyaarihim wa oozoo fee sabeelee wa qaataloo wa qutiloo la ukaffiranna 'anhum saiyi aatihim wa la udkhilanna hum Jannnatin tajree min tahtihal anhaaru sawaabam min 'indil laah; wallaahu 'indahoo husnus sawaab", english: "And their Lord hath accepted of them, and answered them: \"Never will I suffer to be lost the work of any of you, be he male or female: Ye are members, one of another: Those who have left their homes, or been driven out therefrom, or suffered harm in My Cause, or fought or been slain,- verily, I will blot out from them their iniquities, and admit them into Gardens with rivers flowing beneath;- A reward from the presence of Allah, and from His presence is the best of rewards", romanUrdu: "Jawab mein unke Rubb ne farmaya, “ mai tum mein se kisi ka amal zaya karne wala nahin hoon, khwa mard ho ya aurat, tum sab ek dusre ke hum jins ho. Lihaza jin logon ne meri khatir apne watan chodey aur jo meri raah mein apne gharon se nikale gaye aur sataye gaye aur mere liye ladey aur maarey gaye unke sab kasoor mai maaf kardunga aur unhein aisey baaghon mein daakhil karunga jinke nichey nehrein behti hongi. Yeh unki jaza hai Allah ke haan aur behtareen jaza Allah hi ke paas hai”" },
    { number: 196, arabic: "لَا يَغُرَّنَّكَ تَقَلُّبُ ٱلَّذِينَ كَفَرُوا۟ فِى ٱلْبِلَٰدِ", transliteration: "La yaghurrannaka taqallubu allatheena kafaroo fee albiladi", transliterationB: "Laa yaghurrannaka taqal lubul lazeena kafaroo fil bilaad", english: "Let not the strutting about of the Unbelievers through the land deceive thee", romanUrdu: "(Aey Nabi)! Duniya ke mulkon mein khuda ke nafarmaan logon ki chalat phirat tumhein kisi dhoke mein na daaley" },
    { number: 197, arabic: "مَتَٰعٌۭ قَلِيلٌۭ ثُمَّ مَأْوَىٰهُمْ جَهَنَّمُ ۚ وَبِئْسَ ٱلْمِهَادُ", transliteration: "MataAAun qaleelun thumma mawahum jahannamu wabisa almihadu", transliterationB: "Mataa'un qaleelun summa maawaahum Jahannam; wa bi'sal mihaad", english: "Little is it for enjoyment: Their ultimate abode is Hell: what an evil bed (To lie on)", romanUrdu: "Yeh mehaz chandh roza zindagi ka thoda sa lutf hai, phir yeh sab jahannum mein jayenge jo badhtareen jaaye qaraar hai" },
    { number: 198, arabic: "لَٰكِنِ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ لَهُمْ جَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا نُزُلًۭا مِّنْ عِندِ ٱللَّهِ ۗ وَمَا عِندَ ٱللَّهِ خَيْرٌۭ لِّلْأَبْرَارِ", transliteration: "Lakini allatheena ittaqaw rabbahum lahum jannatun tajree min tahtiha alanharu khalideena feeha nuzulan min AAindi Allahi wama AAinda Allahi khayrun lilabrari", transliterationB: "Laakinil lazeenat taqaw Rabbahum lahum Jannnaatun tajree min tahtihal anhaaru khaalideena feehaa nuzulammin 'indil laah; wa maa 'indal laahi khairul lil abraar", english: "On the other hand, for those who fear their Lord, are Gardens, with rivers flowing beneath; therein are they to dwell (for ever),- a gift from the presence of Allah; and that which is in the presence of Allah is the best (bliss) for the righteous", romanUrdu: "Baraks iske jo log apne Rubb se darte huey zindagi basar karte hain unke liye aisey baagh hain jinke nichey nehrein behti hain, in baaghon mein woh hamesha rahenge, Allah ki taraf se yeh samaan e ziyafat hai unke liye, aur jo kuch Allah ke paas hai neik logon ke liye wahi sabse behtar hai" },
    { number: 199, arabic: "وَإِنَّ مِنْ أَهْلِ ٱلْكِتَٰبِ لَمَن يُؤْمِنُ بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْكُمْ وَمَآ أُنزِلَ إِلَيْهِمْ خَٰشِعِينَ لِلَّهِ لَا يَشْتَرُونَ بِـَٔايَٰتِ ٱللَّهِ ثَمَنًۭا قَلِيلًا ۗ أُو۟لَٰٓئِكَ لَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ ۗ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ", transliteration: "Wainna min ahli alkitabi laman yuminu biAllahi wama onzila ilaykum wama onzila ilayhim khashiAAeena lillahi la yashtaroona biayati Allahi thamanan qaleelan olaika lahum ajruhum AAinda rabbihim inna Allaha sareeAAu alhisabi", transliterationB: "Wa inna min Ahlil Kitaabi lamai yu minu billaahi wa maaa unzila ilaikum wa maaa unzila ilaihim khaashi 'eena lillaahi laa yashtaroona bi Aayaatil laahi samanan qaleelaa; ulaaa'ika lahum ajruhum 'inda Rabbihim; innal laaha saree'ul hisaab", english: "And there are, certainly, among the People of the Book, those who believe in Allah, in the revelation to you, and in the revelation to them, bowing in humility to Allah: They will not sell the Signs of Allah for a miserable gain! For them is a reward with their Lord, and Allah is swift in account", romanUrdu: "Ehle kitab mein bhi kuch log aisey hain jo Allah ko maante hain, us kitab par iman latey hain jo tumhari taraf bheji gayi hai aur us kitab par bhi iman rakhte hain jo issey pehle khud unki taraf bheji gayi thi. Allah ke aagey jhuke huey hain, aur Allah ki aayaat ko thodi si keemat par bech nahin dete. Inka ajar inke Rubb ke paas hai aur Allah hisaab chukane mein dair nahin lagata" },
    { number: 200, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱصْبِرُوا۟ وَصَابِرُوا۟ وَرَابِطُوا۟ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ", transliteration: "Ya ayyuha allatheena amanoo isbiroo wasabiroo warabitoo waittaqoo Allaha laAAallakum tuflihoona", transliterationB: "Yaaa aiyuhal lazeena aamanus biroo wa saabiroo wa raabitoo wattaqul laaha la'allakum tuflihoon", english: "O ye who believe! Persevere in patience and constancy; vie in such perseverance; strengthen each other; and fear Allah; that ye may prosper", romanUrdu: "Aey logon jo iman laye ho, Sabr se kaam lo, baatil paraston ke muqable mein pa-mardi dikhao, haqq ki khidmat ke liye kamar-basta ho jao, aur Allah se darte raho, umeed hai ke falaah paogey" }
  ]
};
